pragma solidity 0.8.10;

import "@openzeppelin/contracts-upgradeable/security/ReentrancyGuardUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/access/OwnableUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/token/ERC20/ERC20Upgradeable.sol";

import "./interfaces/IPriceHelper.sol";
import "./interfaces/IVault.sol";
import "./interfaces/IWorker02.sol";
import "./interfaces/IWETH.sol";
import "./interfaces/IWNativeRelayer.sol";
import "./interfaces/IDeltaNeutralVaultConfig.sol";
import "./interfaces/IFairLaunch.sol";
import "../utils/SafeToken.sol";
import "../utils/Math.sol";

contract DeltaNeutralVault is ERC20Upgradeable, ReentrancyGuardUpgradeable, OwnableUpgradeable {

  using SafeToken for address;


  event LogInitializePositions(address indexed _from, uint256 _stableVaultPosId, uint256 _assetVaultPosId);
  event LogDeposit(
    address indexed _from,
    address indexed _shareReceiver,
    uint256 _shares,
    uint256 _stableTokenAmount,
    uint256 _assetTokenAmount
  );
  event LogWithdraw(address indexed _shareOwner, uint256 _minStableTokenAmount, uint256 _minAssetTokenAmount);
  event LogRebalance(uint256 _equityBefore, uint256 _equityAfter);


  error Unauthorized(address _caller);
  error PositionsAlreadyInitialized();
  error PositionsNotInitialized();
  error InvalidPositions(address _vault, uint256 _positionId);
  error UnsafePositionEquity();
  error UnsafePositionValue();
  error UnsafeDebtValue();
  error UnsafeDebtRatio();
  error UnsafeOutstanding(address _token, uint256 _amountBefore, uint256 _amountAfter);
  error PositionsIsHealthy();
  error InsufficientTokenReceived(address _token, uint256 _requiredAmount, uint256 _receivedAmount);
  error InsufficientShareReceived(uint256 _requiredAmount, uint256 _receivedAmount);

  struct Outstanding {
    uint256 stableAmount;
    uint256 assetAmount;
    uint256 nativeAmount;
  }

  struct PositionInfo{
    uint256 stablePositionEquity;
    uint256 stablePositionDebtValue;
    uint256 assetPositionEquity;
    uint256 assetPositionDebtValue;
  }


  uint8 private constant ACTION_WORK = 1;
  uint8 private constant ACTION_WRAP = 2;

  address private lpToken;
  address public stableVault;
  address public assetVault;

  address public stableVaultWorker;
  address public assetVaultWorker;

  address public stableToken;
  address public assetToken;
  address public alpacaToken;

  uint256 public stableVaultPosId;
  uint256 public assetVaultPosId;

  IPriceHelper public priceHelper;

  IDeltaNeutralVaultConfig public config;


  bool private OPENING;


  modifier onlyEOAorWhitelisted() {
    if (msg.sender != tx.origin && !config.whitelistedCallers(msg.sender)) {
      revert Unauthorized(msg.sender);
    }
    _;
  }


  modifier onlyRebalancers() {
    if (!config.whitelistedRebalancers(msg.sender)) revert Unauthorized(msg.sender);
    _;
  }












  function initialize(
    string calldata _name,
    string calldata _symbol,
    address _stableVault,
    address _assetVault,
    address _stableVaultWorker,
    address _assetVaultWorker,
    address _lpToken,
    address _alpacaToken,
    IPriceHelper _priceHelper,
    IDeltaNeutralVaultConfig _config
  ) external initializer {
    OwnableUpgradeable.__Ownable_init();
    ReentrancyGuardUpgradeable.__ReentrancyGuard_init();
    ERC20Upgradeable.__ERC20_init(_name, _symbol);

    stableVault = _stableVault;
    assetVault = _assetVault;

    stableToken = IVault(_stableVault).token();
    assetToken = IVault(_assetVault).token();
    alpacaToken = _alpacaToken;

    stableVaultWorker = _stableVaultWorker;
    assetVaultWorker = _assetVaultWorker;

    lpToken = _lpToken;

    priceHelper = _priceHelper;
    config = _config;
  }






  function initPositions(
    uint256 _minShareReceive,
    uint256 _stableTokenAmount,
    uint256 _assetTokenAmount,
    bytes calldata _data
  ) external payable onlyOwner {
    if (stableVaultPosId != 0 || assetVaultPosId != 0) {
      revert PositionsAlreadyInitialized();
    }

    OPENING = true;
    stableVaultPosId = IVault(stableVault).nextPositionID();
    assetVaultPosId = IVault(assetVault).nextPositionID();

    deposit(msg.sender, _minShareReceive, _stableTokenAmount, _assetTokenAmount, _data);

    OPENING = false;

    emit LogInitializePositions(msg.sender, stableVaultPosId, assetVaultPosId);
  }




  function _transferTokenToVault(address _token, uint256 _amount) internal {
    if (_token == config.getWrappedNativeAddr()) {
      IWETH(config.getWrappedNativeAddr()).deposit{ value: _amount }();
    } else {
      SafeToken.safeTransferFrom(_token, msg.sender, address(this), _amount);
    }
  }





  function _transferTokenToShareOwner(
    address _to,
    address _token,
    uint256 _amount
  ) internal {
    if (_token == config.getWrappedNativeAddr()) {
      SafeToken.safeTransferETH(_to, _amount);
    } else {
      SafeToken.safeTransfer(_token, _to, _amount);
    }
  }









  function deposit(
    address _shareReceiver,
    uint256 _minShareReceive,
    uint256 _stableTokenAmount,
    uint256 _assetTokenAmount,
    bytes calldata _data
  ) public payable onlyEOAorWhitelisted nonReentrant returns (uint256 _shares) {

    PositionInfo memory _positionInfoBefore = positionInfo();
    Outstanding memory _outstandingBefore = _outstanding();
    _outstandingBefore.nativeAmount = _outstandingBefore.nativeAmount - msg.value;


    _transferTokenToVault(stableToken, _stableTokenAmount);
    _transferTokenToVault(assetToken, _assetTokenAmount);


    uint256 _depositValue = ((_stableTokenAmount * priceHelper.getTokenPrice(stableToken)) +
      (_assetTokenAmount * priceHelper.getTokenPrice(assetToken))) / 1e18;

    uint256 _shares = valueToShare(_depositValue);
    if (_shares < _minShareReceive) {
      revert InsufficientShareReceived(_minShareReceive, _shares);
    }

    _mint(_shareReceiver, _shares);

    {


      (uint8[] memory actions, uint256[] memory values, bytes[] memory _datas) = abi.decode(
        _data,
        (uint8[], uint256[], bytes[])
      );
      _execute(actions, values, _datas);
    }


    _depositHealthCheck(
      _depositValue,
      _positionInfoBefore,
      positionInfo()
    );
    _outstandingCheck(_outstandingBefore, _outstanding());

    emit LogDeposit(msg.sender, _shareReceiver, _shares, _stableTokenAmount, _assetTokenAmount);
    return _shares;
  }







  function withdraw(
    uint256 _shareAmount,
    uint256 _minStableTokenAmount,
    uint256 _minAssetTokenAmount,
    bytes calldata _data
  ) public onlyEOAorWhitelisted nonReentrant returns (uint256 _withdrawValue) {

    address _shareOwner = msg.sender;
    PositionInfo memory _positionInfoBefore = positionInfo();
    Outstanding memory _outstandingBefore = _outstanding();

    uint256 _shareValue = shareToValue(_shareAmount);
    _burn(_shareOwner, _shareAmount);

    {
      (uint8[] memory actions, uint256[] memory values, bytes[] memory _datas) = abi.decode(
        _data,
        (uint8[], uint256[], bytes[])
      );
      _execute(actions, values, _datas);
    }

    PositionInfo memory _positionInfoAfter = positionInfo();
    Outstanding memory _outstandingAfter = _outstanding();


    uint256 _stableTokenBack = stableToken == config.getWrappedNativeAddr()
      ? _outstandingAfter.nativeAmount - _outstandingBefore.nativeAmount
      : _outstandingAfter.stableAmount - _outstandingBefore.stableAmount;
    uint256 _assetTokenBack = assetToken == config.getWrappedNativeAddr()
      ? _outstandingAfter.nativeAmount - _outstandingBefore.nativeAmount
      : _outstandingAfter.assetAmount - _outstandingBefore.assetAmount;

    if (_stableTokenBack < _minStableTokenAmount) {
      revert InsufficientTokenReceived(stableToken, _minStableTokenAmount, _stableTokenBack);
    }
    if (_assetTokenBack < _minAssetTokenAmount) {
      revert InsufficientTokenReceived(assetToken, _minAssetTokenAmount, _assetTokenBack);
    }

    _transferTokenToShareOwner(_shareOwner, stableToken, _stableTokenBack);
    _transferTokenToShareOwner(_shareOwner, assetToken, _assetTokenBack);

    uint256 _withdrawValue;
    {
      uint256 _stableWithdrawValue = _stableTokenBack * priceHelper.getTokenPrice(stableToken);
      uint256 _assetWithdrawValue = _assetTokenBack * priceHelper.getTokenPrice(assetToken);
      _withdrawValue = (_stableWithdrawValue + _assetWithdrawValue) / 1e18;
    }


    _withdrawHealthCheck(_withdrawValue, _positionInfoBefore, _positionInfoAfter);
    _outstandingCheck(_outstandingBefore, _outstandingAfter);

    emit LogWithdraw(_shareOwner, _stableTokenBack, _assetTokenBack);
    return _withdrawValue;
  }


  function rebalance(
    uint8[] memory _actions,
    uint256[] memory _values,
    bytes[] memory _datas
  ) external onlyRebalancers {

    PositionInfo memory _positionInfoBefore = positionInfo();
    Outstanding memory _outstandingBefore = _outstanding();
    uint256 _stablePositionValue = _positionInfoBefore.stablePositionEquity + _positionInfoBefore.stablePositionDebtValue;
    uint256 _assetPositionValue = _positionInfoBefore.assetPositionEquity + _positionInfoBefore.assetPositionDebtValue;
    uint256 _equityBefore = _positionInfoBefore.stablePositionEquity + _positionInfoBefore.assetPositionEquity;
    uint256 _rebalanceFactor = config.rebalanceFactor();

    if (
      _stablePositionValue * _rebalanceFactor >= _positionInfoBefore.stablePositionDebtValue * 10000 &&
      _assetPositionValue * _rebalanceFactor >= _positionInfoBefore.assetPositionDebtValue * 10000
    ) {
      revert PositionsIsHealthy();
    }


    {
      _execute(_actions, _values, _datas);
    }



    uint256 _equityAfter = totalEquityValue();
    if (!Math.almostEqual(_equityAfter, _equityBefore, config.positionValueTolerance())) {
      revert UnsafePositionValue();
    }
    _outstandingCheck(_outstandingBefore, _outstanding());

    emit LogRebalance(_equityBefore, _equityAfter);
  }





  function _depositHealthCheck(
    uint256 _depositValue,
    PositionInfo memory _positionInfoBefore,
    PositionInfo memory _positionInfoAfter
  ) internal {

    uint256 _toleranceBps = config.positionValueTolerance();


    if (
      !Math.almostEqual(_positionInfoAfter.stablePositionEquity - _positionInfoBefore.stablePositionEquity, (_depositValue ) / 4, _toleranceBps) ||
      !Math.almostEqual(_positionInfoAfter.assetPositionEquity - _positionInfoBefore.assetPositionEquity, (_depositValue * 3) / 4, _toleranceBps)
    ) {
      revert UnsafePositionEquity();
    }


    if (
      !Math.almostEqual(
        _positionInfoAfter.stablePositionDebtValue - _positionInfoBefore.stablePositionDebtValue ,
        (_depositValue * 2) / 4,
        _toleranceBps
      ) ||
      !Math.almostEqual( _positionInfoAfter.assetPositionDebtValue - _positionInfoBefore.assetPositionDebtValue, (_depositValue * 6) / 4, _toleranceBps)
    ) {
      revert UnsafeDebtValue();
    }
  }





  function _withdrawHealthCheck(
    uint256 _withdrawValue,
    PositionInfo memory _positionInfoBefore,
    PositionInfo memory _positionInfoAfter
  ) internal {
    uint256 _toleranceBps = config.positionValueTolerance();

    uint256 _totalEquityBefore = _positionInfoBefore.stablePositionEquity + _positionInfoBefore.assetPositionEquity;
    uint256 _stableExpectedWithdrawValue = (_withdrawValue *_positionInfoBefore.stablePositionEquity)/_totalEquityBefore;
    uint256 _stableActualWithdrawValue = _positionInfoBefore.stablePositionEquity - _positionInfoAfter.stablePositionEquity;

    if(!Math.almostEqual(_stableActualWithdrawValue, _stableExpectedWithdrawValue, _toleranceBps)){
      revert UnsafePositionValue();
    }
    uint256 _assetExpectedWithdrawValue = (_withdrawValue *_positionInfoBefore.assetPositionEquity)/_totalEquityBefore;
    uint256 _assetActualWithdrawValue = _positionInfoBefore.assetPositionEquity - _positionInfoAfter.assetPositionEquity;
    if(!Math.almostEqual(_assetActualWithdrawValue, _assetExpectedWithdrawValue, _toleranceBps)){
      revert UnsafePositionValue();
    }


    uint256 _totalDebtBefore = _positionInfoBefore.stablePositionDebtValue + _positionInfoBefore.assetPositionDebtValue;
    uint256 _totalPositionValueBefore =  _positionInfoBefore.stablePositionEquity + _positionInfoBefore.assetPositionEquity + _totalDebtBefore;
    uint256 _totalDebtAfter = _positionInfoAfter.stablePositionDebtValue + _positionInfoAfter.assetPositionDebtValue;
    uint256 _totalPositionValueAfter = _positionInfoAfter.stablePositionEquity + _positionInfoAfter.assetPositionEquity + _totalDebtAfter;
    if (!Math.almostEqual(_totalPositionValueBefore/_totalDebtBefore , _totalPositionValueAfter / _totalDebtAfter, _toleranceBps)) {
      revert UnsafeDebtRatio();
    }

  }




  function _outstandingCheck(Outstanding memory _outstandingBefore, Outstanding memory _outstandingAfter) internal {
    if (_outstandingAfter.stableAmount < _outstandingBefore.stableAmount) {
      revert UnsafeOutstanding(stableToken, _outstandingBefore.stableAmount, _outstandingAfter.stableAmount);
    }
    if (_outstandingAfter.assetAmount < _outstandingBefore.assetAmount) {
      revert UnsafeOutstanding(assetToken, _outstandingBefore.assetAmount, _outstandingAfter.assetAmount);
    }
    if (_outstandingAfter.nativeAmount < _outstandingBefore.nativeAmount) {
      revert UnsafeOutstanding(address(0), _outstandingBefore.nativeAmount, _outstandingAfter.nativeAmount);
    }
  }


  function _outstanding() internal view returns (Outstanding memory) {
    return
      Outstanding({
        stableAmount: stableToken.myBalance(),
        assetAmount: assetToken.myBalance(),
        nativeAmount: address(this).balance
      });
  }


  function positionInfo() public view returns (PositionInfo memory) {
    return
      PositionInfo({
        stablePositionEquity: _positionEquity(stableVault, stableVaultWorker, stableVaultPosId),
        stablePositionDebtValue: _positionDebtValue(stableVault, stableVaultPosId),
        assetPositionEquity: _positionEquity(assetVault, assetVaultWorker, assetVaultPosId),
        assetPositionDebtValue: _positionDebtValue(assetVault, assetVaultPosId)
      });
  }



  function shareToValue(uint256 _shareAmount) public view returns (uint256) {
    uint256 _shareSupply = totalSupply();
    if (_shareSupply == 0) return _shareAmount;
    return (_shareAmount * totalEquityValue()) / _shareSupply;
  }



  function valueToShare(uint256 _value) public view returns (uint256) {
    uint256 _shareSupply = totalSupply();
    if (_shareSupply == 0) return _value;
    return (_value * _shareSupply) / totalEquityValue();
  }


  function totalEquityValue() public view returns (uint256) {
    uint256 _positionValue = _positionValue(stableVaultWorker) + _positionValue(assetVaultWorker);
    uint256 _debtValue = _positionDebtValue(stableVault, stableVaultPosId) + _positionDebtValue(assetVault, assetVaultPosId);
    if (_positionValue < _debtValue) {
      return 0;
    }
    return _positionValue - _debtValue;
  }

  function _positionDebtValue(address _vault, uint256 _posId) internal view returns (uint256) {
    (, , uint256 _positionDebtShare) = IVault(_vault).positions(_posId);
    address _token = IVault(_vault).token();
    uint256 _vaultDebtShare = IVault(_vault).vaultDebtShare();
    if (_vaultDebtShare == 0) {
      return (_positionDebtShare * priceHelper.getTokenPrice(_token))/1e18;
    }
    uint256 _vaultDebtValue = IVault(_vault).vaultDebtVal() + IVault(_vault).pendingInterest(0);
    uint256 _debtAmount = (_positionDebtShare * _vaultDebtValue) / _vaultDebtShare;
    return (_debtAmount * priceHelper.getTokenPrice(_token))/1e18;
  }

  function _positionValue(address _worker) internal view returns (uint256) {
    return priceHelper.lpToDollar(IWorker02(_worker).totalLpBalance(), lpToken);
  }

  function _positionEquity(address _vault, address _worker, uint256 _posId) internal view returns (uint256) {
    uint256 _positionValue = _positionValue(_worker);
    uint256 _positionDebtValue = _positionDebtValue(_vault, _posId);
    if( _positionValue < _positionDebtValue){
      return 0;
    }
    return _positionValue - _positionDebtValue;
  }


  function _execute(
    uint8[] memory _actions,
    uint256[] memory _values,
    bytes[] memory _datas
  ) internal {
    for (uint256 i = 0; i < _actions.length; i++) {
      uint8 _action = _actions[i];
      if (_action == ACTION_WORK) {
        _doWork(_datas[i]);
      }
      if (_action == ACTION_WRAP) {
        IWETH(config.getWrappedNativeAddr()).deposit{ value: _values[i] }();
      }
    }
  }



  function _doWork(bytes memory _data) internal {

    if (stableVaultPosId == 0 || assetVaultPosId == 0) {
      revert PositionsNotInitialized();
    }


    (
      address payable _vault,
      uint256 _posId,
      address _worker,
      uint256 _principalAmount,
      uint256 _borrowAmount,
      uint256 _maxReturn,
      bytes memory _workData
    ) = abi.decode(_data, (address, uint256, address, uint256, uint256, uint256, bytes));

    if ( !OPENING  &&
      !((_vault == stableVault && _posId == stableVaultPosId) || (_vault == assetVault && _posId == assetVaultPosId))
    ) {
      revert InvalidPositions({ _vault: _vault, _positionId: _posId });
    }


    stableToken.safeApprove(_vault, type(uint256).max);
    assetToken.safeApprove(_vault, type(uint256).max);


    IVault(_vault).work(_posId, _worker, _principalAmount, _borrowAmount, _maxReturn, _workData);


    stableToken.safeApprove(_vault, 0);
    assetToken.safeApprove(_vault, 0);
  }


  function claim() external returns (uint256, uint256) {
    uint256 rewardStableVault = _claim(IVault(stableVault).fairLaunchPoolId());
    uint256 rewardAssetVault = _claim(IVault(assetVault).fairLaunchPoolId());
  }


  function _claim(uint256 _poolId) internal returns (uint256) {
    uint256 alpacaBefore = alpacaToken.myBalance();
    IFairLaunch(config.fairLaunchAddr()).harvest(_poolId);
    uint256 alpacaAfter = alpacaToken.myBalance();
    return alpacaAfter - alpacaBefore;
  }


  function withdrawAlpaca(address _to, uint256 amount) external onlyOwner {
    alpacaToken.safeTransfer(_to, amount);
  }


  receive() external payable {}
}

pragma solidity 0.8.10;

import "@openzeppelin/contracts-upgradeable/security/ReentrancyGuardUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/access/OwnableUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/token/ERC20/ERC20Upgradeable.sol";

import "./interfaces/IPriceHelper.sol";
import "./interfaces/IVault.sol";
import "./interfaces/IWorker02.sol";
import "./interfaces/IWETH.sol";
import "./interfaces/IWNativeRelayer.sol";
import "./interfaces/IDeltaNeutralVaultConfig.sol";
import "./interfaces/IFairLaunch.sol";
import "../utils/SafeToken.sol";
import "../utils/Math.sol";

contract DeltaNeutralVault is ERC20Upgradeable, ReentrancyGuardUpgradeable, OwnableUpgradeable {

  using SafeToken for address;


  event LogInitializePositions(address indexed _from, uint256 _stableVaultPosId, uint256 _assetVaultPosId);
  event LogDeposit(
    address indexed _from,
    address indexed _shareReceiver,
    uint256 _shares,
    uint256 _stableTokenAmount,
    uint256 _assetTokenAmount
  );
  event LogWithdraw(address indexed _shareOwner, uint256 _minStableTokenAmount, uint256 _minAssetTokenAmount);
  event LogRebalance(uint256 _equityBefore, uint256 _equityAfter);


  error Unauthorized(address _caller);
  error PositionsAlreadyInitialized();
  error PositionsNotInitialized();
  error InvalidPositions(address _vault, uint256 _positionId);
  error UnsafePositionEquity();
  error UnsafePositionValue();
  error UnsafeDebtValue();
  error UnsafeDebtRatio();
  error UnsafeOutstanding(address _token, uint256 _amountBefore, uint256 _amountAfter);
  error PositionsIsHealthy();
  error InsufficientTokenReceived(address _token, uint256 _requiredAmount, uint256 _receivedAmount);
  error InsufficientShareReceived(uint256 _requiredAmount, uint256 _receivedAmount);

  struct Outstanding {
    uint256 stableAmount;
    uint256 assetAmount;
    uint256 nativeAmount;
  }

  struct PositionInfo{
    uint256 stablePositionEquity;
    uint256 stablePositionDebtValue;
    uint256 assetPositionEquity;
    uint256 assetPositionDebtValue;
  }


  uint8 private constant ACTION_WORK = 1;
  uint8 private constant ACTION_WRAP = 2;

  address private lpToken;
  address public stableVault;
  address public assetVault;

  address public stableVaultWorker;
  address public assetVaultWorker;

  address public stableToken;
  address public assetToken;
  address public alpacaToken;

  uint256 public stableVaultPosId;
  uint256 public assetVaultPosId;

  IPriceHelper public priceHelper;

  IDeltaNeutralVaultConfig public config;


  bool private OPENING;


  modifier onlyEOAorWhitelisted() {
    if (msg.sender != tx.origin && !config.whitelistedCallers(msg.sender)) {
      revert Unauthorized(msg.sender);
    }
    _;
  }


  modifier onlyRebalancers() {
    if (!config.whitelistedRebalancers(msg.sender)) revert Unauthorized(msg.sender);
    _;
  }












  function initialize(
    string calldata _name,
    string calldata _symbol,
    address _stableVault,
    address _assetVault,
    address _stableVaultWorker,
    address _assetVaultWorker,
    address _lpToken,
    address _alpacaToken,
    IPriceHelper _priceHelper,
    IDeltaNeutralVaultConfig _config
  ) external initializer {
    OwnableUpgradeable.__Ownable_init();
    ReentrancyGuardUpgradeable.__ReentrancyGuard_init();
    ERC20Upgradeable.__ERC20_init(_name, _symbol);

    stableVault = _stableVault;
    assetVault = _assetVault;

    stableToken = IVault(_stableVault).token();
    assetToken = IVault(_assetVault).token();
    alpacaToken = _alpacaToken;

    stableVaultWorker = _stableVaultWorker;
    assetVaultWorker = _assetVaultWorker;

    lpToken = _lpToken;

    priceHelper = _priceHelper;
    config = _config;
  }






  function initPositions(
    uint256 _minShareReceive,
    uint256 _stableTokenAmount,
    uint256 _assetTokenAmount,
    bytes calldata _data
  ) external payable onlyOwner {
    if (stableVaultPosId != 0 || assetVaultPosId != 0) {
      revert PositionsAlreadyInitialized();
    }

    OPENING = true;
    stableVaultPosId = IVault(stableVault).nextPositionID();
    assetVaultPosId = IVault(assetVault).nextPositionID();

    deposit(msg.sender, _minShareReceive, _stableTokenAmount, _assetTokenAmount, _data);

    OPENING = false;

    emit LogInitializePositions(msg.sender, stableVaultPosId, assetVaultPosId);
  }




  function _transferTokenToVault(address _token, uint256 _amount) internal {
    if (_token == config.getWrappedNativeAddr()) {
      IWETH(config.getWrappedNativeAddr()).deposit{ value: _amount }();
    } else {
      SafeToken.safeTransferFrom(_token, msg.sender, address(this), _amount);
    }
  }





  function _transferTokenToShareOwner(
    address _to,
    address _token,
    uint256 _amount
  ) internal {
    if (_token == config.getWrappedNativeAddr()) {
      SafeToken.safeTransferETH(_to, _amount);
    } else {
      SafeToken.safeTransfer(_token, _to, _amount);
    }
  }









  function deposit(
    address _shareReceiver,
    uint256 _minShareReceive,
    uint256 _stableTokenAmount,
    uint256 _assetTokenAmount,
    bytes calldata _data
  ) public payable onlyEOAorWhitelisted nonReentrant returns (uint256 _shares) {

    PositionInfo memory _positionInfoBefore = positionInfo();
    Outstanding memory _outstandingBefore = _outstanding();
    _outstandingBefore.nativeAmount = _outstandingBefore.nativeAmount - msg.value;


    _transferTokenToVault(stableToken, _stableTokenAmount);
    _transferTokenToVault(assetToken, _assetTokenAmount);


    uint256 _depositValue = ((_stableTokenAmount * priceHelper.getTokenPrice(stableToken)) +
      (_assetTokenAmount * priceHelper.getTokenPrice(assetToken))) / 1e18;

    uint256 _shares = valueToShare(_depositValue);
    if (_shares < _minShareReceive) {
      revert InsufficientShareReceived(_minShareReceive, _shares);
    }

    _mint(_shareReceiver, _shares);

    {


      (uint8[] memory actions, uint256[] memory values, bytes[] memory _datas) = abi.decode(
        _data,
        (uint8[], uint256[], bytes[])
      );
      _execute(actions, values, _datas);
    }


    _depositHealthCheck(
      _depositValue,
      _positionInfoBefore,
      positionInfo()
    );
    _outstandingCheck(_outstandingBefore, _outstanding());

    emit LogDeposit(msg.sender, _shareReceiver, _shares, _stableTokenAmount, _assetTokenAmount);
    return _shares;
  }







  function withdraw(
    uint256 _shareAmount,
    uint256 _minStableTokenAmount,
    uint256 _minAssetTokenAmount,
    bytes calldata _data
  ) public onlyEOAorWhitelisted nonReentrant returns (uint256 _withdrawValue) {

    address _shareOwner = msg.sender;
    PositionInfo memory _positionInfoBefore = positionInfo();
    Outstanding memory _outstandingBefore = _outstanding();

    uint256 _shareValue = shareToValue(_shareAmount);
    _burn(_shareOwner, _shareAmount);

    {
      (uint8[] memory actions, uint256[] memory values, bytes[] memory _datas) = abi.decode(
        _data,
        (uint8[], uint256[], bytes[])
      );
      _execute(actions, values, _datas);
    }

    PositionInfo memory _positionInfoAfter = positionInfo();
    Outstanding memory _outstandingAfter = _outstanding();


    uint256 _stableTokenBack = stableToken == config.getWrappedNativeAddr()
      ? _outstandingAfter.nativeAmount - _outstandingBefore.nativeAmount
      : _outstandingAfter.stableAmount - _outstandingBefore.stableAmount;
    uint256 _assetTokenBack = assetToken == config.getWrappedNativeAddr()
      ? _outstandingAfter.nativeAmount - _outstandingBefore.nativeAmount
      : _outstandingAfter.assetAmount - _outstandingBefore.assetAmount;

    if (_stableTokenBack < _minStableTokenAmount) {
      revert InsufficientTokenReceived(stableToken, _minStableTokenAmount, _stableTokenBack);
    }
    if (_assetTokenBack < _minAssetTokenAmount) {
      revert InsufficientTokenReceived(assetToken, _minAssetTokenAmount, _assetTokenBack);
    }

    _transferTokenToShareOwner(_shareOwner, stableToken, _stableTokenBack);
    _transferTokenToShareOwner(_shareOwner, assetToken, _assetTokenBack);

    uint256 _withdrawValue;
    {
      uint256 _stableWithdrawValue = _stableTokenBack * priceHelper.getTokenPrice(stableToken);
      uint256 _assetWithdrawValue = _assetTokenBack * priceHelper.getTokenPrice(assetToken);
      _withdrawValue = (_stableWithdrawValue + _assetWithdrawValue) / 1e18;
    }


    _withdrawHealthCheck(_withdrawValue, _positionInfoBefore, _positionInfoAfter);
    _outstandingCheck(_outstandingBefore, _outstandingAfter);

    emit LogWithdraw(_shareOwner, _stableTokenBack, _assetTokenBack);
    return _withdrawValue;
  }


  function rebalance(
    uint8[] memory _actions,
    uint256[] memory _values,
    bytes[] memory _datas
  ) external onlyRebalancers {

    PositionInfo memory _positionInfoBefore = positionInfo();
    Outstanding memory _outstandingBefore = _outstanding();
    uint256 _stablePositionValue = _positionInfoBefore.stablePositionEquity + _positionInfoBefore.stablePositionDebtValue;
    uint256 _assetPositionValue = _positionInfoBefore.assetPositionEquity + _positionInfoBefore.assetPositionDebtValue;
    uint256 _equityBefore = _positionInfoBefore.stablePositionEquity + _positionInfoBefore.assetPositionEquity;
    uint256 _rebalanceFactor = config.rebalanceFactor();

    if (
      _stablePositionValue * _rebalanceFactor >= _positionInfoBefore.stablePositionDebtValue * 10000 &&
      _assetPositionValue * _rebalanceFactor >= _positionInfoBefore.assetPositionDebtValue * 10000
    ) {
      revert PositionsIsHealthy();
    }


    {
      _execute(_actions, _values, _datas);
    }



    uint256 _equityAfter = totalEquityValue();
    if (!Math.almostEqual(_equityAfter, _equityBefore, config.positionValueTolerance())) {
      revert UnsafePositionValue();
    }
    _outstandingCheck(_outstandingBefore, _outstanding());

    emit LogRebalance(_equityBefore, _equityAfter);
  }





  function _depositHealthCheck(
    uint256 _depositValue,
    PositionInfo memory _positionInfoBefore,
    PositionInfo memory _positionInfoAfter
  ) internal {

    uint256 _toleranceBps = config.positionValueTolerance();


    if (
      !Math.almostEqual(_positionInfoAfter.stablePositionEquity - _positionInfoBefore.stablePositionEquity, (_depositValue ) / 4, _toleranceBps) ||
      !Math.almostEqual(_positionInfoAfter.assetPositionEquity - _positionInfoBefore.assetPositionEquity, (_depositValue * 3) / 4, _toleranceBps)
    ) {
      revert UnsafePositionEquity();
    }


    if (
      !Math.almostEqual(
        _positionInfoAfter.stablePositionDebtValue - _positionInfoBefore.stablePositionDebtValue ,
        (_depositValue * 2) / 4,
        _toleranceBps
      ) ||
      !Math.almostEqual( _positionInfoAfter.assetPositionDebtValue - _positionInfoBefore.assetPositionDebtValue, (_depositValue * 6) / 4, _toleranceBps)
    ) {
      revert UnsafeDebtValue();
    }
  }





  function _withdrawHealthCheck(
    uint256 _withdrawValue,
    PositionInfo memory _positionInfoBefore,
    PositionInfo memory _positionInfoAfter
  ) internal {
    uint256 _toleranceBps = config.positionValueTolerance();

    uint256 _totalEquityBefore = _positionInfoBefore.stablePositionEquity + _positionInfoBefore.assetPositionEquity;
    uint256 _stableExpectedWithdrawValue = (_withdrawValue *_positionInfoBefore.stablePositionEquity)/_totalEquityBefore;
    uint256 _stableActualWithdrawValue = _positionInfoBefore.stablePositionEquity - _positionInfoAfter.stablePositionEquity;

    if(!Math.almostEqual(_stableActualWithdrawValue, _stableExpectedWithdrawValue, _toleranceBps)){
      revert UnsafePositionValue();
    }
    uint256 _assetExpectedWithdrawValue = (_withdrawValue *_positionInfoBefore.assetPositionEquity)/_totalEquityBefore;
    uint256 _assetActualWithdrawValue = _positionInfoBefore.assetPositionEquity - _positionInfoAfter.assetPositionEquity;
    if(!Math.almostEqual(_assetActualWithdrawValue, _assetExpectedWithdrawValue, _toleranceBps)){
      revert UnsafePositionValue();
    }


    uint256 _totalDebtBefore = _positionInfoBefore.stablePositionDebtValue + _positionInfoBefore.assetPositionDebtValue;
    uint256 _totalPositionValueBefore =  _positionInfoBefore.stablePositionEquity + _positionInfoBefore.assetPositionEquity + _totalDebtBefore;
    uint256 _totalDebtAfter = _positionInfoAfter.stablePositionDebtValue + _positionInfoAfter.assetPositionDebtValue;
    uint256 _totalPositionValueAfter = _positionInfoAfter.stablePositionEquity + _positionInfoAfter.assetPositionEquity + _totalDebtAfter;
    if (!Math.almostEqual(_totalPositionValueBefore/_totalDebtBefore , _totalPositionValueAfter / _totalDebtAfter, _toleranceBps)) {
      revert UnsafeDebtRatio();
    }

  }




  function _outstandingCheck(Outstanding memory _outstandingBefore, Outstanding memory _outstandingAfter) internal {
    if (_outstandingAfter.stableAmount < _outstandingBefore.stableAmount) {
      revert UnsafeOutstanding(stableToken, _outstandingBefore.stableAmount, _outstandingAfter.stableAmount);
    }
    if (_outstandingAfter.assetAmount < _outstandingBefore.assetAmount) {
      revert UnsafeOutstanding(assetToken, _outstandingBefore.assetAmount, _outstandingAfter.assetAmount);
    }
    if (_outstandingAfter.nativeAmount < _outstandingBefore.nativeAmount) {
      revert UnsafeOutstanding(address(0), _outstandingBefore.nativeAmount, _outstandingAfter.nativeAmount);
    }
  }


  function _outstanding() internal view returns (Outstanding memory) {
    return
      Outstanding({
        stableAmount: stableToken.myBalance(),
        assetAmount: assetToken.myBalance(),
        nativeAmount: address(this).balance
      });
  }


  function positionInfo() public view returns (PositionInfo memory) {
    return
      PositionInfo({
        stablePositionEquity: _positionEquity(stableVault, stableVaultWorker, stableVaultPosId),
        stablePositionDebtValue: _positionDebtValue(stableVault, stableVaultPosId),
        assetPositionEquity: _positionEquity(assetVault, assetVaultWorker, assetVaultPosId),
        assetPositionDebtValue: _positionDebtValue(assetVault, assetVaultPosId)
      });
  }



  function shareToValue(uint256 _shareAmount) public view returns (uint256) {
    uint256 _shareSupply = totalSupply();
    if (_shareSupply == 0) return _shareAmount;
    return (_shareAmount * totalEquityValue()) / _shareSupply;
  }



  function valueToShare(uint256 _value) public view returns (uint256) {
    uint256 _shareSupply = totalSupply();
    if (_shareSupply == 0) return _value;
    return (_value * _shareSupply) / totalEquityValue();
  }


  function totalEquityValue() public view returns (uint256) {
    uint256 _positionValue = _positionValue(stableVaultWorker) + _positionValue(assetVaultWorker);
    uint256 _debtValue = _positionDebtValue(stableVault, stableVaultPosId) + _positionDebtValue(assetVault, assetVaultPosId);
    if (_positionValue < _debtValue) {
      return 0;
    }
    return _positionValue - _debtValue;
  }

  function _positionDebtValue(address _vault, uint256 _posId) internal view returns (uint256) {
    (, , uint256 _positionDebtShare) = IVault(_vault).positions(_posId);
    address _token = IVault(_vault).token();
    uint256 _vaultDebtShare = IVault(_vault).vaultDebtShare();
    if (_vaultDebtShare == 0) {
      return (_positionDebtShare * priceHelper.getTokenPrice(_token))/1e18;
    }
    uint256 _vaultDebtValue = IVault(_vault).vaultDebtVal() + IVault(_vault).pendingInterest(0);
    uint256 _debtAmount = (_positionDebtShare * _vaultDebtValue) / _vaultDebtShare;
    return (_debtAmount * priceHelper.getTokenPrice(_token))/1e18;
  }

  function _positionValue(address _worker) internal view returns (uint256) {
    return priceHelper.lpToDollar(IWorker02(_worker).totalLpBalance(), lpToken);
  }

  function _positionEquity(address _vault, address _worker, uint256 _posId) internal view returns (uint256) {
    uint256 _positionValue = _positionValue(_worker);
    uint256 _positionDebtValue = _positionDebtValue(_vault, _posId);
    if( _positionValue < _positionDebtValue){
      return 0;
    }
    return _positionValue - _positionDebtValue;
  }


  function _execute(
    uint8[] memory _actions,
    uint256[] memory _values,
    bytes[] memory _datas
  ) internal {
    for (uint256 i = 0; i < _actions.length; i++) {
      uint8 _action = _actions[i];
      if (_action == ACTION_WORK) {
        _doWork(_datas[i]);
      }
      if (_action == ACTION_WRAP) {
        IWETH(config.getWrappedNativeAddr()).deposit{ value: _values[i] }();
      }
    }
  }



  function _doWork(bytes memory _data) internal {

    if (stableVaultPosId == 0 || assetVaultPosId == 0) {
      revert PositionsNotInitialized();
    }


    (
      address payable _vault,
      uint256 _posId,
      address _worker,
      uint256 _principalAmount,
      uint256 _borrowAmount,
      uint256 _maxReturn,
      bytes memory _workData
    ) = abi.decode(_data, (address, uint256, address, uint256, uint256, uint256, bytes));

    if ( !OPENING  &&
      !((_vault == stableVault && _posId == stableVaultPosId) || (_vault == assetVault && _posId == assetVaultPosId))
    ) {
      revert InvalidPositions({ _vault: _vault, _positionId: _posId });
    }


    stableToken.safeApprove(_vault, type(uint256).max);
    assetToken.safeApprove(_vault, type(uint256).max);


    IVault(_vault).work(_posId, _worker, _principalAmount, _borrowAmount, _maxReturn, _workData);


    stableToken.safeApprove(_vault, 0);
    assetToken.safeApprove(_vault, 0);
  }


  function claim() external returns (uint256, uint256) {
    uint256 rewardStableVault = _claim(IVault(stableVault).fairLaunchPoolId());
    uint256 rewardAssetVault = _claim(IVault(assetVault).fairLaunchPoolId());
  }


  function _claim(uint256 _poolId) internal returns (uint256) {
    uint256 alpacaBefore = alpacaToken.myBalance();
    IFairLaunch(config.fairLaunchAddr()).harvest(_poolId);
    uint256 alpacaAfter = alpacaToken.myBalance();
    return alpacaAfter - alpacaBefore;
  }


  function withdrawAlpaca(address _to, uint256 amount) external onlyOwner {
    alpacaToken.safeTransfer(_to, amount);
  }


  receive() external payable {}
}

pragma solidity =0.7.6;

import './interfaces/IImpossibleWrappedToken.sol';
import './interfaces/IERC20.sol';
import './libraries/SafeMath.sol';

contract ImpossibleWrappedToken is IImpossibleWrappedToken {
    using SafeMath for uint256;

    string public override name;
    string public override symbol;
    uint8 public override decimals = 18;
    uint256 public override totalSupply;

    address public underlying;
    uint256 public underlyingBalance;
    uint256 public ratioNum;
    uint256 public ratioDenom;

    mapping(address => uint256) public override balanceOf;
    mapping(address => mapping(address => uint256)) public override allowance;

    constructor(
        address _underlying,
        uint256 _ratioNum,
        uint256 _ratioDenom
    ) {
        underlying = _underlying;
        ratioNum = _ratioNum;
        ratioDenom = _ratioDenom;
        string memory desc = string(abi.encodePacked(IERC20(_underlying).symbol()));
        name = string(abi.encodePacked('IF-Wrapped ', desc));
        symbol = string(abi.encodePacked('WIF ', desc));
    }



    function deposit(address dst, uint256 wad) public returns (uint256 transferAmt) {
        transferAmt = wad.mul(ratioDenom).div(ratioNum);
        bool success = IERC20(underlying).transferFrom(msg.sender, address(this), transferAmt);
        require(success, 'ImpossibleWrapper: TRANSFERFROM_FAILED');
        _deposit(dst, wad);
        underlyingBalance = underlyingBalance.add(transferAmt);
        emit Transfer(address(0), msg.sender, wad);
    }




    function deposit(address dst) public override returns (uint256 transferAmt) {
        uint256 balance = IERC20(underlying).balanceOf(address(this));
        transferAmt = balance.sub(underlyingBalance);
        uint256 wad = transferAmt.mul(ratioNum).div(ratioDenom);
        _deposit(dst, wad);
        underlyingBalance = balance;
        emit Transfer(address(0), dst, wad);
    }


    function _deposit(address dst, uint256 wad) internal {
        balanceOf[dst] = balanceOf[dst].add(wad);
        totalSupply = totalSupply.add(wad);
    }


    function withdraw(address dst, uint256 wad) public override returns (uint256 transferAmt) {
        balanceOf[msg.sender] = balanceOf[msg.sender].sub(wad);
        emit Transfer(msg.sender, address(0), wad);
        return _withdraw(dst, wad);
    }

    function withdraw(
        address src,
        address dst,
        uint256 wad
    ) public returns (uint256 transferAmt) {
        allowance[src][msg.sender] = allowance[src][msg.sender].sub(wad);
        balanceOf[src] = balanceOf[src].sub(wad);
        emit Transfer(src, address(0), wad);
        return _withdraw(dst, wad);
    }

    function _withdraw(address dst, uint256 wad) internal returns (uint256 transferAmt) {
        totalSupply = totalSupply.sub(wad);
        transferAmt = wad.mul(ratioDenom).div(ratioNum);
        bool success = IERC20(underlying).transfer(dst, transferAmt);
        require(success, 'IF Wrapper: UNDERLYING_TRANSFER_FAIL');
        underlyingBalance = underlyingBalance.sub(transferAmt);
    }

    function amtToUnderlyingAmt(uint256 amt) public view override returns (uint256) {
        return amt.mul(ratioDenom).div(ratioNum);
    }

    function approve(address guy, uint256 wad) public override returns (bool) {
        allowance[msg.sender][guy] = wad;
        emit Approval(msg.sender, guy, wad);
        return true;
    }

    function transfer(address dst, uint256 wad) public override returns (bool) {
        return transferFrom(msg.sender, dst, wad);
    }

    function transferFrom(
        address src,
        address dst,
        uint256 wad
    ) public override returns (bool) {
        require(balanceOf[src] >= wad, '');

        if (src != msg.sender && allowance[src][msg.sender] != uint256(-1)) {
            require(allowance[src][msg.sender] >= wad, 'ImpossibleWrapper: INSUFF_ALLOWANCE');
            allowance[src][msg.sender] -= wad;
        }

        balanceOf[src] -= wad;
        balanceOf[dst] += wad;

        emit Transfer(src, dst, wad);

        return true;
    }
}

pragma solidity ^0.8.7;

import "../interfaces/external/uniswap/IUniswapV3Router.sol";
import "../interfaces/external/aave/IAave.sol";

import "./GenericLenderBase.sol";





contract GenericAave is GenericLenderBase {
    using SafeERC20 for IERC20;
    using Address for address;

    uint256 internal constant _SECONDS_IN_YEAR = 365 days;
    uint16 internal constant _DEFAULT_REFERRAL = 179; 



    IProtocolDataProvider public constant protocolDataProvider =
        IProtocolDataProvider(address(0x057835Ad21a177dbdd3090bB1CAE03EaCF78Fc6d));
    IAToken public aToken;
    IStakedAave public constant stkAave = IStakedAave(0x4da27a545c0c5B758a6BA100e3a049001de870f5);
    address public constant WETH = address(0xC02aaA39b223FE8D0A0e5C4F27eAD9083C756Cc2);
    address public constant AAVE = address(0x7Fc66500c84A76Ad7e9c93437bFc5Ac33E2DDaE9);
    IUniswapV3Router public uniswapRouter;



    bytes public path;
    bool public isIncentivised;
    uint16 internal _customReferral;




    constructor(
        address _strategy,
        string memory name,
        IUniswapV3Router _uniswapRouter,
        IAToken _aToken,
        bool _isIncentivised,
        bytes memory _path,
        address[] memory governorList,
        address guardian
    ) GenericLenderBase(_strategy, name, governorList, guardian) {
        require(address(aToken) == address(0), "already initialized");

        require(
            !_isIncentivised || address(_aToken.getIncentivesController()) != address(0),
            "aToken does not have incentives controller set up"
        );
        uniswapRouter = _uniswapRouter;
        isIncentivised = _isIncentivised;
        aToken = _aToken;
        path = _path;
        require(_lendingPool().getReserveData(address(want)).aTokenAddress == address(_aToken), "wrong aToken");
        IERC20(address(want)).safeApprove(address(_lendingPool()), type(uint256).max);
    }




    function deposit() external override onlyRole(STRATEGY_ROLE) {
        uint256 balance = want.balanceOf(address(this));
        _deposit(balance);
    }




    function withdraw(uint256 amount) external override onlyRole(STRATEGY_ROLE) returns (uint256) {
        return _withdraw(amount);
    }




    function emergencyWithdraw(uint256 amount) external override onlyRole(GUARDIAN_ROLE) {
        _lendingPool().withdraw(address(want), amount, address(this));

        want.safeTransfer(address(poolManager), want.balanceOf(address(this)));
    }


    function withdrawAll() external override onlyRole(STRATEGY_ROLE) returns (bool) {
        uint256 invested = _nav();
        uint256 returned = _withdraw(invested);
        return returned >= invested;
    }

    function startCooldown() external onlyRole(GUARDIAN_ROLE) {

        IStakedAave(stkAave).cooldown(); 
    }





    function harvest() external {
        require(_checkCooldown(), "conditions are not met");

        uint256 stkAaveBalance = IERC20(address(stkAave)).balanceOf(address(this));
        if (stkAaveBalance > 0) {
            stkAave.redeem(address(this), stkAaveBalance);
        }


        uint256 aaveBalance = IERC20(AAVE).balanceOf(address(this));
        _sellAAVEForWant(aaveBalance);


        uint256 balance = want.balanceOf(address(this));
        if (balance > 0) {
            _deposit(balance);
        }


        address[] memory assets = new address[](1);
        assets[0] = address(aToken);
        uint256 pendingRewards = _incentivesController().getRewardsBalance(assets, address(this));
        if (pendingRewards > 0) {
            _incentivesController().claimRewards(assets, pendingRewards, address(this));
        }


        if (IERC20(address(stkAave)).balanceOf(address(this)) > 0) {
            stkAave.cooldown();
        }
    }




    function nav() external view override returns (uint256) {
        return _nav();
    }


    function underlyingBalanceStored() public view returns (uint256 balance) {
        balance = aToken.balanceOf(address(this));
    }


    function apr() external view override returns (uint256) {
        return _apr();
    }


    function weightedApr() external view override returns (uint256) {
        uint256 a = _apr();
        return a * _nav();
    }



    function aprAfterDeposit(uint256 extraAmount) external view override returns (uint256) {

        DataTypes.ReserveData memory reserveData = _lendingPool().getReserveData(address(want));

        (
            uint256 availableLiquidity,
            uint256 totalStableDebt,
            uint256 totalVariableDebt,
            ,
            ,
            ,
            uint256 averageStableBorrowRate,
            ,
            ,

        ) = protocolDataProvider.getReserveData(address(want));

        uint256 newLiquidity = availableLiquidity + extraAmount;

        (, , , , uint256 reserveFactor, , , , , ) = protocolDataProvider.getReserveConfigurationData(address(want));

        (uint256 newLiquidityRate, , ) = IReserveInterestRateStrategy(reserveData.interestRateStrategyAddress)
            .calculateInterestRates(
                address(want),
                newLiquidity,
                totalStableDebt,
                totalVariableDebt,
                averageStableBorrowRate,
                reserveFactor
            );

        return newLiquidityRate / 1e9; 
    }


    function hasAssets() external view override returns (bool) {
        return aToken.balanceOf(address(this)) > 0;
    }


    function harvestTrigger() external view returns (bool) {
        return _checkCooldown();
    }




    function _apr() internal view returns (uint256) {
        uint256 liquidityRate = uint256(_lendingPool().getReserveData(address(want)).currentLiquidityRate) / 1e9; 
        return liquidityRate;
    }


    function _nav() internal view returns (uint256) {
        return want.balanceOf(address(this)) + underlyingBalanceStored();
    }


    function _withdraw(uint256 amount) internal returns (uint256) {
        uint256 balanceUnderlying = aToken.balanceOf(address(this));
        uint256 looseBalance = want.balanceOf(address(this));
        uint256 total = balanceUnderlying + looseBalance;

        if (amount > total) {

            amount = total;
        }

        if (looseBalance >= amount) {
            want.safeTransfer(address(strategy), amount);
            return amount;
        }


        uint256 liquidity = want.balanceOf(address(aToken));

        if (liquidity > 1) {
            uint256 toWithdraw = amount - looseBalance;

            if (toWithdraw <= liquidity) {

                _lendingPool().withdraw(address(want), toWithdraw, address(this));
            } else {

                _lendingPool().withdraw(address(want), liquidity, address(this));
            }
        }
        looseBalance = want.balanceOf(address(this));
        want.safeTransfer(address(strategy), looseBalance);
        return looseBalance;
    }


    function _deposit(uint256 amount) internal {
        ILendingPool lp = _lendingPool();




        if (want.allowance(address(this), address(lp)) < amount) {
            IERC20(address(want)).safeApprove(address(lp), 0);
            IERC20(address(want)).safeApprove(address(lp), type(uint256).max);
        }

        uint16 referral;
        uint16 __customReferral = _customReferral;
        if (__customReferral != 0) {
            referral = __customReferral;
        } else {
            referral = _DEFAULT_REFERRAL;
        }

        lp.deposit(address(want), amount, address(this), referral);
    }


    function _lendingPool() internal view returns (ILendingPool lendingPool) {
        lendingPool = ILendingPool(protocolDataProvider.ADDRESSES_PROVIDER().getLendingPool());
    }


    function _checkCooldown() internal view returns (bool) {
        if (!isIncentivised) {
            return false;
        }

        uint256 cooldownStartTimestamp = IStakedAave(stkAave).stakersCooldowns(address(this));
        uint256 cooldownSeconds = IStakedAave(stkAave).COOLDOWN_SECONDS();
        uint256 unstakeWindow = IStakedAave(stkAave).UNSTAKE_WINDOW();
        if (block.timestamp >= cooldownStartTimestamp + cooldownSeconds) {
            return
                block.timestamp - cooldownStartTimestamp + cooldownSeconds <= unstakeWindow ||
                cooldownStartTimestamp == 0;
        } else {
            return false;
        }
    }



    function _sellAAVEForWant(uint256 _amount) internal {
        if (_amount == 0) {
            return;
        }

        if (IERC20(AAVE).allowance(address(this), address(uniswapRouter)) < _amount) {
            IERC20(AAVE).safeApprove(address(uniswapRouter), 0);
            IERC20(AAVE).safeApprove(address(uniswapRouter), type(uint256).max);
        }

        uniswapRouter.exactInput(ExactInputParams(path, address(this), block.timestamp, _amount, uint256(0)));
    }


    function _incentivesController() internal view returns (IAaveIncentivesController) {
        if (isIncentivised) {
            return aToken.getIncentivesController();
        } else {
            return IAaveIncentivesController(address(0));
        }
    }


    function _protectedTokens() internal view override returns (address[] memory) {
        address[] memory protected = new address[](2);
        protected[0] = address(want);
        protected[1] = address(aToken);
        return protected;
    }





    function setIsIncentivised(bool _isIncentivised) external onlyRole(GUARDIAN_ROLE) {


        require(
            !_isIncentivised || address(aToken.getIncentivesController()) != address(0),
            "aToken does not have incentives controller set up"
        );
        isIncentivised = _isIncentivised;
    }



    function setReferralCode(uint16 __customReferral) external onlyRole(GUARDIAN_ROLE) {
        require(__customReferral != 0, "invalid referral code");
        _customReferral = __customReferral;
    }



    function setPath(bytes memory _path) external onlyRole(GUARDIAN_ROLE) {
        path = _path;
    }
}

pragma solidity ^0.4.24;

import "../abstract/erc/IERC20Base.sol";
import "../abstract/IFeeService.sol";

import "../zeppelin/Math.sol";
import "./QuotaLib.sol";



library ProPoolLib {    
    using QuotaLib for QuotaLib.Storage;





    enum State {
        Open,
        PaidToPresale,
        Distribution,        
        FullRefund,
        Canceled
    }


    struct Group {




        uint contribution;            







        uint remaining;                   


        uint maxBalance;


        uint minContribution; 


        uint maxContribution;        


        uint ctorFeePerEther;          




        bool isRestricted;


        bool exists;
    }


    struct Participant {


        uint[8] contribution;


        uint[8] remaining;


        bool[8] whitelist;  


        bool isAdmin;


        bool exists;
    }    


    struct Pool {


        State state;



        uint svcFeePerEther;



        address refundAddress;




        address presaleAddress;



        bool lockPresale;


        IFeeService feeService;




        address feeToTokenAddress;        
        bool feeToTokenMode;


        address[] admins;


        address[] participants;     


        address[] tokenAddresses;


        Group[8] groups;         


        mapping(address => Participant) participantToData;   


        mapping(address => QuotaLib.Storage) tokenQuota;  


        QuotaLib.Storage refundQuota;
    }                     


    modifier onlyAdmin(Pool storage pool) {
        require(pool.participantToData[msg.sender].isAdmin);
        _;
    }


    modifier onlyInState(Pool storage pool, State state) {
        require(pool.state == state);
        _;
    }      


    modifier onlyInStates2(Pool storage pool, State state1, State state2) {
        require(pool.state == state1 || pool.state == state2);
        _;
    }  


    modifier onlyInStates3(Pool storage pool, State state1, State state2, State state3) {
        require(pool.state == state1 || pool.state == state2 || pool.state == state3);
        _;
    }    


    function init(
        Pool storage pool,           
        uint maxBalance,
        uint minContribution,
        uint maxContribution,
        uint ctorFeePerEther,
        bool isRestricted,                
        address creatorAddress,        
        address presaleAddress,        
        address feeServiceAddr,
        address[] whitelist,
        address[] admins
    )
        public 
    {


        if(presaleAddress != address(0)) {
            require(presaleAddress != address(this)); 
            pool.presaleAddress = presaleAddress;           
            emit PresaleAddressLocked(presaleAddress);            
        }


        pool.feeService = IFeeService(feeServiceAddr);        
        pool.svcFeePerEther = pool.feeService.getFeePerEther();
        require(pool.svcFeePerEther <= (1 ether / 4));
        emit FeeServiceAttached(
            feeServiceAddr,
            pool.svcFeePerEther
        );  


        require(creatorAddress != address(0));
        addAdmin(pool, creatorAddress);
        for(uint i = 0; i < admins.length; i++) {
            addAdmin(pool, admins[i]);
        }


        setGroupSettingsCore(
            pool,
            0,
            maxBalance,
            minContribution,
            maxContribution,
            ctorFeePerEther,
            isRestricted            
        );


        if(whitelist.length > 0) {
            require(isRestricted);
            modifyWhitelistCore(pool, 0, whitelist, new address[](0));
        }
    }


    function setGroupSettings(
        Pool storage pool,        
        uint idx,
        uint maxBalance,
        uint minContribution,
        uint maxContribution,
        uint ctorFeePerEther,         
        bool isRestricted
    )
        public     
        onlyAdmin(pool)
        onlyInState(pool, State.Open)      
    {

        bool exists = pool.groups[idx].exists;


        setGroupSettingsCore(
            pool,
            idx,
            maxBalance,
            minContribution,
            maxContribution,
            ctorFeePerEther,
            isRestricted            
        );

        if(exists) {            

            groupRebalance(pool, idx);
        }
    }


    function modifyWhitelist(Pool storage pool, uint idx, address[] include, address[] exclude)
        public 
        onlyAdmin(pool)
        onlyInState(pool, State.Open)
    {

        modifyWhitelistCore(pool, idx, include, exclude); 

        groupRebalance(pool, idx);
    }     


    function lockPresaleAddress(Pool storage pool, address presaleAddress, bool lock)
        public 
        onlyAdmin(pool) 
        onlyInState(pool, State.Open) 
    {        
        require(presaleAddress != address(0));
        require(presaleAddress != address(this));
        require(pool.presaleAddress == address(0));
        require(!pool.lockPresale);


        pool.presaleAddress = presaleAddress;


        if(lock) {
            pool.lockPresale = true;
        }

        emit PresaleAddressLocked(presaleAddress);
    }   


    function confirmTokenAddress(Pool storage pool, address tokenAddress)
        public
        onlyAdmin(pool)
        onlyInStates2(pool, State.PaidToPresale, State.Distribution)         
    {        
        require(tokenAddress != address(0));
        require(pool.tokenAddresses.length <= 4);
        require(!contains(pool.tokenAddresses, tokenAddress));


        IERC20Base ERC20 = IERC20Base(tokenAddress);
        uint balance = ERC20.balanceOf(address(this));  


        require(balance > 0);


        if(pool.state == State.PaidToPresale) {
            changeState(pool, State.Distribution);            
            sendFees(pool);
        } 


        pool.tokenAddresses.push(tokenAddress);

        emit TokenAddressConfirmed(
            tokenAddress,
            balance
        );
    }


    function setRefundAddress(Pool storage pool, address refundAddress)
        public
        onlyAdmin(pool)
        onlyInStates3(pool, State.PaidToPresale, State.Distribution, State.FullRefund)
    {        
        require(refundAddress != address(0));
        require(pool.refundAddress != refundAddress);


        pool.refundAddress = refundAddress;
        emit RefundAddressChanged(refundAddress);


        if(pool.state == State.PaidToPresale) {
            changeState(pool, State.FullRefund);
        }
    }   


    function payToPresale(
        Pool storage pool,
        address presaleAddress,
        uint minPoolBalance,
        bool feeToToken,
        bytes data
    )
        public
        onlyAdmin(pool) 
        onlyInState(pool, State.Open) 
    {
        require(presaleAddress != address(0));


        if(pool.presaleAddress == address(0)) {
            pool.presaleAddress = presaleAddress;
            emit PresaleAddressLocked(presaleAddress);
        } else { 

            require(pool.presaleAddress == presaleAddress);
        }

        uint ctorFee;
        uint poolRemaining;
        uint poolContribution;      

        (poolContribution, poolRemaining, ctorFee) = calcPoolSummary(pool);        
        require(poolContribution > 0 && poolContribution >= minPoolBalance);


        if(feeToToken) {
            pool.feeToTokenMode = true;            
            pool.feeToTokenAddress = msg.sender;
            ctorFee = 0;
        }

        changeState(pool, State.PaidToPresale);


        addressCall(
            pool.presaleAddress,
            poolContribution - ctorFee - calcFee(poolContribution, pool.svcFeePerEther),
            data
        );        
    }


    function cancel(Pool storage pool)
        public
        onlyAdmin(pool) 
        onlyInState(pool, State.Open)
    {
        changeState(pool, State.Canceled);
    }  


    function deposit(Pool storage pool, uint idx)
        public        
        onlyInState(pool, State.Open)  
    {
        require(msg.value > 0);
        require(pool.groups.length > idx);
        require(pool.groups[idx].exists);


        Participant storage participant = pool.participantToData[msg.sender];
        Group storage group = pool.groups[idx];        


        uint remaining;
        uint contribution;                
        (contribution, remaining) = calcContribution(
            idx, 
            msg.value, 
            group.maxBalance, 
            group.contribution - participant.contribution[idx], 
            group.minContribution, 
            group.maxContribution, 
            group.isRestricted,            
            participant
        );


        require(remaining == 0);


        if (!participant.exists) {
            participant.exists = true;   
            pool.participants.push(msg.sender);
        }        


        if(!participant.whitelist[idx]) {
            participant.whitelist[idx] = true;         
        }


        group.contribution = group.contribution - participant.contribution[idx] + contribution;
        group.remaining = group.remaining - participant.remaining[idx] + remaining;
        participant.contribution[idx] = contribution;
        participant.remaining[idx] = remaining;

        emit Contribution(
            msg.sender,
            idx,
            msg.value,
            contribution,
            group.contribution
        );        
    }


    function withdrawAmount(Pool storage pool, uint amount, uint idx)
        public
        onlyInState(pool, State.Open)
    {

        Participant storage participant = pool.participantToData[msg.sender];                        
        uint finalAmount;

        if(amount == 0) {

            finalAmount = participant.contribution[idx] + participant.remaining[idx];
        } else {


            require(amount >= participant.remaining[idx]);
            require(amount <= participant.contribution[idx] + participant.remaining[idx]);
            finalAmount = amount;
        }

        require(finalAmount > 0);


        Group storage group = pool.groups[idx];


        group.remaining -= participant.remaining[idx];        


        uint extra = finalAmount - participant.remaining[idx];        


        participant.remaining[idx] = 0;        

        if(extra > 0) {

            participant.contribution[idx] -= extra;
            group.contribution -= extra;            

            if(!participant.isAdmin) {

                require(participant.contribution[idx] >= group.minContribution);
            }
        }


        addressTransfer(msg.sender, finalAmount);

        emit Withdrawal(
            msg.sender,
            finalAmount,
            participant.contribution[idx],
            0,
            group.contribution,
            group.remaining,
            idx
        );                        
    } 


    function withdrawAll(Pool storage pool) public {


        if (pool.state == State.FullRefund || pool.state == State.Distribution) {
            withdrawRefundAndTokens(pool);
            return;
        }


        if(pool.state == State.Canceled || pool.state == State.Open) {
            withdrawAllContribution(pool);
            return;
        }            


        if (pool.state == State.PaidToPresale) {
            withdrawAllRemaining1(pool);
            return;
        } 


        revert();
    }


    function tokenFallback(Pool storage pool, address from, uint value, bytes data)
        public 
        onlyInStates2(pool, State.PaidToPresale, State.Distribution)
    {
        emit ERC223Fallback(
            msg.sender,
            from,
            value,
            data
        );
    }    


    function acceptRefundTransfer(Pool storage pool)
        public 
        onlyInStates2(pool, State.Distribution, State.FullRefund)  
    {
        require(msg.value > 0);
        require(msg.sender == pool.refundAddress);

        emit RefundReceived(
            msg.sender, 
            msg.value
        );
    }  


    function getPoolDetails1(Pool storage pool) 
        public view 
        returns (     
            uint libVersion,
            uint groupsCount,
            uint currentState,
            uint svcFeePerEther,
            bool feeToTokenMode,            
            address presaleAddress,
            address feeToTokenAddress,            
            address[] participants,
            address[] admins
        )
    {
        libVersion = version();
        currentState = uint(pool.state);
        groupsCount = pool.groups.length;
        svcFeePerEther = pool.svcFeePerEther;
        feeToTokenMode = pool.feeToTokenMode;        
        presaleAddress = pool.presaleAddress;
        feeToTokenAddress = pool.feeToTokenAddress;        
        participants = pool.participants;
        admins = pool.admins;
    }  


    function getPoolDetails2(Pool storage pool) 
        public view 
        returns (      
            uint refundBalance,
            address refundAddress,
            address[] tokenAddresses,
            uint[] tokenBalances
        )
    {                                                
        if(pool.state == State.Distribution || pool.state == State.FullRefund) {                 
            uint poolRemaining;
            (,poolRemaining,) = calcPoolSummary(pool);
            refundBalance = address(this).balance - poolRemaining;
            refundAddress = pool.refundAddress;

            tokenAddresses = pool.tokenAddresses;
            tokenBalances = new uint[](tokenAddresses.length);
            for(uint i = 0; i < tokenAddresses.length; i++) {
                tokenBalances[i] = IERC20Base(tokenAddresses[i]).balanceOf(address(this));
            }
        }
    }


    function getParticipantDetails(Pool storage pool, address addr)
        public view 
        returns (
            uint[] contribution,
            uint[] remaining,
            bool[] whitelist,
            bool isAdmin,
            bool exists
        ) 
    {
        Participant storage part = pool.participantToData[addr];
        isAdmin = part.isAdmin;                
        exists = part.exists;

        uint length = pool.groups.length;
        contribution = new uint[](length);
        remaining = new uint[](length);
        whitelist = new bool[](length);        

        for(uint i = 0; i < length; i++) {
            contribution[i] = part.contribution[i];
            remaining[i] = part.remaining[i];
            whitelist[i] = part.whitelist[i];
        }                      
    }        


    function getParticipantShares(Pool storage pool, address addr) public view returns (uint[] tokenShare, uint refundShare) {       
        if(pool.state == State.Distribution || pool.state == State.FullRefund) {
            uint netPoolContribution;
            uint netPartContribution;
            uint poolRemaining;
            uint poolCtorFee;   

            (netPoolContribution, netPartContribution, poolRemaining, poolCtorFee) = calcPoolSummary3(pool, addr);
            tokenShare = new uint[](pool.tokenAddresses.length);

            if(netPartContribution > 0) {
                refundShare = pool.refundQuota.calcShare(
                    addr, 
                    address(this).balance - poolRemaining,
                    [netPartContribution, netPoolContribution]
                );        
            }     

            if(pool.feeToTokenMode) {
                netPoolContribution += poolCtorFee;
                if(pool.feeToTokenAddress == addr) {
                    netPartContribution += poolCtorFee;
                }
            }  

            if(netPartContribution > 0) {
                for(uint i = 0; i < pool.tokenAddresses.length; i++) {
                    tokenShare[i] = pool.tokenQuota[pool.tokenAddresses[i]].calcShare(
                        addr,
                        IERC20Base(pool.tokenAddresses[i]).balanceOf(address(this)),
                        [netPartContribution, netPoolContribution]
                    );                
                }      
            }
        }  
    }    


    function getGroupDetails(Pool storage pool, uint idx)
        public view 
        returns (
            uint contributionBalance,
            uint remainingBalance,
            uint maxBalance,
            uint minContribution,                 
            uint maxContribution,
            uint ctorFeePerEther,
            bool isRestricted,
            bool exists
        ) 
    {
        Group storage group = pool.groups[idx];                                                
        contributionBalance = group.contribution;
        remainingBalance = group.remaining;
        maxBalance = group.maxBalance;
        minContribution = group.minContribution;
        maxContribution = group.maxContribution;
        ctorFeePerEther = group.ctorFeePerEther;
        isRestricted = group.isRestricted;
        exists = group.exists;
    }       


    function version() public pure returns (uint) {



        return 100100101;
    }    


    function withdrawAllContribution(Pool storage pool) private {        
        Participant storage participant = pool.participantToData[msg.sender];
        Group storage group;
        uint contribution;  
        uint remaining;
        uint amount;
        uint sum;


        uint length = pool.groups.length;
        for(uint idx = 0; idx < length; idx++) {


            contribution = participant.contribution[idx];
            remaining = participant.remaining[idx];
            sum = contribution + remaining;

            if(sum > 0) {
                amount += sum;
                group = pool.groups[idx];


                if(contribution > 0) {                    
                    group.contribution -= contribution;
                    participant.contribution[idx] = 0;
                }


                if(remaining > 0) {
                    group.remaining -= remaining;
                    participant.remaining[idx] = 0;
                }

                emit Withdrawal(
                    msg.sender,
                    idx,
                    sum,
                    0,
                    0,
                    group.contribution,
                    group.remaining                    
                );
            }
        }


        require(amount > 0);
        addressTransfer(
            msg.sender, 
            amount
        );
    }


    function withdrawAllRemaining1(Pool storage pool) private {
        Participant storage participant = pool.participantToData[msg.sender];        
        Group storage group;
        uint remaining;
        uint amount;


        uint length = pool.groups.length;
        for(uint idx = 0; idx < length; idx++) {            
            remaining = participant.remaining[idx];


            if(remaining > 0) {
                amount += remaining;
                group = pool.groups[idx];
                group.remaining -= remaining;        
                participant.remaining[idx] = 0;                                

                emit Withdrawal(
                    msg.sender,
                    idx,
                    remaining,
                    participant.contribution[idx],
                    0,
                    group.contribution,
                    group.remaining
                );
            }
        }


        require(amount > 0);
        addressTransfer(
            msg.sender, 
            amount
        );
    }


    function withdrawAllRemaining2(Pool storage pool) 
        private 
        returns
    (
        uint poolContribution,
        uint poolRemaining,
        uint poolCtorFee,
        uint partContribution,        
        uint partCtorFee
    ) 
    {
        Participant storage participant = pool.participantToData[msg.sender];
        Group storage group;
        uint sumRemaining; 
        uint remaining;     


        uint length = pool.groups.length;
        for(uint idx = 0; idx < length; idx++) {                        
            group = pool.groups[idx];


            poolRemaining += group.remaining;
            poolContribution += group.contribution;
            poolCtorFee += calcFee(group.contribution, group.ctorFeePerEther);


            remaining = participant.remaining[idx];
            partContribution += participant.contribution[idx];
            partCtorFee += calcFee(participant.contribution[idx], group.ctorFeePerEther);


            if(remaining > 0) {              
                sumRemaining += remaining;                            
                group.remaining -= remaining;
                participant.remaining[idx] = 0;  

                emit Withdrawal(
                    msg.sender,
                    idx,
                    remaining,
                    participant.contribution[idx],
                    0,
                    group.contribution,
                    group.remaining                    
                );
            }
        }


        if(sumRemaining > 0) {
            poolRemaining -= sumRemaining;
            addressTransfer(msg.sender, sumRemaining);
        }
    }    


    function withdrawRefundAndTokens(Pool storage pool) private {
        uint poolContribution;
        uint poolRemaining;
        uint poolCtorFee;
        uint partContribution;        
        uint partCtorFee;


        (poolContribution, 
            poolRemaining, 
            poolCtorFee, 
            partContribution,             
            partCtorFee
        ) = withdrawAllRemaining2(pool);


        uint netPoolContribution = poolContribution - poolCtorFee - calcFee(poolContribution, pool.svcFeePerEther);
        uint netPartContribution = partContribution - partCtorFee - calcFee(partContribution, pool.svcFeePerEther);

        if(netPartContribution > 0) {

            withdrawRefundShare(pool, poolRemaining, netPoolContribution, netPartContribution);
        }


        if(pool.feeToTokenMode) {
            netPoolContribution += poolCtorFee;
            if(pool.feeToTokenAddress == msg.sender) {
                netPartContribution += poolCtorFee;
            }
        }

        if(netPartContribution > 0) {

            withdrawTokens(pool, netPoolContribution, netPartContribution);
        }
    }


    function withdrawRefundShare(
        Pool storage pool, 
        uint poolRemaining,
        uint netPoolContribution, 
        uint netPartContribution
    )
        private 
    {
        if(address(this).balance > poolRemaining) {

            uint amount = pool.refundQuota.claimShare(
                msg.sender, 
                address(this).balance - poolRemaining,
                [netPartContribution, netPoolContribution]
            );

            if(amount > 0) {          

                addressTransfer(msg.sender, amount);
                emit RefundWithdrawal(
                    msg.sender,
                    address(this).balance,
                    poolRemaining,
                    amount
                );                
            }
        }
    }


    function withdrawTokens(
        Pool storage pool,        
        uint netPoolContribution,
        uint netPartContribution
    )
        private 
    {
        bool succeeded;
        uint tokenAmount;
        uint tokenBalance;
        address tokenAddress;
        IERC20Base tokenContract;
        QuotaLib.Storage storage quota;


        uint length = pool.tokenAddresses.length;
        for(uint i = 0; i < length; i++) {             

            tokenAddress = pool.tokenAddresses[i];            
            tokenContract = IERC20Base(tokenAddress); 

            tokenBalance = tokenContract.balanceOf(address(this));

            if(tokenBalance > 0) {    

                quota = pool.tokenQuota[tokenAddress];
                tokenAmount = quota.claimShare(
                    msg.sender,
                    tokenBalance, 
                    [netPartContribution, netPoolContribution]
                ); 

                if(tokenAmount > 0) {

                    succeeded = tokenContract.transfer(msg.sender, tokenAmount);
                    if (!succeeded) {                        
                        quota.undoClaimShare(msg.sender, tokenAmount);
                    }
                    emit TokenWithdrawal(
                        tokenAddress,
                        msg.sender,
                        tokenBalance,
                        tokenAmount,
                        succeeded
                    );
                }
            }
        } 
    }   


    function setGroupSettingsCore(
        Pool storage pool,        
        uint idx,
        uint maxBalance,
        uint minContribution,
        uint maxContribution,
        uint ctorFeePerEther,         
        bool isRestricted
    )
        private             
    {
        require(pool.groups.length > idx);
        Group storage group = pool.groups[idx];        

        if(!group.exists) {

            require(idx == 0 || pool.groups[idx - 1].exists);
            group.exists = true;
        }

        validateGroupSettings(
            maxBalance, 
            minContribution, 
            maxContribution
        );        

        if(group.maxBalance != maxBalance) {
            group.maxBalance = maxBalance;  
        }          

        if(group.minContribution != minContribution) {
            group.minContribution = minContribution;
        }

        if(group.maxContribution != maxContribution) {
            group.maxContribution = maxContribution;
        }

        if(group.ctorFeePerEther != ctorFeePerEther) {
            require(ctorFeePerEther <= (1 ether / 2));
            group.ctorFeePerEther = ctorFeePerEther;
        }

        if(group.isRestricted != isRestricted) {
            group.isRestricted = isRestricted;  
        }      

        emit GroupSettingsChanged(
            idx,
            maxBalance,
            minContribution,
            maxContribution,
            ctorFeePerEther,
            isRestricted
        );                             
    }    


    function modifyWhitelistCore(Pool storage pool, uint idx, address[] include, address[] exclude) private {
        require(include.length > 0 || exclude.length > 0);
        require(pool.groups.length > idx && pool.groups[idx].exists);


        Group storage group = pool.groups[idx];
        Participant storage participant;        
        uint i;


        if(!group.isRestricted) {
            group.isRestricted = true;
            emit WhitelistEnabled(idx);
        }    


        for(i = 0; i < exclude.length; i++) {
            participant = pool.participantToData[exclude[i]];            
            if(participant.whitelist[idx]) {
                participant.whitelist[idx] = false;
                emit ExcludedFromWhitelist(
                    exclude[i],
                    idx
                );                
            }
        }


        for(i = 0; i < include.length; i++) {
            participant = pool.participantToData[include[i]];  

            if(!participant.whitelist[idx]) { 

                if (!participant.exists) {                    
                    pool.participants.push(include[i]);
                    participant.exists = true;                                        
                }                        


                participant.whitelist[idx] = true;               
                emit IncludedInWhitelist(
                    include[i],
                    idx
                );
            }                
        }
    }        


    function sendFees(Pool storage pool) private {
        uint ctorFee;
        uint poolRemaining;
        uint poolContribution;

        (poolContribution, poolRemaining, ctorFee) = calcPoolSummary(pool);
        if(ctorFee > 0 && !pool.feeToTokenMode) {
            addressTransfer(msg.sender, ctorFee);            
        }


        uint svcFee = address(this).balance - poolRemaining;        
        if(svcFee > 0) {
            address creator = getPoolCreator(pool);
            pool.feeService.sendFee.value(svcFee)(creator);
        }

        emit FeesDistributed(
            ctorFee,
            svcFee
        );
    }   


    function groupRebalance(Pool storage pool, uint idx) private {
        Group storage group = pool.groups[idx];          
        uint maxBalance = group.maxBalance;
        uint minContribution = group.minContribution;    
        uint maxContribution = group.maxContribution;            
        bool isRestricted = group.isRestricted;        
        Participant storage participant;         
        uint groupContribution;
        uint groupRemaining;
        uint contribution;
        uint remaining;     
        uint x = idx;   



        for(uint i = 0; i < pool.participants.length; i++) {           
            participant = pool.participantToData[pool.participants[i]];                


            (contribution, remaining) = calcContribution(       
                x,
                0,
                maxBalance,
                groupContribution,
                minContribution,
                maxContribution,
                isRestricted,
                participant
            );        


            if(contribution != participant.contribution[x]) {
                participant.contribution[x] = contribution;
                participant.remaining[x] = remaining;
            }            

            groupContribution += contribution;            
            groupRemaining += remaining;

            emit ContributionAdjusted(
                pool.participants[i], 
                contribution,
                remaining,
                groupContribution,
                groupRemaining,
                x
            );
        }


        if(group.contribution != groupContribution) {
            group.contribution = groupContribution;             
            group.remaining = groupRemaining;           
        }  
    } 


    function changeState(Pool storage pool, State state) private {
        assert(pool.state != state);
        emit StateChanged(
            uint(pool.state), 
            uint(state)
        );
        pool.state = state;        
    }


    function addAdmin(Pool storage pool, address admin) private {
        require(admin != address(0));
        Participant storage participant = pool.participantToData[admin];
        require(!participant.exists && !participant.isAdmin);

        participant.exists = true;
        participant.isAdmin = true;
        pool.participants.push(admin);
        pool.admins.push(admin);             

        emit AdminAdded(admin);                  
    }  


    function addressTransfer(address destination, uint etherAmount) private {
        emit AddressTransfer(
            destination,
            etherAmount
        );
        destination.transfer(etherAmount);        
    }


    function addressCall(address destination, uint etherAmount, bytes data) private {
        addressCall(destination, 0, etherAmount, data);
    }


    function addressCall(address destination, uint gasAmount,  uint etherAmount, bytes data) private {
        emit AddressCall(
            destination,
            etherAmount,
            gasAmount > 0 ? gasAmount : gasleft(),
            data
        );
        require(
            destination.call
            .gas(gasAmount > 0 ? gasAmount : gasleft())
            .value(etherAmount)
            (data)            
        );
    }


    function calcContribution(
        uint idx,
        uint amount,
        uint maxBalance,
        uint currentBalance,
        uint minContribution, 
        uint maxContribution,
        bool isRestricted,        
        Participant storage participant
    )
        private view 
        returns(uint contribution, uint remaining)
    {

        uint totalAmount = participant.contribution[idx]
            + participant.remaining[idx]
            + amount;


        if(participant.isAdmin) {
            contribution = totalAmount;
            return;
        }                


        if(currentBalance >= maxBalance || (isRestricted && !participant.whitelist[idx])) {
            remaining = totalAmount;            
            return;
        }        

        contribution = Math.min(maxContribution, totalAmount);        
        contribution = Math.min(maxBalance - currentBalance, contribution);


        if(contribution < minContribution) {
            remaining = totalAmount;
            contribution = 0;
            return;
        }

        remaining = totalAmount - contribution;
    }


    function calcPoolSummary(Pool storage pool) 
        private view 
        returns
    (
        uint poolContribution, 
        uint poolRemaining, 
        uint ctorFee
    ) 
    {
        Group storage group;
        uint length = pool.groups.length;

        for(uint idx = 0; idx < length; idx++) {
            group = pool.groups[idx];
            if(!group.exists) {
                break;
            }

            poolRemaining += group.remaining;
            poolContribution += group.contribution;            
            ctorFee += calcFee(group.contribution, group.ctorFeePerEther);
        }
    }  


    function calcPoolSummary2(Pool storage pool, address addr) 
        private view
        returns
    (
        uint poolContribution,
        uint poolRemaining,
        uint poolCtorFee,
        uint partContribution,        
        uint partCtorFee
    ) 
    {
        Group storage group;
        Participant storage participant = pool.participantToData[addr];        
        uint length = pool.groups.length;

        for(uint idx = 0; idx < length; idx++) {            
            group = pool.groups[idx];
            if(!group.exists) {
                break;
            }

            poolRemaining += group.remaining;
            poolContribution += group.contribution;
            poolCtorFee += calcFee(group.contribution, group.ctorFeePerEther);

            partContribution += participant.contribution[idx];
            partCtorFee += calcFee(participant.contribution[idx], group.ctorFeePerEther);
        }
    }     


    function calcPoolSummary3(Pool storage pool, address addr) 
        private view
        returns
    (
        uint netPoolContribution,
        uint netPartContribution,
        uint poolRemaining,
        uint poolCtorFee
    ) 
    {
        uint poolContribution;        
        uint partContribution;
        uint partCtorFee;

        (poolContribution, 
            poolRemaining, 
            poolCtorFee, 
            partContribution,             
            partCtorFee
        ) = calcPoolSummary2(pool, addr);

        netPoolContribution = poolContribution - poolCtorFee - calcFee(poolContribution, pool.svcFeePerEther);
        netPartContribution = partContribution - partCtorFee - calcFee(partContribution, pool.svcFeePerEther);
    }          


    function validateGroupSettings(uint maxBalance, uint minContribution, uint maxContribution) private pure {
        require(
            minContribution > 0 &&
            minContribution <= maxContribution &&
            maxContribution <= maxBalance &&
            maxBalance <= 1e9 ether            
        );
    }


    function contains(address[] storage array, address addr) private view returns (bool) {
        for (uint i = 0; i < array.length; i++) {
            if (array[i] == addr) {
                return true;
            }
        }
        return false;
    } 


    function getPoolCreator(Pool storage pool) private view returns(address) {
        return pool.admins[0];
    }     


    function calcFee(uint etherAmount, uint feePerEther) private pure returns(uint fee) {
        fee = (etherAmount * feePerEther) / 1 ether;
    }    


    event StateChanged(
        uint fromState,
        uint toState
    ); 

    event AdminAdded(
        address adminAddress
    );

    event WhitelistEnabled(
        uint groupIndex
    );

    event PresaleAddressLocked(
        address presaleAddress
    );  

    event RefundAddressChanged(
        address refundAddress
    );    

    event FeesDistributed(
        uint creatorFeeAmount,
        uint serviceFeeAmount
    );

    event IncludedInWhitelist(
        address participantAddress,
        uint groupIndex
    );

    event ExcludedFromWhitelist(
        address participantAddress,
        uint groupIndex
    );  

    event FeeServiceAttached(
        address serviceAddress,
        uint feePerEther
    );    

    event TokenAddressConfirmed(
        address tokenAddress,
        uint tokenBalance
    ); 

    event RefundReceived(
        address senderAddress,
        uint etherAmount
    );    

    event Contribution(
        address participantAddress,
        uint groupIndex,
        uint etherAmount,
        uint participantContribution,
        uint groupContribution        
    );

    event Withdrawal(
        address participantAddress,
        uint groupIndex,
        uint etherAmount,
        uint participantContribution,
        uint participantRemaining,        
        uint groupContribution,
        uint groupRemaining
    );

    event TokenWithdrawal(
        address tokenAddress,
        address participantAddress,
        uint poolTokenBalance,
        uint tokenAmount,
        bool succeeded    
    );   

    event RefundWithdrawal(
        address participantAddress,
        uint contractBalance,
        uint poolRemaining,
        uint etherAmount
    );  

    event ContributionAdjusted(
        address participantAddress,
        uint participantContribution,
        uint participantRemaining,
        uint groupContribution,
        uint groupRemaining,
        uint groupIndex
    );

    event GroupSettingsChanged(
        uint index,
        uint maxBalance,                               
        uint minContribution,
        uint maxContribution,                        
        uint ctorFeePerEther,
        bool isRestricted                            
    );       

    event AddressTransfer(
        address destinationAddress,
