pragma solidity 0.6.6;

import "@openzeppelin/contracts-ethereum-package/contracts/math/SafeMath.sol";
import "@openzeppelin/contracts-ethereum-package/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts-ethereum-package/contracts/Initializable.sol";
import "@openzeppelin/contracts-ethereum-package/contracts/access/Ownable.sol";

import "../../interfaces/ISwapFactoryLike.sol";
import "../../interfaces/ISwapPairLike.sol";
import "../../interfaces/ISwapRouter02Like.sol";
import "../../interfaces/IStrategy.sol";
import "../../interfaces/IWorker03.sol";

import "../../../utils/SafeToken.sol";
import "../../../utils/AlpacaMath.sol";

contract SpookySwapStrategyAddBaseTokenOnly is OwnableUpgradeSafe, ReentrancyGuardUpgradeSafe, IStrategy {
  using SafeToken for address;
  using SafeMath for uint256;

  event LogSetWorkerOk(address[] indexed workers, bool isOk);

  ISwapFactoryLike public factory;
  ISwapRouter02Like public router;
  mapping(address => bool) public okWorkers;


  modifier onlyWhitelistedWorkers() {
    require(okWorkers[msg.sender], "bad worker");
    _;
  }



  function initialize(ISwapRouter02Like _router) external initializer {
    OwnableUpgradeSafe.__Ownable_init();
    ReentrancyGuardUpgradeSafe.__ReentrancyGuard_init();
    factory = ISwapFactoryLike(_router.factory());
    router = _router;
  }





  function execute(
    address, 
    uint256, 
    bytes calldata data
  ) external override onlyWhitelistedWorkers nonReentrant {

    uint256 minLPAmount = abi.decode(data, (uint256));
    IWorker03 worker = IWorker03(msg.sender);
    address baseToken = worker.baseToken();
    address farmingToken = worker.farmingToken();
    ISwapPairLike lpToken = worker.lpToken();

    baseToken.safeApprove(address(router), uint256(-1));
    farmingToken.safeApprove(address(router), uint256(-1));

    uint256 balance = baseToken.myBalance();
    (uint256 r0, uint256 r1, ) = lpToken.getReserves();
    uint256 rIn = lpToken.token0() == baseToken ? r0 : r1;






    uint256 aIn = AlpacaMath.sqrt(rIn.mul(balance.mul(3992000).add(rIn.mul(3992004)))).sub(rIn.mul(1998)) / 1996;

    address[] memory path = new address[](2);
    path[0] = baseToken;
    path[1] = farmingToken;
    router.swapExactTokensForTokens(aIn, 0, path, address(this), now);

    (, , uint256 moreLPAmount) = router.addLiquidity(
      baseToken,
      farmingToken,
      baseToken.myBalance(),
      farmingToken.myBalance(),
      0,
      0,
      address(this),
      now
    );
    require(moreLPAmount >= minLPAmount, "insufficient LP tokens received");
    address(lpToken).safeTransfer(msg.sender, lpToken.balanceOf(address(this)));

    baseToken.safeApprove(address(router), 0);
    farmingToken.safeApprove(address(router), 0);
  }

  function setWorkersOk(address[] calldata workers, bool isOk) external onlyOwner {
    for (uint256 idx = 0; idx < workers.length; idx++) {
      okWorkers[workers[idx]] = isOk;
    }
    emit LogSetWorkerOk(workers, isOk);
  }
}

pragma solidity 0.6.6;

import "@openzeppelin/contracts-ethereum-package/contracts/access/Ownable.sol";
import "@openzeppelin/contracts-ethereum-package/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts-ethereum-package/contracts/math/SafeMath.sol";
import "@openzeppelin/contracts-ethereum-package/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts-ethereum-package/contracts/Initializable.sol";

import "../../interfaces/ISwapFactoryLike.sol";
import "../../interfaces/ISwapPairLike.sol";
import "../../interfaces/ISwapRouter02Like.sol";
import "../../interfaces/IStrategy.sol";
import "../../interfaces/IWorker03.sol";
import "../../interfaces/ISpookyMasterChef.sol";
import "../../interfaces/IVault.sol";

import "../../../utils/SafeToken.sol";


contract SpookyWorker03 is OwnableUpgradeSafe, ReentrancyGuardUpgradeSafe, IWorker03 {

  using SafeToken for address;
  using SafeMath for uint256;


  event Reinvest(address indexed caller, uint256 reward, uint256 bounty);
  event AddShare(uint256 indexed id, uint256 share);
  event RemoveShare(uint256 indexed id, uint256 share);
  event Liquidate(uint256 indexed id, uint256 wad);
  event SetTreasuryConfig(address indexed caller, address indexed account, uint256 bountyBps);
  event BeneficialVaultTokenBuyback(address indexed caller, IVault indexed beneficialVault, uint256 indexed buyback);
  event SetStrategyOK(address indexed caller, address indexed strategy, bool indexed isOk);
  event SetReinvestorOK(address indexed caller, address indexed reinvestor, bool indexed isOk);
  event SetCriticalStrategy(address indexed caller, IStrategy indexed addStrat, IStrategy indexed liqStrat);
  event SetMaxReinvestBountyBps(address indexed caller, uint256 indexed maxReinvestBountyBps);
  event SetRewardPath(address indexed caller, address[] newRewardPath);
  event SetBeneficialVaultConfig(
    address indexed caller,
    uint256 indexed beneficialVaultBountyBps,
    IVault indexed beneficialVault,
    address[] rewardPath
  );
  event SetReinvestConfig(
    address indexed caller,
    uint256 reinvestBountyBps,
    uint256 reinvestThreshold,
    address[] reinvestPath
  );


  ISpookyMasterChef public spookyMasterChef;
  ISwapFactoryLike public factory;
  ISwapRouter02Like public router;
  ISwapPairLike public override lpToken;
  address public wNative;
  address public override baseToken;
  address public override farmingToken;
  address public boo;
  address public operator;
  uint256 public pid;



  mapping(uint256 => uint256) public shares;
  mapping(address => bool) public okStrats;
  uint256 public totalShare;
  IStrategy public addStrat;
  IStrategy public liqStrat;
  uint256 public reinvestBountyBps;
  uint256 public maxReinvestBountyBps;
  mapping(address => bool) public okReinvestors;
  uint256 public fee;
  uint256 public feeDenom;

  uint256 public reinvestThreshold;
  address[] public reinvestPath;
  address public treasuryAccount;
  uint256 public treasuryBountyBps;
  IVault public beneficialVault;
  uint256 public beneficialVaultBountyBps;
  address[] public rewardPath;
  uint256 public buybackAmount;

  function initialize(
    address _operator,
    address _baseToken,
    ISpookyMasterChef _spookyMasterChef,
    ISwapRouter02Like _router,
    uint256 _pid,
    IStrategy _addStrat,
    IStrategy _liqStrat,
    uint256 _reinvestBountyBps,
    address _treasuryAccount,
    address[] calldata _reinvestPath,
    uint256 _reinvestThreshold
  ) external initializer {

    OwnableUpgradeSafe.__Ownable_init();
    ReentrancyGuardUpgradeSafe.__ReentrancyGuard_init();


    operator = _operator;
    wNative = _router.WETH();
    spookyMasterChef = _spookyMasterChef;
    router = _router;
    factory = ISwapFactoryLike(_router.factory());


    baseToken = _baseToken;
    pid = _pid;
    (IERC20 _lpToken, , , ) = spookyMasterChef.poolInfo(_pid);
    lpToken = ISwapPairLike(address(_lpToken));
    address token0 = lpToken.token0();
    address token1 = lpToken.token1();
    farmingToken = token0 == baseToken ? token1 : token0;
    boo = address(spookyMasterChef.boo());


    addStrat = _addStrat;
    liqStrat = _liqStrat;
    okStrats[address(addStrat)] = true;
    okStrats[address(liqStrat)] = true;


    reinvestBountyBps = _reinvestBountyBps;
    reinvestThreshold = _reinvestThreshold;
    reinvestPath = _reinvestPath;
    treasuryAccount = _treasuryAccount;
    treasuryBountyBps = _reinvestBountyBps;
    maxReinvestBountyBps = 900;


    fee = 998;
    feeDenom = 1000;

    require(baseToken != boo, "baseToken must !boo");
    require(reinvestBountyBps <= maxReinvestBountyBps, "exceeded maxReinvestBountyBps");
    require(
      (farmingToken == lpToken.token0() || farmingToken == lpToken.token1()) &&
        (baseToken == lpToken.token0() || baseToken == lpToken.token1()),
      "bad baseToken or farmingToken"
    );
    require(reinvestPath.length >= 2, "_reinvestPath length must >= 2");
    require(reinvestPath[0] == boo && reinvestPath[reinvestPath.length - 1] == baseToken, "bad reinvest path");
  }


  modifier onlyEOA() {
    require(msg.sender == tx.origin, "not eoa");
    _;
  }


  modifier onlyOperator() {
    require(msg.sender == operator, "not operator");
    _;
  }


  modifier onlyReinvestor() {
    require(okReinvestors[msg.sender], "not reinvestor");
    _;
  }



  function shareToBalance(uint256 share) public view returns (uint256) {
    if (totalShare == 0) return share; 
    (uint256 totalBalance, ) = spookyMasterChef.userInfo(pid, address(this));
    return share.mul(totalBalance).div(totalShare);
  }



  function balanceToShare(uint256 balance) public view returns (uint256) {
    if (totalShare == 0) return balance; 
    (uint256 totalBalance, ) = spookyMasterChef.userInfo(pid, address(this));
    return balance.mul(totalShare).div(totalBalance);
  }


  function reinvest() external override onlyEOA onlyReinvestor nonReentrant {
    _reinvest(msg.sender, reinvestBountyBps, 0, 0);


    _buyback();
  }







  function _reinvest(
    address _treasuryAccount,
    uint256 _treasuryBountyBps,
    uint256 _callerBalance,
    uint256 _reinvestThreshold
  ) internal {

    spookyMasterChef.withdraw(pid, 0);
    uint256 reward = boo.balanceOf(address(this));
    if (reward <= _reinvestThreshold) return;


    boo.safeApprove(address(router), uint256(-1));
    address(lpToken).safeApprove(address(spookyMasterChef), uint256(-1));


    uint256 bounty = reward.mul(_treasuryBountyBps) / 10000;
    if (bounty > 0) {
      uint256 beneficialVaultBounty = bounty.mul(beneficialVaultBountyBps) / 10000;
      if (beneficialVaultBounty > 0) _rewardToBeneficialVault(beneficialVaultBounty, _callerBalance);
      boo.safeTransfer(_treasuryAccount, bounty.sub(beneficialVaultBounty));
    }


    router.swapExactTokensForTokens(reward.sub(bounty), 0, getReinvestPath(), address(this), now);


    baseToken.safeTransfer(address(addStrat), actualBaseTokenBalance().sub(_callerBalance));
    addStrat.execute(address(0), 0, abi.encode(0));


    spookyMasterChef.deposit(pid, lpToken.balanceOf(address(this)));


    boo.safeApprove(address(router), 0);
    address(lpToken).safeApprove(address(spookyMasterChef), 0);

    emit Reinvest(_treasuryAccount, reward, bounty);
  }






  function work(
    uint256 id,
    address user,
    uint256 debt,
    bytes calldata data
  ) external override onlyOperator nonReentrant {

    _reinvest(treasuryAccount, treasuryBountyBps, actualBaseTokenBalance(), reinvestThreshold);

    _removeShare(id);

    (address strat, bytes memory ext) = abi.decode(data, (address, bytes));
    require(okStrats[strat], "!approved strategy");
    address(lpToken).safeTransfer(strat, lpToken.balanceOf(address(this)));
    baseToken.safeTransfer(strat, actualBaseTokenBalance());
    IStrategy(strat).execute(user, debt, ext);

    _addShare(id);

    baseToken.safeTransfer(msg.sender, actualBaseTokenBalance());
  }





  function getMktSellAmount(
    uint256 aIn,
    uint256 rIn,
    uint256 rOut
  ) public view returns (uint256) {
    if (aIn == 0) return 0;
    require(rIn > 0 && rOut > 0, "bad reserve values");
    uint256 aInWithFee = aIn.mul(fee);
    uint256 numerator = aInWithFee.mul(rOut);
    uint256 denominator = rIn.mul(feeDenom).add(aInWithFee);
    return numerator / denominator;
  }



  function health(uint256 id) external view override returns (uint256) {

    uint256 lpBalance = shareToBalance(shares[id]);
    uint256 lpSupply = lpToken.totalSupply(); 

    (uint256 r0, uint256 r1, ) = lpToken.getReserves();
    (uint256 totalBaseToken, uint256 totalFarmingToken) = lpToken.token0() == baseToken ? (r0, r1) : (r1, r0);

    uint256 userBaseToken = lpBalance.mul(totalBaseToken).div(lpSupply);
    uint256 userFarmingToken = lpBalance.mul(totalFarmingToken).div(lpSupply);

    return
      getMktSellAmount(userFarmingToken, totalFarmingToken.sub(userFarmingToken), totalBaseToken.sub(userBaseToken))
        .add(userBaseToken);
  }



  function liquidate(uint256 id) external override onlyOperator nonReentrant {

    _removeShare(id);
    lpToken.transfer(address(liqStrat), lpToken.balanceOf(address(this)));
    liqStrat.execute(address(0), 0, abi.encode(0));

    uint256 liquidatedAmount = actualBaseTokenBalance();
    baseToken.safeTransfer(msg.sender, liquidatedAmount);
    emit Liquidate(id, liquidatedAmount);
  }




  function _rewardToBeneficialVault(uint256 _beneficialVaultBounty, uint256 _callerBalance) internal {

    address beneficialVaultToken = beneficialVault.token();

    uint256[] memory amounts = router.swapExactTokensForTokens(
      _beneficialVaultBounty,
      0,
      rewardPath,
      address(this),
      now
    );



    if (beneficialVaultToken != baseToken) {
      buybackAmount = 0;
      beneficialVaultToken.safeTransfer(address(beneficialVault), beneficialVaultToken.myBalance());
      emit BeneficialVaultTokenBuyback(msg.sender, beneficialVault, amounts[amounts.length - 1]);
    } else {
      buybackAmount = beneficialVaultToken.myBalance().sub(_callerBalance);
    }
  }



  function _buyback() internal {
    if (buybackAmount == 0) return;
    uint256 _buybackAmount = buybackAmount;
    buybackAmount = 0;
    beneficialVault.token().safeTransfer(address(beneficialVault), _buybackAmount);
    emit BeneficialVaultTokenBuyback(msg.sender, beneficialVault, _buybackAmount);
  }



  function actualBaseTokenBalance() internal view returns (uint256) {
    return baseToken.myBalance().sub(buybackAmount);
  }


  function _addShare(uint256 id) internal {
    uint256 balance = lpToken.balanceOf(address(this));
    if (balance > 0) {

      address(lpToken).safeApprove(address(spookyMasterChef), uint256(-1));

      uint256 share = balanceToShare(balance);
      require(share > 0, "no zero share");


      spookyMasterChef.deposit(pid, balance);

      shares[id] = shares[id].add(share);
      totalShare = totalShare.add(share);

      address(lpToken).safeApprove(address(spookyMasterChef), 0);
      emit AddShare(id, share);
    }
  }


  function _removeShare(uint256 id) internal {
    uint256 share = shares[id];
    if (share > 0) {
      uint256 balance = shareToBalance(share);
      spookyMasterChef.withdraw(pid, balance);
      totalShare = totalShare.sub(share);
      shares[id] = 0;
      emit RemoveShare(id, share);
    }
  }


  function getPath() external view override returns (address[] memory) {
    address[] memory path = new address[](2);
    path[0] = baseToken;
    path[1] = farmingToken;
    return path;
  }


  function getReversedPath() external view override returns (address[] memory) {
    address[] memory reversePath = new address[](2);
    reversePath[0] = farmingToken;
    reversePath[1] = baseToken;
    return reversePath;
  }


  function getRewardPath() external view override returns (address[] memory) {
    return rewardPath;
  }



  function getReinvestPath() public view returns (address[] memory) {
    if (reinvestPath.length != 0) return reinvestPath;
    address[] memory path;
    if (baseToken == wNative) {
      path = new address[](2);
      path[0] = address(boo);
      path[1] = address(wNative);
    } else {
      path = new address[](3);
      path[0] = address(boo);
      path[1] = address(wNative);
      path[2] = address(baseToken);
    }
    return path;
  }





  function setReinvestConfig(
    uint256 _reinvestBountyBps,
    uint256 _reinvestThreshold,
    address[] calldata _reinvestPath
  ) external onlyOwner {
    require(_reinvestBountyBps <= maxReinvestBountyBps, "exceeded maxReinvestBountyBps");
    require(_reinvestPath.length >= 2, "_reinvestPath length must >= 2");
    require(_reinvestPath[0] == boo && _reinvestPath[_reinvestPath.length - 1] == baseToken, "bad _reinvestPath");

    reinvestBountyBps = _reinvestBountyBps;
    reinvestThreshold = _reinvestThreshold;
    reinvestPath = _reinvestPath;

    emit SetReinvestConfig(msg.sender, _reinvestBountyBps, _reinvestThreshold, _reinvestPath);
  }



  function setMaxReinvestBountyBps(uint256 _maxReinvestBountyBps) external onlyOwner {
    require(_maxReinvestBountyBps >= reinvestBountyBps, "lower than reinvestBountyBps");
    require(_maxReinvestBountyBps <= 3000, "exceeded 30%");

    maxReinvestBountyBps = _maxReinvestBountyBps;

    emit SetMaxReinvestBountyBps(msg.sender, maxReinvestBountyBps);
  }




  function setStrategyOk(address[] calldata strats, bool isOk) external override onlyOwner {
    uint256 len = strats.length;
    for (uint256 idx = 0; idx < len; idx++) {
      okStrats[strats[idx]] = isOk;
      emit SetStrategyOK(msg.sender, strats[idx], isOk);
    }
  }




  function setReinvestorOk(address[] calldata reinvestors, bool isOk) external override onlyOwner {
    uint256 len = reinvestors.length;
    for (uint256 idx = 0; idx < len; idx++) {
      okReinvestors[reinvestors[idx]] = isOk;
      emit SetReinvestorOK(msg.sender, reinvestors[idx], isOk);
    }
  }



  function setRewardPath(address[] calldata _rewardPath) external onlyOwner {
    require(_rewardPath.length >= 2, "_rewardPath length must be >= 2");
    require(_rewardPath[0] == boo && _rewardPath[_rewardPath.length - 1] == beneficialVault.token(), "bad _rewardPath");

    rewardPath = _rewardPath;

    emit SetRewardPath(msg.sender, _rewardPath);
  }




  function setCriticalStrategies(IStrategy _addStrat, IStrategy _liqStrat) external onlyOwner {
    addStrat = _addStrat;
    liqStrat = _liqStrat;

    emit SetCriticalStrategy(msg.sender, addStrat, liqStrat);
  }




  function setTreasuryConfig(address _treasuryAccount, uint256 _treasuryBountyBps) external onlyOwner {
    require(_treasuryAccount != address(0), "bad _treasuryAccount");
    require(_treasuryBountyBps <= maxReinvestBountyBps, "exceeded maxReinvestBountyBps");

    treasuryAccount = _treasuryAccount;
    treasuryBountyBps = _treasuryBountyBps;

    emit SetTreasuryConfig(msg.sender, treasuryAccount, treasuryBountyBps);
  }





  function setBeneficialVaultConfig(
    uint256 _beneficialVaultBountyBps,
    IVault _beneficialVault,
    address[] calldata _rewardPath
  ) external onlyOwner {
    require(_beneficialVaultBountyBps <= 10000, "exceeds 100%");
    require(_rewardPath.length >= 2, "_rewardPath length must >= 2");
    require(
      _rewardPath[0] == boo && _rewardPath[_rewardPath.length - 1] == _beneficialVault.token(),
      "bad _rewardPath"
    );

    _buyback();

    beneficialVaultBountyBps = _beneficialVaultBountyBps;
    beneficialVault = _beneficialVault;
    rewardPath = _rewardPath;

    emit SetBeneficialVaultConfig(msg.sender, _beneficialVaultBountyBps, _beneficialVault, _rewardPath);
  }
}

pragma solidity ^0.6.0;

import {ReentrancyGuard} from "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import {Ownable} from "@openzeppelin/contracts/access/Ownable.sol";
import {Pausable} from "@openzeppelin/contracts/utils/Pausable.sol";
import {SafeERC20} from "@openzeppelin/contracts/token/ERC20/SafeERC20.sol";
import {SafeMath} from "@openzeppelin/contracts/math/SafeMath.sol";
import {Address} from "@openzeppelin/contracts/utils/Address.sol";
import {IERC20} from "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import {Initializable} from "@openzeppelin/contracts/proxy/Initializable.sol";

import "./Interfaces.sol";
import { ReentrancyGuardPausable } from "../ReentrancyGuardPausable.sol";
import "../UpgradeableOwnable.sol";


interface IVaultConfig {

  function getReservePoolBps() external view returns (uint256);
}

interface IAlpacaVault is IERC20 {

  function config() external view returns (address);
  function vaultDebtVal() external view returns (uint256);
  function lastAccrueTime() external view returns (uint256);
  function reservePool() external view returns (uint256);


  function totalToken() external view returns (uint256);


  function deposit(uint256 amountToken) external payable;


  function withdraw(uint256 share) external;


  function requestFunds(address targetedToken, uint amount) external;

  function pendingInterest(uint256 value) external view returns (uint256);

}

interface IFairLaunch {
  function poolLength() external view returns (uint256);

  function addPool(
    uint256 _allocPoint,
    address _stakeToken,
    bool _withUpdate
  ) external;

  function setPool(
    uint256 _pid,
    uint256 _allocPoint,
    bool _withUpdate
  ) external;

  function pendingAlpaca(uint256 _pid, address _user) external view returns (uint256);

  function updatePool(uint256 _pid) external;

  function deposit(address _for, uint256 _pid, uint256 _amount) external;

  function withdraw(address _for, uint256 _pid, uint256 _amount) external;

  function withdrawAll(address _for, uint256 _pid) external;

  function harvest(uint256 _pid) external;

  function userInfo(uint256 _pid, address user) external view returns (uint256, uint256, uint256, address);
}

contract StratAlpaca is UpgradeableOwnable, ReentrancyGuardPausable, ISimpleStrategy, Initializable {

    using SafeERC20 for IERC20;
    using Address for address;
    using SafeMath for uint256;
    using SafeERC20 for IAlpacaVault;

    bool public wantIsWBNB = false;
    IERC20 public wantToken = IERC20(0xe9e7CEA3DedcA5984780Bafc599bD69ADd087D56);
    address public uniRouterAddress = 0x05fF2B0DB69458A0750badebc4f9e13aDd608C7F;

    address public wbnbAddress =
        0xbb4CdB9CBd36B01bD1cBaEBF2De08d9173bc095c;

    IFairLaunch public fairLaunch = IFairLaunch(0xA625AB01B08ce023B2a342Dbb12a16f2C8489A8F);
    IERC20 public alpacaToken = IERC20(0x8F0528cE5eF7B51152A59745bEfDD91D97091d2F);
    IAlpacaVault public alpacaVault = IAlpacaVault(0x7C9e73d4C71dae564d41F78d56439bB4ba87592f);

    uint256 public lastHarvestBlock = 0;

    address[] public alpacaToWantPath;

    uint256 public poolId = 3;

    address public vault;

    mapping (address => bool) public keepers;

    event KeepersSet(address[] keepers, bool[] states);

    constructor() public {}


    function initialize(
        uint256 _poolId,
        address _fairLaunchAddress,
        address _alpacaToken,
        address _alpacaVault,
        address _wantAddress,
        address _wbnbAddress,
        address _uniRouterAddress,
        address _vault
    )
        external
        initializer
        onlyOwner
    {
        poolId = _poolId;
        fairLaunch = IFairLaunch(_fairLaunchAddress);
        alpacaToken = IERC20(_alpacaToken);
        alpacaVault = IAlpacaVault(_alpacaVault);

        wantToken = IERC20(_wantAddress);
        wbnbAddress = _wbnbAddress;

        if (_wantAddress == wbnbAddress) {
            wantIsWBNB = true;
            alpacaToWantPath = [_alpacaToken, wbnbAddress];
        } else {
            alpacaToWantPath = [_alpacaToken, wbnbAddress, _wantAddress];
        }

        uniRouterAddress = _uniRouterAddress;

        wantToken.safeApprove(_alpacaVault, uint256(-1));
        alpacaVault.safeApprove(_fairLaunchAddress, uint256(-1));
        alpacaToken.safeApprove(uniRouterAddress, uint256(-1));
        vault = _vault;
    }

    modifier onlyVault() {
        require (msg.sender == vault, "Must from vault");
        _;
    }

    modifier onlyVaultOrKeeper() {
        require (msg.sender == vault || keepers[msg.sender], "Must from vault/keeper");
        _;
    }

    function alpacaVaultTotalToken() public view returns (uint256) {
        uint256 reservePool = alpacaVault.reservePool();
        uint256 vaultDebtVal = alpacaVault.vaultDebtVal();
        if (now > alpacaVault.lastAccrueTime()) {
            uint256 interest = alpacaVault.pendingInterest(0);
            uint256 toReserve = interest.mul(IVaultConfig(alpacaVault.config()).getReservePoolBps()).div(10000);
            reservePool = reservePool.add(toReserve);
            vaultDebtVal = vaultDebtVal.add(interest);
        }
        return wantToken.balanceOf(address(alpacaVault)).add(vaultDebtVal).sub(reservePool);
    }

    function _ibDeposited() internal view returns (uint256) {
        (uint256 ibBal,,,) = fairLaunch.userInfo(poolId, address(this));
        return ibBal;
    }

    function totalBalance() external override view returns (uint256) {
        uint256 ibBal = _ibDeposited();
        return alpacaVaultTotalToken().mul(ibBal).div(alpacaVault.totalSupply());
    }

    function wantAmtToIbAmount(uint256 _wantAmt) public view returns (uint256) {
        return _wantAmt.mul(alpacaVault.totalSupply()).div(alpacaVaultTotalToken());
    }


    function deposit(uint256 _wantAmt)
        external
        override
        onlyVault
        nonReentrantAndUnpaused
    {
        IERC20(wantToken).safeTransferFrom(
            address(msg.sender),
            address(this),
            _wantAmt
        );

        alpacaVault.deposit(_wantAmt);
        fairLaunch.deposit(address(this), poolId, alpacaVault.balanceOf(address(this)));
    }

    function withdraw(uint256 _wantAmt)
        external
        override
        onlyVault
        nonReentrantAndUnpaused
    {
        uint256 ibAmt = wantAmtToIbAmount(_wantAmt);
        fairLaunch.withdraw(address(this), poolId, ibAmt);
        alpacaVault.withdraw(alpacaVault.balanceOf(address(this)));

        uint256 actualWantAmount = wantToken.balanceOf(address(this));
        wantToken.safeTransfer(
            address(msg.sender),
            actualWantAmount
        );
    }

    function _harvest(uint256 priceMin) internal {
        if (lastHarvestBlock == block.number) {
            return;
        }


        if (_ibDeposited() == 0) {
            return;
        }


        fairLaunch.harvest(poolId);

        uint256 earnedAlpacaBalance = alpacaToken.balanceOf(address(this));
        if (earnedAlpacaBalance == 0) {
            return;
        }

        if (alpacaToken != wantToken) {
            IPancakeRouter02(uniRouterAddress).swapExactTokensForTokens(
                earnedAlpacaBalance,
                earnedAlpacaBalance.mul(priceMin).div(1e18),
                alpacaToWantPath,
                address(this),
                now.add(600)
            );
        }

        alpacaVault.deposit(IERC20(wantToken).balanceOf(address(this)));
        fairLaunch.deposit(address(this), poolId, alpacaVault.balanceOf(address(this)));

        lastHarvestBlock = block.number;
    }

    function harvest(uint256 minPrice) external override onlyVaultOrKeeper nonReentrantAndUnpaused {
        _harvest(minPrice);
    }


    function pause(uint256 _flags) external onlyOwner {
        _pause();

        alpacaToken.safeApprove(uniRouterAddress, 0);
        wantToken.safeApprove(uniRouterAddress, 0);
    }


    function unpause(uint256 _flags) external onlyOwner {
        _unpause();

        alpacaToken.safeApprove(uniRouterAddress, uint256(-1));
        wantToken.safeApprove(uniRouterAddress, uint256(-1));
    }

    function setVault(address _vault) external onlyOwner {
        vault = _vault;
    }

    function setKeepers(address[] calldata _keepers, bool[] calldata _states) external onlyOwner {
        uint256 n = _keepers.length;
        for(uint256 i = 0; i < n; i++) {
            keepers[_keepers[i]] = _states[i];
        }
        emit KeepersSet(_keepers, _states);
    }

    receive() external payable {}
}

pragma solidity ^0.6.0;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC20/SafeERC20.sol";
import "@openzeppelin/contracts-upgradeable/access/OwnableUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/utils/PausableUpgradeable.sol";
import "@uniswap/v2-periphery/contracts/interfaces/IUniswapV2Router02.sol";
import "@uniswap/v2-core/contracts/interfaces/IUniswapV2Pair.sol";
import "../../interfaces/IMasterChef.sol";

contract StrategyWardenLP is OwnableUpgradeable, PausableUpgradeable {
    using SafeERC20 for IERC20;
    using SafeMath for uint256;

    uint constant public MAX_FEE = 1000;
    uint constant public CALL_FEE = 125; 
    uint constant public aleswapFee = MAX_FEE - CALL_FEE;    

    IUniswapV2Router02 private constant WARDEN_ROUTER = IUniswapV2Router02(0x71ac17934b60A4610dc58b715B61e45DCBdE4054);

    uint constant public WITHDRAWAL_FEE = 10;
    uint constant public WITHDRAWAL_MAX = 10000;

    address public keeper;
    address public vault;
    address public aleswapFeeRecipient;  


    address constant public wbnb = address(0xbb4CdB9CBd36B01bD1cBaEBF2De08d9173bc095c);
    address constant public wad = address(0x0fEAdcC3824E7F3c12f40E324a60c23cA51627fc);
    address public want;
    address public lpToken0;
    address public lpToken1;


    address constant public masterchef = address(0xde866dD77b6DF6772e320dC92BFF0eDDC626C674);
    uint256 public poolId;


    address[] public wadToWbnbRoute = [wad, wbnb];
    address[] public wadToLp0Route;
    address[] public wadToLp1Route;


    event StratHarvest(address indexed harvester);

    function initialize(
        address _want,
        uint256 _poolId,
        address _keeper,
        address _aleswapFeeRecipient        
    ) external initializer {
        __Ownable_init();
        __Pausable_init();

        want = _want;
        lpToken0 = IUniswapV2Pair(want).token0();
        lpToken1 = IUniswapV2Pair(want).token1();
        poolId = _poolId;
        keeper = _keeper;

        aleswapFeeRecipient = _aleswapFeeRecipient;

        if (lpToken0 == wbnb) {
            wadToLp0Route = [wad, wbnb];
        } else if (lpToken0 != wad) {
            wadToLp0Route = [wad, wbnb, lpToken0];
        }

        if (lpToken1 == wbnb) {
            wadToLp1Route = [wad, wbnb];
        } else if (lpToken1 != wad) {
            wadToLp1Route = [wad, wbnb, lpToken1];
        }

        _giveAllowances();
    }


    modifier onlyKeeper() {
        require(msg.sender == owner() || msg.sender == keeper, "!keeper");
        _;
    }    


    modifier onlyEOA() {
        require(msg.sender == tx.origin, "!EOA");
        _;
    }


    function deposit() public whenNotPaused {
        uint256 wantBal = IERC20(want).balanceOf(address(this));

        if (wantBal > 0) {
            IMasterChef(masterchef).deposit(poolId, wantBal);
        }
    }

    function withdraw(uint256 _amount) external returns (uint256) {
        require(msg.sender == vault, "!vault");

        uint256 wantBal = IERC20(want).balanceOf(address(this));

        if (wantBal < _amount) {
            IMasterChef(masterchef).withdraw(poolId, _amount.sub(wantBal));
            wantBal = IERC20(want).balanceOf(address(this));
        }

        if (wantBal > _amount) {
            wantBal = _amount;
        }

        if (tx.origin == owner() || paused()) {
            IERC20(want).safeTransfer(vault, wantBal);
            return wantBal;
        } else {
            uint256 withdrawalFee = wantBal.mul(WITHDRAWAL_FEE).div(WITHDRAWAL_MAX);
            IERC20(want).safeTransfer(vault, wantBal.sub(withdrawalFee));
            return wantBal.sub(withdrawalFee);
        }
    }



    function harvest() external whenNotPaused onlyEOA {
        IMasterChef(masterchef).deposit(poolId, 0);
        chargeFees();
        addLiquidity();
        deposit();

        emit StratHarvest(msg.sender);
    }


    function chargeFees() internal {
        uint256 toWbnb = IERC20(wad).balanceOf(address(this)).mul(40).div(1000); 
        WARDEN_ROUTER.swapExactTokensForTokens(toWbnb, 0, wadToWbnbRoute, address(this), now);

        uint256 wbnbBal = IERC20(wbnb).balanceOf(address(this));

        uint256 callFeeAmount = wbnbBal.mul(CALL_FEE).div(MAX_FEE); 
        IERC20(wbnb).safeTransfer(msg.sender, callFeeAmount);

        uint256 aleswapFeeAmount = wbnbBal.mul(aleswapFee).div(MAX_FEE); 
        IERC20(wbnb).safeTransfer(aleswapFeeRecipient, aleswapFeeAmount);

    }


    function addLiquidity() internal {
        uint256 wadHalf = IERC20(wad).balanceOf(address(this)).div(2);

        if (lpToken0 != wad) 
            WARDEN_ROUTER.swapExactTokensForTokens(wadHalf, 0, wadToLp0Route, address(this), now);

        if (lpToken1 != wad) 
            WARDEN_ROUTER.swapExactTokensForTokens(wadHalf, 0, wadToLp1Route, address(this), now);

        uint256 lp0Bal = IERC20(lpToken0).balanceOf(address(this));
        uint256 lp1Bal = IERC20(lpToken1).balanceOf(address(this));
        WARDEN_ROUTER.addLiquidity(lpToken0, lpToken1, lp0Bal, lp1Bal, 1, 1, address(this), now);
    }


    function balanceOf() public view returns (uint256) {
        return balanceOfWant().add(balanceOfPool());
    }


    function balanceOfWant() public view returns (uint256) {
        return IERC20(want).balanceOf(address(this));
    }


    function balanceOfPool() public view returns (uint256) {
        (uint256 _amount, ) = IMasterChef(masterchef).userInfo(poolId, address(this));
        return _amount;
    }


    function panic() public onlyKeeper {
        pause();
        IMasterChef(masterchef).emergencyWithdraw(poolId);
    }

    function pause() public onlyKeeper {
        _pause();

        _removeAllowances();
    }

    function unpause() external onlyKeeper {
        _unpause();

        _giveAllowances();

        deposit();
    }

    function setVault(address _vault) external onlyOwner {
        vault = _vault;
    }

    function setaleswapFeeRecipient(address _aleswapFeeRecipient) external onlyOwner {
        aleswapFeeRecipient = _aleswapFeeRecipient;
    }    

    function _giveAllowances() internal {
        IERC20(want).safeApprove(masterchef, uint256(-1));
        IERC20(wad).safeApprove(address(WARDEN_ROUTER), uint256(-1));

        IERC20(lpToken0).safeApprove(address(WARDEN_ROUTER), 0);
        IERC20(lpToken0).safeApprove(address(WARDEN_ROUTER), uint256(-1));

        IERC20(lpToken1).safeApprove(address(WARDEN_ROUTER), 0);
        IERC20(lpToken1).safeApprove(address(WARDEN_ROUTER), uint256(-1));
    }

    function _removeAllowances() internal {
        IERC20(want).safeApprove(masterchef, 0);
        IERC20(wad).safeApprove(address(WARDEN_ROUTER), 0);
        IERC20(lpToken0).safeApprove(address(WARDEN_ROUTER), 0);
        IERC20(lpToken1).safeApprove(address(WARDEN_ROUTER), 0);
    }
}

pragma solidity ^0.8.0;


abstract contract Context {
    function _msgSender() internal view virtual returns (address) {
        return msg.sender;
    }

    function _msgData() internal view virtual returns (bytes calldata) {
        return msg.data;
    }
}


abstract contract Ownable is Context {
    address private _owner;

    event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);


    constructor() {
        _setOwner(_msgSender());
    }


    function owner() public view virtual returns (address) {
        return _owner;
    }


    modifier onlyOwner() {
        require(owner() == _msgSender(), "Ownable: caller is not the owner");
        _;
    }


    function renounceOwnership() public virtual onlyOwner {
        _setOwner(address(0));
    }


    function transferOwnership(address newOwner) public virtual onlyOwner {
        require(newOwner != address(0), "Ownable: new owner is the zero address");
        _setOwner(newOwner);
    }

    function _setOwner(address newOwner) private {
        address oldOwner = _owner;
        _owner = newOwner;
        emit OwnershipTransferred(oldOwner, newOwner);
    }
}


abstract contract Withdrawable is Context, Ownable {


    address private _withdrawer;

    event WithdrawershipTransferred(address indexed previousWithdrawer, address indexed newWithdrawer);


    constructor () {
        address msgSender = _msgSender();
        _withdrawer = msgSender;
        emit WithdrawershipTransferred(address(0), msgSender);
    }


    function withdrawer() public view returns (address) {
        return _withdrawer;
    }


    modifier onlyWithdrawer() {
        require(_withdrawer == _msgSender(), "Withdrawable: caller is not the withdrawer");
        _;
    }


    function transferWithdrawership(address newWithdrawer) public virtual onlyOwner {
        require(newWithdrawer != address(0), "Withdrawable: new withdrawer is the zero address");

        emit WithdrawershipTransferred(_withdrawer, newWithdrawer);
        _withdrawer = newWithdrawer;
    }
}


abstract contract ReentrancyGuard {











    uint256 private constant _NOT_ENTERED = 1;
    uint256 private constant _ENTERED = 2;

    uint256 private _status;

    constructor() {
        _status = _NOT_ENTERED;
    }


    modifier nonReentrant() {

        require(_status != _ENTERED, "ReentrancyGuard: reentrant call");


        _status = _ENTERED;

        _;



        _status = _NOT_ENTERED;
    }
}


interface IERC20 {

    function totalSupply() external view returns (uint256);


    function balanceOf(address account) external view returns (uint256);


    function transfer(address recipient, uint256 amount) external returns (bool);


    function allowance(address owner, address spender) external view returns (uint256);


    function approve(address spender, uint256 amount) external returns (bool);


    function transferFrom(
        address sender,
        address recipient,
        uint256 amount
    ) external returns (bool);


    event Transfer(address indexed from, address indexed to, uint256 value);


    event Approval(address indexed owner, address indexed spender, uint256 value);
}


library Address {

    function isContract(address account) internal view returns (bool) {




        uint256 size;
        assembly {
            size := extcodesize(account)
        }
        return size > 0;
    }


    function sendValue(address payable recipient, uint256 amount) internal {
        require(address(this).balance >= amount, "Address: insufficient balance");

        (bool success, ) = recipient.call{value: amount}("");
        require(success, "Address: unable to send value, recipient may have reverted");
    }


    function functionCall(address target, bytes memory data) internal returns (bytes memory) {
        return functionCall(target, data, "Address: low-level call failed");
    }


    function functionCall(
        address target,
        bytes memory data,
        string memory errorMessage
    ) internal returns (bytes memory) {
        return functionCallWithValue(target, data, 0, errorMessage);
    }


    function functionCallWithValue(
        address target,
        bytes memory data,
        uint256 value
    ) internal returns (bytes memory) {
        return functionCallWithValue(target, data, value, "Address: low-level call with value failed");
    }


    function functionCallWithValue(
        address target,
        bytes memory data,
        uint256 value,
        string memory errorMessage
    ) internal returns (bytes memory) {
        require(address(this).balance >= value, "Address: insufficient balance for call");
        require(isContract(target), "Address: call to non-contract");

        (bool success, bytes memory returndata) = target.call{value: value}(data);
        return _verifyCallResult(success, returndata, errorMessage);
    }


    function functionStaticCall(address target, bytes memory data) internal view returns (bytes memory) {
        return functionStaticCall(target, data, "Address: low-level static call failed");
    }


    function functionStaticCall(
        address target,
        bytes memory data,
        string memory errorMessage
    ) internal view returns (bytes memory) {
        require(isContract(target), "Address: static call to non-contract");

        (bool success, bytes memory returndata) = target.staticcall(data);
        return _verifyCallResult(success, returndata, errorMessage);
    }


    function functionDelegateCall(address target, bytes memory data) internal returns (bytes memory) {
        return functionDelegateCall(target, data, "Address: low-level delegate call failed");
    }


    function functionDelegateCall(
        address target,
        bytes memory data,
        string memory errorMessage
    ) internal returns (bytes memory) {
        require(isContract(target), "Address: delegate call to non-contract");

        (bool success, bytes memory returndata) = target.delegatecall(data);
        return _verifyCallResult(success, returndata, errorMessage);
    }

    function _verifyCallResult(
        bool success,
        bytes memory returndata,
        string memory errorMessage
    ) private pure returns (bytes memory) {
        if (success) {
            return returndata;
        } else {

            if (returndata.length > 0) {


                assembly {
                    let returndata_size := mload(returndata)
                    revert(add(32, returndata), returndata_size)
                }
            } else {
                revert(errorMessage);
            }
        }
    }
}


library SafeERC20 {
    using Address for address;

    function safeTransfer(
        IERC20 token,
        address to,
        uint256 value
    ) internal {
        _callOptionalReturn(token, abi.encodeWithSelector(token.transfer.selector, to, value));
    }

    function safeTransferFrom(
        IERC20 token,
        address from,
        address to,
        uint256 value
    ) internal {
        _callOptionalReturn(token, abi.encodeWithSelector(token.transferFrom.selector, from, to, value));
    }


    function safeApprove(
        IERC20 token,
        address spender,
        uint256 value
    ) internal {



        require(
            (value == 0) || (token.allowance(address(this), spender) == 0),
            "SafeERC20: approve from non-zero to non-zero allowance"
        );
        _callOptionalReturn(token, abi.encodeWithSelector(token.approve.selector, spender, value));
    }

    function safeIncreaseAllowance(
        IERC20 token,
        address spender,
        uint256 value
    ) internal {
        uint256 newAllowance = token.allowance(address(this), spender) + value;
        _callOptionalReturn(token, abi.encodeWithSelector(token.approve.selector, spender, newAllowance));
    }

    function safeDecreaseAllowance(
        IERC20 token,
        address spender,
        uint256 value
    ) internal {
        unchecked {
            uint256 oldAllowance = token.allowance(address(this), spender);
            require(oldAllowance >= value, "SafeERC20: decreased allowance below zero");
            uint256 newAllowance = oldAllowance - value;
            _callOptionalReturn(token, abi.encodeWithSelector(token.approve.selector, spender, newAllowance));
        }
    }


    function _callOptionalReturn(IERC20 token, bytes memory data) private {




        bytes memory returndata = address(token).functionCall(data, "SafeERC20: low-level call failed");
        if (returndata.length > 0) {

            require(abi.decode(returndata, (bool)), "SafeERC20: ERC20 operation did not succeed");
        }
    }
}

interface IWUSD is IERC20 {
    function mint(address account, uint256 amount) external;
    function burn(address account, uint256 amount) external;
}

interface IWswapRouter {
    function swapExactTokensForTokensSupportingFeeOnTransferTokens(
        uint amountIn,
        uint amountOutMin,
        address[] calldata path,
        address to,
        uint deadline
    ) external;
}

contract WUSDMaster is Ownable, Withdrawable, ReentrancyGuard {
    using SafeERC20 for IERC20;

    IWUSD public immutable wusd;
    IERC20 public usdt;
    IERC20 public wex;
    IWswapRouter public immutable wswapRouter;
    address public treasury;
    address public strategist;

    address[] public swapPath;
    address[] public swapPathReverse;

    uint public wexPermille = 100;
    uint public treasuryPermille = 5;
    uint public feePermille = 2;

    uint256 public maxStakeAmount;

    mapping(address => uint256) public wusdClaimAmount;
    mapping(address => uint256) public wusdClaimBlock;
    mapping(address => uint256) public usdtClaimAmount;
    mapping(address => uint256) public usdtClaimBlock;

    event Stake(address indexed user, uint256 amount);
    event WusdClaim(address indexed user, uint256 amount);
    event Redeem(address indexed user, uint256 amount);
    event UsdtClaim(address indexed user, uint256 amount);
    event UsdtWithdrawn(uint256 amount);
    event WexWithdrawn(uint256 amount);
    event SwapPathChanged(address[] swapPath);
    event WexPermilleChanged(uint256 wexPermille);
    event TreasuryPermilleChanged(uint256 treasuryPermille);
    event FeePermilleChanged(uint256 feePermille);
    event TreasuryAddressChanged(address treasury);
    event StrategistAddressChanged(address strategist);
    event MaxStakeAmountChanged(uint256 maxStakeAmount);

    constructor(IWUSD _wusd, IERC20 _usdt, IERC20 _wex, IWswapRouter _wswapRouter, address _treasury, uint256 _maxStakeAmount) {
        require(
            address(_wusd) != address(0) &&
            address(_usdt) != address(0) &&
            address(_wex) != address(0) &&
            address(_wswapRouter) != address(0) &&
            _treasury != address(0),
            "zero address in constructor"
        );
        wusd = _wusd;
        usdt = _usdt;
        wex = _wex;
        wswapRouter = _wswapRouter;
        treasury = _treasury;
        swapPath = [address(usdt), address(wex)];
        swapPathReverse = [address(wex), address(usdt)];
        maxStakeAmount = _maxStakeAmount;
    }

    function setSwapPath(address[] calldata _swapPath) external onlyOwner {
        swapPath = _swapPath;

        emit SwapPathChanged(swapPath);
    }

    function setWexPermille(uint _wexPermille) external onlyOwner {
        require(_wexPermille <= 500, 'wexPermille too high!');
        wexPermille = _wexPermille;

        emit WexPermilleChanged(wexPermille);
    }

    function setTreasuryPermille(uint _treasuryPermille) external onlyOwner {
        require(_treasuryPermille <= 50, 'treasuryPermille too high!');
        treasuryPermille = _treasuryPermille;

        emit TreasuryPermilleChanged(treasuryPermille);
    }

    function setFeePermille(uint _feePermille) external onlyOwner {
        require(_feePermille <= 20, 'feePermille too high!');
        feePermille = _feePermille;

        emit FeePermilleChanged(feePermille);
    }

    function setTreasuryAddress(address _treasury) external onlyOwner {
        treasury = _treasury;

        emit TreasuryAddressChanged(treasury);
    }

    function setStrategistAddress(address _strategist) external onlyOwner {
        strategist = _strategist;

        emit StrategistAddressChanged(strategist);
    }

    function setMaxStakeAmount(uint256 _maxStakeAmount) external onlyOwner {
        maxStakeAmount = _maxStakeAmount;

        emit MaxStakeAmountChanged(maxStakeAmount);
    }

    function stake(uint256 amount) external nonReentrant {
        require(amount > 0, 'amount cant be zero');
        require(wusdClaimAmount[msg.sender] == 0, 'you have to claim first');
        require(amount <= maxStakeAmount, 'amount too high');

        usdt.safeTransferFrom(msg.sender, address(this), amount);
        if(feePermille > 0) {
            uint256 feeAmount = amount * feePermille / 1000;
            usdt.safeTransfer(treasury, feeAmount);
            amount = amount - feeAmount;
        }
        uint256 wexAmount = amount * wexPermille / 1000;
        usdt.approve(address(wswapRouter), wexAmount);
        wswapRouter.swapExactTokensForTokensSupportingFeeOnTransferTokens(
            wexAmount,
            0,
            swapPath,
            address(this),
            block.timestamp
        );

        wusdClaimAmount[msg.sender] = amount;
        wusdClaimBlock[msg.sender] = block.number;

        emit Stake(msg.sender, amount);
    }

    function claimWusd() external nonReentrant {
        require(wusdClaimAmount[msg.sender] > 0, 'there is nothing to claim');
        require(wusdClaimBlock[msg.sender] < block.number, 'you cant claim yet');

        uint256 amount = wusdClaimAmount[msg.sender];
        wusdClaimAmount[msg.sender] = 0;
        wusd.mint(msg.sender, amount);

        emit WusdClaim(msg.sender, amount);
    }

    function redeem(uint256 amount) external nonReentrant {
        require(amount > 0, 'amount cant be zero');
        require(usdtClaimAmount[msg.sender] == 0, 'you have to claim first');

        wusd.burn(msg.sender, amount);
        usdtClaimAmount[msg.sender] = amount;
        usdtClaimBlock[msg.sender] = block.number;

        emit Redeem(msg.sender, amount);
    }

    function claimUsdt() external nonReentrant {
        require(usdtClaimAmount[msg.sender] > 0, 'there is nothing to claim');
        require(usdtClaimBlock[msg.sender] < block.number, 'you cant claim yet');

        uint256 amount = usdtClaimAmount[msg.sender];
        usdtClaimAmount[msg.sender] = 0;

        uint256 usdtTransferAmount = amount * (1000 - wexPermille - treasuryPermille) / 1000;
        uint256 usdtTreasuryAmount = amount * treasuryPermille / 1000;
        uint256 wexTransferAmount = wex.balanceOf(address(this)) * amount / (wusd.totalSupply() + amount);
        usdt.safeTransfer(treasury, usdtTreasuryAmount);
        usdt.safeTransfer(msg.sender, usdtTransferAmount);
        wex.approve(address(wswapRouter), wexTransferAmount);
        wswapRouter.swapExactTokensForTokensSupportingFeeOnTransferTokens(
            wexTransferAmount,
            0,
            swapPathReverse,
            msg.sender,
            block.timestamp
        );

        emit UsdtClaim(msg.sender, amount);
    }

    function withdrawUsdt(uint256 amount) external onlyOwner {
        require(strategist != address(0), 'strategist not set');
        usdt.safeTransfer(strategist, amount);

        emit UsdtWithdrawn(amount);
    }

    function withdrawWex(uint256 amount) external onlyWithdrawer {
        wex.safeTransfer(msg.sender, amount);

        emit WexWithdrawn(amount);
    }
}

