import '../interfaces/ITenBankHall.sol';
import "../utils/TenMath.sol";

contract StrategyUtils is Ownable {
    using SafeMath for uint256;
    using SafeERC20 for IERC20;

    IStrategyConfig public sconfig;
    address public strategy;

    IMdexFactory constant factory = IMdexFactory(0xb0b670fc1F7724119963018DB0BfA86aDb22d941);
    IMdexRouter public constant router = IMdexRouter(0xED7d5F38C79115ca12fe6C0041abb22F0A06C300);

    constructor(address _sconfig) public {
        sconfig = IStrategyConfig(_sconfig);
        strategy = msg.sender;
    }

    function setSConfig(address _sconfig) external onlyOwner {
        sconfig = IStrategyConfig(_sconfig);
    }


    function makeDepositFee(uint256 _pid) external onlyOwner {
        if(address(sconfig) == address(0)) {
            return;
        }
        address[] memory collateralToken = IStrategyLink(strategy).getPoolCollateralToken(_pid);
        (address gather, uint256 feerate) = sconfig.getDepositFee(strategy, _pid);
        makeFeeTransfer(collateralToken[0], feerate, 1e9, gather);
        makeFeeTransfer(collateralToken[1], feerate, 1e9, gather);
    }

    function makeFeeTransfer(address _token, uint256 _feerate, uint256 _balancerate, address _gather) internal { 
        if(_token == address(0) || _feerate == 0 || _gather == address(0)) {
            return ;
        }
        uint256 feeValue = IERC20(_token).balanceOf(strategy).mul(_balancerate).div(1e9).mul(_feerate).div(1e9);
        if(feeValue > 0) {
            IERC20(_token).safeTransferFrom(strategy, _gather, feeValue);
        }
    }

    function makeFeeTransferByValue(address _token, uint256 _feeValue, address _gather) internal { 
        if(_token == address(0) || _feeValue == 0 || _gather == address(0)) {
            return ;
        }
        if(_feeValue > 0) {
            IERC20(_token).safeTransferFrom(strategy, _gather, _feeValue);
        }
    }

    function makeWithdrawRewardFee(uint256 _pid, uint256 _borrowRate, uint256 _rewardsRate) external onlyOwner {
        if(address(sconfig) == address(0)) {
            return;
        }
        address[] memory collateralToken = IStrategyLink(strategy).getPoolCollateralToken(_pid);


        (address gather, uint256 feerate) = sconfig.getWithdrawFee(strategy, _pid);
        uint256 rewardsByBorrowRate = _rewardsRate.mul(_borrowRate).div(1e9);
        if(rewardsByBorrowRate > 0) {
            makeFeeTransfer(collateralToken[0], feerate, rewardsByBorrowRate, gather);
            makeFeeTransfer(collateralToken[1], feerate, rewardsByBorrowRate, gather);
        }
    }

    function makeRefundFee(uint256 _pid, uint256 _newRewardBase) external onlyOwner {
        if(address(sconfig) == address(0)) {
            return;
        }
        address baseToken = IStrategyLink(strategy).getBaseToken(_pid);


        (address gather, uint256 feerate) = sconfig.getRefundFee(strategy, _pid);
        uint256 feeValue = _newRewardBase.mul(feerate).div(1e9);
        makeFeeTransferByValue(baseToken, feeValue, gather);
    }

    function makeLiquidationFee(uint256 _pid, address _baseToken, uint256 _borrowAmount) external onlyOwner {
        if(address(sconfig) == address(0)) {
            return ;
        }

        _borrowAmount;


        (address gather, uint256 feerate) = sconfig.getLiquidationFee(strategy, _pid);
        makeFeeTransfer(_baseToken, feerate, 1e9, gather);
    }


    function checkAddPoolLimit(uint256 _pid, address _baseToken, address _lpTokenInPools) 
            external view returns (bool bok) {

        address[] memory collateralToken = IStrategyLink(strategy).getPoolCollateralToken(_pid);
        address lpToken = factory.getPair(collateralToken[0], collateralToken[1]);

        bok = true;
        if(lpToken == address(0)) {
            bok = false;
        }
        if(lpToken != _lpTokenInPools) {
            bok = false;
        }
        if(collateralToken[1] != _baseToken) {
            bok = false;
        }
    }

    function checkDepositLimit(uint256 _pid, address _account, uint256 _lpAmount) 
            external view returns (bool bok) {
        _account;
        require(address(sconfig) != address(0), 'not config deposit limit');
        uint256 farmLimit = sconfig.getFarmPoolFactor(strategy, _pid);
        if(farmLimit <= 0) {
            return true;
        }
        (,,,,, uint256 totalLPRefund) = IStrategyLink(strategy).getPoolInfo(_pid);
        bok = totalLPRefund.add(_lpAmount) <= farmLimit;
    }

    function checkSlippageLimit(uint256 _pid, uint256 _desirePrice, uint256 _slippage) 
            external view returns (bool bok) {
        if(_slippage <= 0) {
            return true;
        }
        if(_slippage >= 1e9) {
            return false;
        }
        address[] memory collateralToken = IStrategyLink(strategy).getPoolCollateralToken(_pid);
        address pairs = factory.getPair(collateralToken[0], collateralToken[1]);
        (uint256 a, uint256 b,) = IMdexPair(pairs).getReserves();
        bok = (a.mul(1e18).div(b) < _desirePrice.mul(uint256(1e9).add(_slippage)).div(1e9)) &&
                (a.mul(1e18).div(b) > _desirePrice.mul(uint256(1e9).sub(_slippage)).div(1e9));
    }

    function checkBorrowLimit(uint256 _pid, address _account, address _borrowFrom, uint256 _borrowAmount) 
        public view returns (bool bok) {

        if(_borrowFrom == address(0) || _borrowAmount <= 0) {
            return true;
        }

        address baseToken = IStrategyLink(strategy).getBaseToken(_pid);
        uint256 holdAmount = checkBorrowGetHoldAmount(strategy, _pid, baseToken);

        uint256 totalAmount = IStrategyLink(strategy).getDepositAmount(_pid, _account);
        uint256 borrowAmount = IStrategyLink(strategy).getBorrowAmount(_pid, _account);
        totalAmount = totalAmount.add(holdAmount);

        uint256 borrowFactor = sconfig.getBorrowFactor(strategy, _pid);
        bok = borrowAmount.add(_borrowAmount) <= totalAmount.mul(borrowFactor).div(1e9);
    }

    function checkBorrowGetHoldAmount(address _strategy, uint256 _pid, address baseToken) 
        internal view returns (uint256 holdAmount) {

        address[] memory collateralToken = IStrategyLink(_strategy).getPoolCollateralToken(_pid);
        address token0 = collateralToken[0];
        address token1 = collateralToken[1];
        uint256 amount0 = IERC20(token0).balanceOf(_strategy);
        uint256 amount1 = IERC20(token1).balanceOf(_strategy);
        if(amount0 > 0) {
            holdAmount = holdAmount.add(getAmountIn(token0, amount0, baseToken));
        }
        if(amount1 > 0) {
            holdAmount = holdAmount.add(getAmountIn(token1, amount1, baseToken));
        }
    } 

    function checkLiquidationLimit(uint256 _pid, address _account, uint256 _borrowRate)
            external view returns (bool bok) {
        _account;
        require(address(sconfig) != address(0), 'not config liguidate');

        uint256 liquRate = sconfig.getLiquidationFactor(strategy, _pid);
        bok = (_borrowRate > liquRate);
    }

    function makeRepay(uint256 _pid, address _borrowFrom, address _account, uint256 _rate, bool _fast)
            external onlyOwner {
        if(_borrowFrom == address(0)) {
            return ;
        }
        uint256 bid = ISafeBox(_borrowFrom).getBorrowId(msg.sender, _pid, _account);
        if( bid <= 0) {
            return ;
        }

        ISafeBox(_borrowFrom).update();

        address[] memory collateralToken = IStrategyLink(strategy).getPoolCollateralToken(_pid);
        uint256 borrowAmount = IStrategyLink(strategy).getBorrowAmount(_pid, _account);
        uint256 repayAmount = borrowAmount.mul(_rate).div(1e9);
        if(repayAmount <= 0) {
            return ;
        }

        address token0 = collateralToken[0];
        address token1 = collateralToken[1];
        address baseToken = IStrategyLink(strategy).getBaseToken(_pid);
        uint256 baseTokenAmount = IERC20(baseToken).balanceOf(strategy);
        if( baseTokenAmount < repayAmount ) {

            uint256 amount0 = 0;
            if(_fast) {
                amount0 = getAmountOut(token0, token1, repayAmount.sub(baseTokenAmount));
            } else {
                amount0 = IERC20(token0).balanceOf(strategy);
            }
            if(amount0 > 0) {
                IERC20(token0).safeTransferFrom(address(strategy), address(this), amount0);
                getTokenInTo(address(this), token0, amount0, baseToken);
            }
            uint256 amount1 = IERC20(token1).balanceOf(strategy);
            IERC20(token1).safeTransferFrom(address(strategy), address(this), amount1);
        } else {
            IERC20(baseToken).safeTransferFrom(address(strategy), address(this), repayAmount);
        }
        IERC20(baseToken).safeTransfer(address(_borrowFrom), repayAmount);
        ISafeBox(_borrowFrom).repay(bid, repayAmount);
        uint256 free = IERC20(baseToken).balanceOf(address(this));
        if(free > 0) {
            IERC20(baseToken).safeTransfer(address(strategy), free);
        }
    }

    function getBorrowAmount(uint256 _pid, address _account) external view returns (uint256 value) {
        (address borrowFrom,uint256 bid) = IStrategyLink(strategy).getBorrowInfo(_pid, _account);
        if(borrowFrom != address(0) && bid != 0) {
            value = value.add(ISafeBox(borrowFrom).pendingBorrowAmount(bid));
            value = value.add(ISafeBox(borrowFrom).pendingBorrowRewards(bid));
        } else {
            value = 0;
        }
    }


    function transferFromAllToken(address _from, address _to, address _token0, address _token1)
        public onlyOwner {

        transferFromToken(_from, _to, _token0);
        transferFromToken(_from, _to, _token1);
    }

    function transferFromToken(address _from, address _to, address _token) public onlyOwner {
        uint256 amount = IERC20(_token).balanceOf(_from);
        if(amount <= 0) { 
            return ;
        }
        if(_from == address(this)) {
            IERC20(_token).safeTransfer(_to, amount);
        } else {
            IERC20(_token).safeTransferFrom(_from, _to, amount);
        }
    }





    function optimalDepositAmount(
        address lpToken,
        uint amtA,
        uint amtB
    ) public view returns (uint swapAmt, bool isReversed) {
        uint256 resA;
        uint256 resB;
        (resA, resB, ) = IMdexPair(lpToken).getReserves();
        if (amtA.mul(resB) >= amtB.mul(resA)) {
            swapAmt = _optimalDepositA(amtA, amtB, resA, resB);
            isReversed = false;
        } else {
            swapAmt = _optimalDepositA(amtB, amtA, resB, resA);
            isReversed = true;
        }
    }







    function _optimalDepositA(
        uint amtA,
        uint amtB,
        uint resA,
        uint resB
    ) internal pure returns (uint) {
        require(amtA.mul(resB) >= amtB.mul(resA), 'Reversed');
        uint a = 997;
        uint b = uint(1997).mul(resA);
        uint _c = (amtA.mul(resB)).sub(amtB.mul(resA));
        uint c = _c.mul(1000).div(amtB.add(resB)).mul(resA);
        uint d = a.mul(c).mul(4);
        uint e = TenMath.sqrt(b.mul(b).add(d));
        uint numerator = e.sub(b);
        uint denominator = a.mul(2);
        return numerator.div(denominator);
    }

    function getLPToken2TokenAmount(address _lpToken, address _baseToken, uint256 _lpTokenAmount)
            public view returns (uint256 amount) {
        (uint256 a, uint256 b, ) = IMdexPair(_lpToken).getReserves();
        address token0 = IMdexPair(_lpToken).token0();
        address token1 = IMdexPair(_lpToken).token1();
        if(token0 == _baseToken) {
            amount = _lpTokenAmount.mul(a).div(ERC20(_lpToken).totalSupply()).mul(2);
        }else if(token1 == _baseToken) {
            amount = _lpTokenAmount.mul(b).div(ERC20(_lpToken).totalSupply()).mul(2);
        }
        else{
            require(false, 'unsupport baseToken not in pairs');
        }
    }

    function getAmountOut(address _tokenIn, address _tokenOut, uint256 _amountOut)
            public virtual view returns (uint256) {
        if(_tokenIn == _tokenOut) {
            return _amountOut;
        }
        address[] memory path = new address[](2);
        path[0] = _tokenIn;
        path[1] = _tokenOut;

        uint256[] memory result = router.getAmountsIn(_amountOut, path);
        if(result.length == 0) {
            return 0;
        }
        return result[0];
    }

    function getAmountIn(address _tokenIn, uint256 _amountIn, address _tokenOut)
            public virtual view returns (uint256) {
        if(_tokenIn == _tokenOut) {
            return _amountIn;
        }
        address[] memory path = new address[](2);
        path[0] = _tokenIn;
        path[1] = _tokenOut;
        uint256[] memory result = router.getAmountsOut(_amountIn, path);
        if(result.length == 0) {
            return 0;
        }
        return result[result.length-1];
    }

    function getTokenOut(address _tokenIn, address _tokenOut, uint256 _amountOut) 
            public virtual onlyOwner returns (uint256 value) {
        uint256 amountIn = getAmountOut(_tokenIn, _tokenOut, _amountOut);
        IERC20(_tokenIn).safeTransferFrom(msg.sender, address(this), amountIn);
        value = getTokenInTo(msg.sender, _tokenIn, amountIn, _tokenOut);
        transferFromAllToken(address(this), msg.sender, _tokenIn, _tokenOut);
    }

    function getTokenIn(address _tokenIn, uint256 _amountIn, address _tokenOut) 
            public virtual onlyOwner returns (uint256 value) {
        IERC20(_tokenIn).safeTransferFrom(msg.sender, address(this), _amountIn);
        value = getTokenInTo(msg.sender, _tokenIn, _amountIn, _tokenOut);
        transferFromAllToken(address(this), msg.sender, _tokenIn, _tokenOut);
    }

    function getTokenInTo(address _toAddress, address _tokenIn, uint256 _amountIn, address _tokenOut) 
            internal virtual returns (uint256 value) {
        if(_tokenIn == _tokenOut) {
            value = _amountIn;
            return value;
        }
        address[] memory path = new address[](2);
        path[0] = _tokenIn;
        path[1] = _tokenOut;
        uint256 amountOutMin = 0;
        IERC20(_tokenIn).approve(address(router), uint256(-1));
        require(IERC20(_tokenIn).balanceOf(address(this)) >= _amountIn, 'getTokenInTo not amount in');

        uint256[] memory result = router.swapExactTokensForTokens(_amountIn, amountOutMin, path, _toAddress, block.timestamp.add(60));
        if(result.length == 0) {
            value = 0;
        } else {
            value = result[result.length-1];
        }
    }
}

pragma solidity 0.6.12;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/SafeERC20.sol";
import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/math/SafeMath.sol";

import "../../interfaces/IMdexRouter.sol";
import "../interfaces/IBuyback.sol";
import "./TenMath.sol";

contract BuybackBooToken is IBuyback {
    using SafeMath for uint256;
    using SafeERC20 for IERC20;

    IMdexRouter constant router = IMdexRouter(0xED7d5F38C79115ca12fe6C0041abb22F0A06C300);
    address public lockedAddr = address(0xfe5392013a4bA722CAf16FD116baaba8604Bb275);
    address public USDT = address(0xa71EdC38d189767582C38A3145b5873052c3e47a);
    address public booToken;

    mapping(address => uint256) public burnSource;
    mapping(address => uint256) public burnAmount;

    constructor(address _booToken) public {
        booToken = _booToken;
    }

    function setLockedAddr(address _lockedAddr) external {
        require(msg.sender == lockedAddr, 'prev one');
        lockedAddr = _lockedAddr;
    }

    function buyback(address _token, uint256 _value) external override returns (uint256 value) {
        uint256 decimals = uint256(ERC20(_token).decimals());
        if(_value < (10**decimals.div(4))) {
            return 0;
        }

        if(booToken == address(0)) {
            return 0;
        }

        address[] memory path;
        if (USDT != _token) {
            path = new address[](3);
            path[0] = _token;
            path[1] = USDT;
            path[2] = booToken;
        } else {
            path = new address[](2);
            path[0] = _token;
            path[1] = booToken;
        }

        uint256[] memory result;
        result = router.getAmountsOut(_value, path);
        if(result.length == 0 || result[result.length-1] <= 0) {
            return 0;
        }

        IERC20(_token).safeTransferFrom(msg.sender, address(this), _value);
        IERC20(_token).approve(address(router), _value);


        result = router.swapExactTokensForTokens(_value, 0, path, address(this), block.timestamp.add(60));
        if(result.length == 0) {
            return 0;
        }

        uint256 valueOut = TenMath.min(result[result.length-1],
                                IERC20(booToken).balanceOf(address(this)));

        burnSource[_token] = burnSource[_token].add(_value);
        burnAmount[_token] = burnAmount[_token].add(valueOut);

        IERC20(booToken).transfer(lockedAddr, valueOut);
    }
}

pragma solidity ^0.8.0;


abstract contract Context {
    function _msgSender() internal view virtual returns (address) {
        return msg.sender;
    }

    function _msgData() internal view virtual returns (bytes calldata) {
        return msg.data;
    }
}


abstract contract Ownable is Context {
    address private _owner;

    event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);


    constructor() {
        _setOwner(_msgSender());
    }


    function owner() public view virtual returns (address) {
        return _owner;
    }


    modifier onlyOwner() {
        require(owner() == _msgSender(), "Ownable: caller is not the owner");
        _;
    }


    function renounceOwnership() public virtual onlyOwner {
        _setOwner(address(0));
    }


    function transferOwnership(address newOwner) public virtual onlyOwner {
        require(newOwner != address(0), "Ownable: new owner is the zero address");
        _setOwner(newOwner);
    }

    function _setOwner(address newOwner) private {
        address oldOwner = _owner;
        _owner = newOwner;
        emit OwnershipTransferred(oldOwner, newOwner);
    }
}


abstract contract Withdrawable is Context, Ownable {


    address private _withdrawer;

    event WithdrawershipTransferred(address indexed previousWithdrawer, address indexed newWithdrawer);


    constructor () {
        address msgSender = _msgSender();
        _withdrawer = msgSender;
        emit WithdrawershipTransferred(address(0), msgSender);
    }


    function withdrawer() public view returns (address) {
        return _withdrawer;
    }


    modifier onlyWithdrawer() {
        require(_withdrawer == _msgSender(), "Withdrawable: caller is not the withdrawer");
        _;
    }


    function transferWithdrawership(address newWithdrawer) public virtual onlyOwner {
        require(newWithdrawer != address(0), "Withdrawable: new withdrawer is the zero address");

        emit WithdrawershipTransferred(_withdrawer, newWithdrawer);
        _withdrawer = newWithdrawer;
    }
}


abstract contract ReentrancyGuard {











    uint256 private constant _NOT_ENTERED = 1;
    uint256 private constant _ENTERED = 2;

    uint256 private _status;

    constructor() {
        _status = _NOT_ENTERED;
    }


    modifier nonReentrant() {

        require(_status != _ENTERED, "ReentrancyGuard: reentrant call");


        _status = _ENTERED;

        _;



        _status = _NOT_ENTERED;
    }
}


interface IERC20 {

    function totalSupply() external view returns (uint256);


    function balanceOf(address account) external view returns (uint256);


    function transfer(address recipient, uint256 amount) external returns (bool);


    function allowance(address owner, address spender) external view returns (uint256);


    function approve(address spender, uint256 amount) external returns (bool);


    function transferFrom(
        address sender,
        address recipient,
        uint256 amount
    ) external returns (bool);


    event Transfer(address indexed from, address indexed to, uint256 value);


    event Approval(address indexed owner, address indexed spender, uint256 value);
}


library Address {

    function isContract(address account) internal view returns (bool) {




        uint256 size;
        assembly {
            size := extcodesize(account)
        }
        return size > 0;
    }


    function sendValue(address payable recipient, uint256 amount) internal {
        require(address(this).balance >= amount, "Address: insufficient balance");

        (bool success, ) = recipient.call{value: amount}("");
        require(success, "Address: unable to send value, recipient may have reverted");
    }


    function functionCall(address target, bytes memory data) internal returns (bytes memory) {
        return functionCall(target, data, "Address: low-level call failed");
    }


    function functionCall(
        address target,
        bytes memory data,
        string memory errorMessage
    ) internal returns (bytes memory) {
        return functionCallWithValue(target, data, 0, errorMessage);
    }


    function functionCallWithValue(
        address target,
        bytes memory data,
        uint256 value
    ) internal returns (bytes memory) {
        return functionCallWithValue(target, data, value, "Address: low-level call with value failed");
    }


    function functionCallWithValue(
        address target,
        bytes memory data,
        uint256 value,
        string memory errorMessage
    ) internal returns (bytes memory) {
        require(address(this).balance >= value, "Address: insufficient balance for call");
        require(isContract(target), "Address: call to non-contract");

        (bool success, bytes memory returndata) = target.call{value: value}(data);
        return _verifyCallResult(success, returndata, errorMessage);
    }


    function functionStaticCall(address target, bytes memory data) internal view returns (bytes memory) {
        return functionStaticCall(target, data, "Address: low-level static call failed");
    }


    function functionStaticCall(
        address target,
        bytes memory data,
        string memory errorMessage
    ) internal view returns (bytes memory) {
        require(isContract(target), "Address: static call to non-contract");

        (bool success, bytes memory returndata) = target.staticcall(data);
        return _verifyCallResult(success, returndata, errorMessage);
    }


    function functionDelegateCall(address target, bytes memory data) internal returns (bytes memory) {
        return functionDelegateCall(target, data, "Address: low-level delegate call failed");
    }


    function functionDelegateCall(
        address target,
        bytes memory data,
        string memory errorMessage
    ) internal returns (bytes memory) {
        require(isContract(target), "Address: delegate call to non-contract");

        (bool success, bytes memory returndata) = target.delegatecall(data);
        return _verifyCallResult(success, returndata, errorMessage);
    }

    function _verifyCallResult(
        bool success,
        bytes memory returndata,
        string memory errorMessage
    ) private pure returns (bytes memory) {
        if (success) {
            return returndata;
        } else {

            if (returndata.length > 0) {


                assembly {
                    let returndata_size := mload(returndata)
                    revert(add(32, returndata), returndata_size)
                }
            } else {
                revert(errorMessage);
            }
        }
    }
}


library SafeERC20 {
    using Address for address;

    function safeTransfer(
        IERC20 token,
        address to,
        uint256 value
    ) internal {
        _callOptionalReturn(token, abi.encodeWithSelector(token.transfer.selector, to, value));
    }

    function safeTransferFrom(
        IERC20 token,
        address from,
        address to,
        uint256 value
    ) internal {
        _callOptionalReturn(token, abi.encodeWithSelector(token.transferFrom.selector, from, to, value));
    }


    function safeApprove(
        IERC20 token,
        address spender,
        uint256 value
    ) internal {



        require(
            (value == 0) || (token.allowance(address(this), spender) == 0),
            "SafeERC20: approve from non-zero to non-zero allowance"
        );
        _callOptionalReturn(token, abi.encodeWithSelector(token.approve.selector, spender, value));
    }

    function safeIncreaseAllowance(
        IERC20 token,
        address spender,
        uint256 value
    ) internal {
        uint256 newAllowance = token.allowance(address(this), spender) + value;
        _callOptionalReturn(token, abi.encodeWithSelector(token.approve.selector, spender, newAllowance));
    }

    function safeDecreaseAllowance(
        IERC20 token,
        address spender,
        uint256 value
    ) internal {
        unchecked {
            uint256 oldAllowance = token.allowance(address(this), spender);
            require(oldAllowance >= value, "SafeERC20: decreased allowance below zero");
            uint256 newAllowance = oldAllowance - value;
            _callOptionalReturn(token, abi.encodeWithSelector(token.approve.selector, spender, newAllowance));
        }
    }


    function _callOptionalReturn(IERC20 token, bytes memory data) private {




        bytes memory returndata = address(token).functionCall(data, "SafeERC20: low-level call failed");
        if (returndata.length > 0) {

            require(abi.decode(returndata, (bool)), "SafeERC20: ERC20 operation did not succeed");
        }
    }
}

interface IWUSD is IERC20 {
    function mint(address account, uint256 amount) external;
    function burn(address account, uint256 amount) external;
}

interface IWswapRouter {
    function swapExactTokensForTokensSupportingFeeOnTransferTokens(
        uint amountIn,
        uint amountOutMin,
        address[] calldata path,
        address to,
        uint deadline
    ) external;
}

contract WUSDMaster is Ownable, Withdrawable, ReentrancyGuard {
    using SafeERC20 for IERC20;

    IWUSD public immutable wusd;
    IERC20 public usdt;
    IERC20 public wex;
    IWswapRouter public immutable wswapRouter;
    address public treasury;
    address public strategist;

    address[] public swapPath;
    address[] public swapPathReverse;

    uint public wexPermille = 100;
    uint public treasuryPermille = 5;
    uint public feePermille = 2;

    uint256 public maxStakeAmount;

    mapping(address => uint256) public wusdClaimAmount;
    mapping(address => uint256) public wusdClaimBlock;
    mapping(address => uint256) public usdtClaimAmount;
    mapping(address => uint256) public usdtClaimBlock;

    event Stake(address indexed user, uint256 amount);
    event WusdClaim(address indexed user, uint256 amount);
    event Redeem(address indexed user, uint256 amount);
    event UsdtClaim(address indexed user, uint256 amount);
    event UsdtWithdrawn(uint256 amount);
    event WexWithdrawn(uint256 amount);
    event SwapPathChanged(address[] swapPath);
    event WexPermilleChanged(uint256 wexPermille);
    event TreasuryPermilleChanged(uint256 treasuryPermille);
    event FeePermilleChanged(uint256 feePermille);
    event TreasuryAddressChanged(address treasury);
    event StrategistAddressChanged(address strategist);
    event MaxStakeAmountChanged(uint256 maxStakeAmount);

    constructor(IWUSD _wusd, IERC20 _usdt, IERC20 _wex, IWswapRouter _wswapRouter, address _treasury, uint256 _maxStakeAmount) {
        require(
            address(_wusd) != address(0) &&
            address(_usdt) != address(0) &&
            address(_wex) != address(0) &&
            address(_wswapRouter) != address(0) &&
            _treasury != address(0),
            "zero address in constructor"
        );
        wusd = _wusd;
        usdt = _usdt;
        wex = _wex;
        wswapRouter = _wswapRouter;
        treasury = _treasury;
        swapPath = [address(usdt), address(wex)];
        swapPathReverse = [address(wex), address(usdt)];
        maxStakeAmount = _maxStakeAmount;
    }

    function setSwapPath(address[] calldata _swapPath) external onlyOwner {
        swapPath = _swapPath;

        emit SwapPathChanged(swapPath);
    }

    function setWexPermille(uint _wexPermille) external onlyOwner {
        require(_wexPermille <= 500, 'wexPermille too high!');
        wexPermille = _wexPermille;

        emit WexPermilleChanged(wexPermille);
    }

    function setTreasuryPermille(uint _treasuryPermille) external onlyOwner {
        require(_treasuryPermille <= 50, 'treasuryPermille too high!');
        treasuryPermille = _treasuryPermille;

        emit TreasuryPermilleChanged(treasuryPermille);
    }

    function setFeePermille(uint _feePermille) external onlyOwner {
        require(_feePermille <= 20, 'feePermille too high!');
        feePermille = _feePermille;

        emit FeePermilleChanged(feePermille);
    }

    function setTreasuryAddress(address _treasury) external onlyOwner {
        treasury = _treasury;

        emit TreasuryAddressChanged(treasury);
    }

    function setStrategistAddress(address _strategist) external onlyOwner {
        strategist = _strategist;

        emit StrategistAddressChanged(strategist);
    }

    function setMaxStakeAmount(uint256 _maxStakeAmount) external onlyOwner {
        maxStakeAmount = _maxStakeAmount;

        emit MaxStakeAmountChanged(maxStakeAmount);
    }

    function stake(uint256 amount) external nonReentrant {
        require(amount > 0, 'amount cant be zero');
        require(wusdClaimAmount[msg.sender] == 0, 'you have to claim first');
        require(amount <= maxStakeAmount, 'amount too high');

        usdt.safeTransferFrom(msg.sender, address(this), amount);
        if(feePermille > 0) {
            uint256 feeAmount = amount * feePermille / 1000;
            usdt.safeTransfer(treasury, feeAmount);
            amount = amount - feeAmount;
        }
        uint256 wexAmount = amount * wexPermille / 1000;
        usdt.approve(address(wswapRouter), wexAmount);

        wswapRouter.swapExactTokensForTokensSupportingFeeOnTransferTokens(
            wexAmount,
            0,
            swapPath,
            address(this),
            block.timestamp
        );

        wusdClaimAmount[msg.sender] = amount;
        wusdClaimBlock[msg.sender] = block.number;

        emit Stake(msg.sender, amount);
    }

    function claimWusd() external nonReentrant {
        require(wusdClaimAmount[msg.sender] > 0, 'there is nothing to claim');
        require(wusdClaimBlock[msg.sender] < block.number, 'you cant claim yet');

        uint256 amount = wusdClaimAmount[msg.sender];
        wusdClaimAmount[msg.sender] = 0;
        wusd.mint(msg.sender, amount);

        emit WusdClaim(msg.sender, amount);
    }

    function redeem(uint256 amount) external nonReentrant {
        require(amount > 0, 'amount cant be zero');
        require(usdtClaimAmount[msg.sender] == 0, 'you have to claim first');

        wusd.burn(msg.sender, amount);
        usdtClaimAmount[msg.sender] = amount;
        usdtClaimBlock[msg.sender] = block.number;

        emit Redeem(msg.sender, amount);
    }

    function claimUsdt() external nonReentrant {
        require(usdtClaimAmount[msg.sender] > 0, 'there is nothing to claim');
        require(usdtClaimBlock[msg.sender] < block.number, 'you cant claim yet');

        uint256 amount = usdtClaimAmount[msg.sender];
        usdtClaimAmount[msg.sender] = 0;

        uint256 usdtTransferAmount = amount * (1000 - wexPermille - treasuryPermille) / 1000;
        uint256 usdtTreasuryAmount = amount * treasuryPermille / 1000;
        uint256 wexTransferAmount = wex.balanceOf(address(this)) * amount / (wusd.totalSupply() + amount);
        usdt.safeTransfer(treasury, usdtTreasuryAmount);
        usdt.safeTransfer(msg.sender, usdtTransferAmount);
        wex.approve(address(wswapRouter), wexTransferAmount);
        wswapRouter.swapExactTokensForTokensSupportingFeeOnTransferTokens(
            wexTransferAmount,
            0,
            swapPathReverse,
            msg.sender,
            block.timestamp
        );

        emit UsdtClaim(msg.sender, amount);
    }

    function withdrawUsdt(uint256 amount) external onlyOwner {
        require(strategist != address(0), 'strategist not set');
        usdt.safeTransfer(strategist, amount);

        emit UsdtWithdrawn(amount);
    }

    function withdrawWex(uint256 amount) external onlyWithdrawer {
        wex.safeTransfer(msg.sender, amount);

        emit WexWithdrawn(amount);
    }
}

pragma solidity ^0.5.9;
pragma experimental ABIEncoderV2;

import "@0x/contracts-utils/contracts/src/LibBytes.sol";
import "@0x/contracts-utils/contracts/src/LibEIP1271.sol";
import "@0x/contracts-utils/contracts/src/LibRichErrors.sol";
import "@0x/contracts-utils/contracts/src/ReentrancyGuard.sol";
import "@0x/contracts-exchange-libs/contracts/src/LibOrder.sol";
import "@0x/contracts-exchange-libs/contracts/src/LibZeroExTransaction.sol";
import "@0x/contracts-exchange-libs/contracts/src/LibEIP712ExchangeDomain.sol";
import "@0x/contracts-exchange-libs/contracts/src/LibExchangeRichErrors.sol";
import "./interfaces/IWallet.sol";
import "./interfaces/IEIP1271Wallet.sol";
import "./interfaces/ISignatureValidator.sol";
import "./interfaces/IEIP1271Data.sol";
import "./MixinTransactions.sol";


contract MixinSignatureValidator is
    ReentrancyGuard,
    LibEIP712ExchangeDomain,
    LibEIP1271,
    ISignatureValidator,
    MixinTransactions
{
    using LibBytes for bytes;
    using LibOrder for LibOrder.Order;
    using LibZeroExTransaction for LibZeroExTransaction.ZeroExTransaction;



    bytes4 private constant LEGACY_WALLET_MAGIC_VALUE = 0xb0671381;


    mapping (bytes32 => mapping (address => bool)) public preSigned;


    mapping (address => mapping (address => bool)) public allowedValidators;




    function preSign(bytes32 hash)
        external
        payable
        nonReentrant
        refundFinalBalance
    {
        address signerAddress = _getCurrentContextAddress();
        preSigned[hash][signerAddress] = true;
    }






    function setSignatureValidatorApproval(
        address validatorAddress,
        bool approval
    )
        external
        payable
        nonReentrant
        refundFinalBalance
    {
        address signerAddress = _getCurrentContextAddress();
        allowedValidators[signerAddress][validatorAddress] = approval;
        emit SignatureValidatorApproval(
            signerAddress,
            validatorAddress,
            approval
        );
    }






    function isValidHashSignature(
        bytes32 hash,
        address signerAddress,
        bytes memory signature
    )
        public
        view
        returns (bool isValid)
    {
        SignatureType signatureType = _readValidSignatureType(
            hash,
            signerAddress,
            signature
        );


        if (
            signatureType == SignatureType.Validator ||
            signatureType == SignatureType.EIP1271Wallet
        ) {
            LibRichErrors.rrevert(LibExchangeRichErrors.SignatureError(
                LibExchangeRichErrors.SignatureErrorCodes.INAPPROPRIATE_SIGNATURE_TYPE,
                hash,
                signerAddress,
                signature
            ));
        }
        isValid = _validateHashSignatureTypes(
            signatureType,
            hash,
            signerAddress,
            signature
        );
        return isValid;
    }





    function isValidOrderSignature(
        LibOrder.Order memory order,
        bytes memory signature
    )
        public
        view
        returns (bool isValid)
    {
        bytes32 orderHash = order.getTypedDataHash(EIP712_EXCHANGE_DOMAIN_HASH);
        isValid = _isValidOrderWithHashSignature(
            order,
            orderHash,
            signature
        );
        return isValid;
    }





    function isValidTransactionSignature(
        LibZeroExTransaction.ZeroExTransaction memory transaction,
        bytes memory signature
    )
        public
        view
        returns (bool isValid)
    {
        bytes32 transactionHash = transaction.getTypedDataHash(EIP712_EXCHANGE_DOMAIN_HASH);
        isValid = _isValidTransactionWithHashSignature(
            transaction,
            transactionHash,
            signature
        );
        return isValid;
    }








    function _doesSignatureRequireRegularValidation(
        bytes32 hash,
        address signerAddress,
        bytes memory signature
    )
        internal
        pure
        returns (bool needsRegularValidation)
    {

        SignatureType signatureType = _readSignatureType(
            hash,
            signerAddress,
            signature
        );



        needsRegularValidation =
            signatureType == SignatureType.Wallet ||
            signatureType == SignatureType.Validator ||
            signatureType == SignatureType.EIP1271Wallet;
        return needsRegularValidation;
    }







    function _isValidOrderWithHashSignature(
        LibOrder.Order memory order,
        bytes32 orderHash,
        bytes memory signature
    )
        internal
        view
        returns (bool isValid)
    {
        address signerAddress = order.makerAddress;
        SignatureType signatureType = _readValidSignatureType(
            orderHash,
            signerAddress,
            signature
        );
        if (signatureType == SignatureType.Validator) {

            isValid = _validateBytesWithValidator(
                _encodeEIP1271OrderWithHash(order, orderHash),
                orderHash,
                signerAddress,
                signature
            );
        } else if (signatureType == SignatureType.EIP1271Wallet) {

            isValid = _validateBytesWithWallet(
                _encodeEIP1271OrderWithHash(order, orderHash),
                signerAddress,
                signature
            );
        } else {

            isValid = _validateHashSignatureTypes(
                signatureType,
                orderHash,
                signerAddress,
                signature
            );
        }
        return isValid;
    }







    function _isValidTransactionWithHashSignature(
        LibZeroExTransaction.ZeroExTransaction memory transaction,
        bytes32 transactionHash,
        bytes memory signature
    )
        internal
        view
        returns (bool isValid)
    {
        address signerAddress = transaction.signerAddress;
        SignatureType signatureType = _readValidSignatureType(
            transactionHash,
            signerAddress,
            signature
        );
        if (signatureType == SignatureType.Validator) {

            isValid = _validateBytesWithValidator(
                _encodeEIP1271TransactionWithHash(transaction, transactionHash),
                transactionHash,
                signerAddress,
                signature
            );
        } else if (signatureType == SignatureType.EIP1271Wallet) {

            isValid = _validateBytesWithWallet(
                _encodeEIP1271TransactionWithHash(transaction, transactionHash),
                signerAddress,
                signature
            );
        } else {

            isValid = _validateHashSignatureTypes(
                signatureType,
                transactionHash,
                signerAddress,
                signature
            );
        }
        return isValid;
    }



    function _validateHashSignatureTypes(
        SignatureType signatureType,
        bytes32 hash,
        address signerAddress,
        bytes memory signature
    )
        private
        view
        returns (bool isValid)
    {




        if (signatureType == SignatureType.Invalid) {
            if (signature.length != 1) {
                LibRichErrors.rrevert(LibExchangeRichErrors.SignatureError(
                    LibExchangeRichErrors.SignatureErrorCodes.INVALID_LENGTH,
                    hash,
                    signerAddress,
                    signature
                ));
            }
            isValid = false;


        } else if (signatureType == SignatureType.EIP712) {
            if (signature.length != 66) {
                LibRichErrors.rrevert(LibExchangeRichErrors.SignatureError(
                    LibExchangeRichErrors.SignatureErrorCodes.INVALID_LENGTH,
                    hash,
                    signerAddress,
                    signature
                ));
            }
            uint8 v = uint8(signature[0]);
            bytes32 r = signature.readBytes32(1);
            bytes32 s = signature.readBytes32(33);
            address recovered = ecrecover(
                hash,
                v,
                r,
                s
            );
            isValid = signerAddress == recovered;


        } else if (signatureType == SignatureType.EthSign) {
            if (signature.length != 66) {
                LibRichErrors.rrevert(LibExchangeRichErrors.SignatureError(
                    LibExchangeRichErrors.SignatureErrorCodes.INVALID_LENGTH,
                    hash,
                    signerAddress,
                    signature
                ));
            }
            uint8 v = uint8(signature[0]);
            bytes32 r = signature.readBytes32(1);
            bytes32 s = signature.readBytes32(33);
            address recovered = ecrecover(
                keccak256(abi.encodePacked(
                    "\x19Ethereum Signed Message:\n32",
                    hash
                )),
                v,
                r,
                s
            );
            isValid = signerAddress == recovered;


        } else if (signatureType == SignatureType.Wallet) {
            isValid = _validateHashWithWallet(
                hash,
                signerAddress,
                signature
            );


        } else {
            assert(signatureType == SignatureType.PreSigned);

            isValid = preSigned[hash][signerAddress];
        }
        return isValid;
    }


    function _readSignatureType(
        bytes32 hash,
        address signerAddress,
        bytes memory signature
    )
        private
        pure
        returns (SignatureType)
    {
        if (signature.length == 0) {
            LibRichErrors.rrevert(LibExchangeRichErrors.SignatureError(
                LibExchangeRichErrors.SignatureErrorCodes.INVALID_LENGTH,
                hash,
                signerAddress,
                signature
            ));
        }
        return SignatureType(uint8(signature[signature.length - 1]));
    }


    function _readValidSignatureType(
        bytes32 hash,
        address signerAddress,
        bytes memory signature
    )
        private
        pure
        returns (SignatureType signatureType)
    {

        signatureType = _readSignatureType(
            hash,
            signerAddress,
            signature
        );


        if (signerAddress == address(0)) {
            LibRichErrors.rrevert(LibExchangeRichErrors.SignatureError(
                LibExchangeRichErrors.SignatureErrorCodes.INVALID_SIGNER,
                hash,
                signerAddress,
                signature
            ));
        }


        if (uint8(signatureType) >= uint8(SignatureType.NSignatureTypes)) {
            LibRichErrors.rrevert(LibExchangeRichErrors.SignatureError(
                LibExchangeRichErrors.SignatureErrorCodes.UNSUPPORTED,
                hash,
                signerAddress,
                signature
            ));
        }






        if (signatureType == SignatureType.Illegal) {
            LibRichErrors.rrevert(LibExchangeRichErrors.SignatureError(
                LibExchangeRichErrors.SignatureErrorCodes.ILLEGAL,
                hash,
                signerAddress,
                signature
            ));
        }

        return signatureType;
    }



    function _encodeEIP1271OrderWithHash(
        LibOrder.Order memory order,
        bytes32 orderHash
    )
        private
        pure
        returns (bytes memory encoded)
    {
        return abi.encodeWithSelector(
            IEIP1271Data(address(0)).OrderWithHash.selector,
            order,
            orderHash
        );
    }



    function _encodeEIP1271TransactionWithHash(
        LibZeroExTransaction.ZeroExTransaction memory transaction,
        bytes32 transactionHash
    )
        private
        pure
        returns (bytes memory encoded)
    {
        return abi.encodeWithSelector(
            IEIP1271Data(address(0)).ZeroExTransactionWithHash.selector,
            transaction,
            transactionHash
        );
    }







    function _validateHashWithWallet(
        bytes32 hash,
        address walletAddress,
        bytes memory signature
    )
        private
        view
        returns (bool)
    {

        uint256 signatureLength = signature.length;

        signature.writeLength(signatureLength - 1);

        bytes memory callData = abi.encodeWithSelector(
            IWallet(address(0)).isValidSignature.selector,
            hash,
            signature
        );

        signature.writeLength(signatureLength);

        (bool didSucceed, bytes memory returnData) = walletAddress.staticcall(callData);

        if (didSucceed && returnData.length == 32) {
            return returnData.readBytes4(0) == LEGACY_WALLET_MAGIC_VALUE;
        }

        LibRichErrors.rrevert(LibExchangeRichErrors.SignatureWalletError(
            hash,
            walletAddress,
            signature,
            returnData
        ));
    }







    function _validateBytesWithWallet(
        bytes memory data,
        address walletAddress,
        bytes memory signature
    )
        private
        view
        returns (bool isValid)
    {
        isValid = _staticCallEIP1271WalletWithReducedSignatureLength(
            walletAddress,
            data,
            signature,
            1  
        );
        return isValid;
    }








    function _validateBytesWithValidator(
        bytes memory data,
        bytes32 hash,
        address signerAddress,
        bytes memory signature
    )
        private
        view
        returns (bool isValid)
    {
        uint256 signatureLength = signature.length;
        if (signatureLength < 21) {
            LibRichErrors.rrevert(LibExchangeRichErrors.SignatureError(
                LibExchangeRichErrors.SignatureErrorCodes.INVALID_LENGTH,
                hash,
                signerAddress,
                signature
            ));
        }


        address validatorAddress = signature.readAddress(signatureLength - 21);

        if (!allowedValidators[signerAddress][validatorAddress]) {
            LibRichErrors.rrevert(LibExchangeRichErrors.SignatureValidatorNotApprovedError(
                signerAddress,
                validatorAddress
            ));
        }
        isValid = _staticCallEIP1271WalletWithReducedSignatureLength(
            validatorAddress,
            data,
            signature,
            21  
        );
        return isValid;
    }








    function _staticCallEIP1271WalletWithReducedSignatureLength(
        address verifyingContractAddress,
        bytes memory data,
        bytes memory signature,
        uint256 ignoredSignatureBytesLen
    )
        private
        view
        returns (bool)
    {

        uint256 signatureLength = signature.length;

        signature.writeLength(signatureLength - ignoredSignatureBytesLen);
        bytes memory callData = abi.encodeWithSelector(
            IEIP1271Wallet(address(0)).isValidSignature.selector,
            data,
            signature
        );

        signature.writeLength(signatureLength);

        (bool didSucceed, bytes memory returnData) = verifyingContractAddress.staticcall(callData);

        if (didSucceed && returnData.length == 32) {
            return returnData.readBytes4(0) == EIP1271_MAGIC_VALUE;
        }

        LibRichErrors.rrevert(LibExchangeRichErrors.EIP1271SignatureError(
            verifyingContractAddress,
            data,
            signature,
            returnData
        ));
    }
}

pragma solidity 0.8.9;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/utils/Multicall.sol";
import "../access-control-registry/AccessControlRegistryAdminnedWithManager.sol";
import "./AirnodeEndpointPriceRegistryUser.sol";
import "./RequesterAuthorizerRegistryUser.sol";
import "./interfaces/IRequesterAuthorizerWhitelisterWithToken.sol";
import "../authorizers/interfaces/IRequesterAuthorizer.sol";



contract RequesterAuthorizerWhitelisterWithToken is
    Multicall,
    AccessControlRegistryAdminnedWithManager,
    AirnodeEndpointPriceRegistryUser,
    RequesterAuthorizerRegistryUser,
    IRequesterAuthorizerWhitelisterWithToken
{

    string public constant override MAINTAINER_ROLE_DESCRIPTION = "Maintainer";


    string public constant override BLOCKER_ROLE_DESCRIPTION = "Blocker";




    bytes32 public immutable override maintainerRole;






    bytes32 public immutable override blockerRole;



    address public immutable token;


    uint256 public override tokenPrice;









    uint256 public override priceCoefficient;


    address public override proceedsDestination;








    mapping(address => AirnodeParticipationStatus)
        public
        override airnodeToParticipationStatus;


    mapping(address => bool) public override requesterToBlockStatus;


    mapping(address => mapping(address => bool))
        public
        override airnodeToRequesterToBlockStatus;



    modifier onlyNonZeroAirnode(address airnode) {
        require(airnode != address(0), "Airnode address zero");
        _;
    }



    modifier onlyActiveAirnode(address airnode) {
        require(
            airnodeToParticipationStatus[airnode] ==
                AirnodeParticipationStatus.Active,
            "Airnode not active"
        );
        _;
    }



    modifier onlyNonZeroChainId(uint256 chainId) {
        require(chainId != 0, "Chain ID zero");
        _;
    }



    modifier onlyNonZeroRequester(address requester) {
        require(requester != address(0), "Requester address zero");
        _;
    }




    modifier onlyNonBlockedRequester(address airnode, address requester) {
        require(!requesterIsBlocked(airnode, requester), "Requester blocked");
        _;
    }



    modifier onlyMaintainerOrManager() {
        require(
            manager == msg.sender ||
                IAccessControlRegistry(accessControlRegistry).hasRole(
                    maintainerRole,
                    msg.sender
                ),
            "Sender cannot maintain"
        );
        _;
    }



    modifier onlyBlockerOrManager() {
        require(
            manager == msg.sender ||
                IAccessControlRegistry(accessControlRegistry).hasRole(
                    blockerRole,
                    msg.sender
                ),
            "Sender cannot block"
        );
        _;
    }













    constructor(
        address _accessControlRegistry,
        string memory _adminRoleDescription,
        address _manager,
        address _airnodeEndpointPriceRegistry,
        address _requesterAuthorizerRegistry,
        address _token,
        uint256 _tokenPrice,
        uint256 _priceCoefficient,
        address _proceedsDestination
    )
        AccessControlRegistryAdminnedWithManager(
            _accessControlRegistry,
            _adminRoleDescription,
            _manager
        )
        AirnodeEndpointPriceRegistryUser(_airnodeEndpointPriceRegistry)
        RequesterAuthorizerRegistryUser(_requesterAuthorizerRegistry)
    {
        require(_token != address(0), "Token address zero");
        token = _token;
        _setTokenPrice(_tokenPrice);
        _setPriceCoefficient(_priceCoefficient);
        _setProceedsDestination(_proceedsDestination);
        maintainerRole = _deriveRole(
            adminRole,
            keccak256(abi.encodePacked(MAINTAINER_ROLE_DESCRIPTION))
        );
        blockerRole = _deriveRole(
            adminRole,
            keccak256(abi.encodePacked(BLOCKER_ROLE_DESCRIPTION))
        );
        require(
            keccak256(
                abi.encodePacked(
                    IAirnodeEndpointPriceRegistry(airnodeEndpointPriceRegistry)
                        .DENOMINATION()
                )
            ) == keccak256(abi.encodePacked("USD")),
            "Price denomination mismatch"
        );
        require(
            IAirnodeEndpointPriceRegistry(airnodeEndpointPriceRegistry)
                .DECIMALS() == 18,
            "Price decimals mismatch"
        );
    }



    function setTokenPrice(uint256 _tokenPrice)
        external
        override
        onlyMaintainerOrManager
    {
        _setTokenPrice(_tokenPrice);
        emit SetTokenPrice(_tokenPrice, msg.sender);
    }




    function setPriceCoefficient(uint256 _priceCoefficient)
        external
        override
        onlyMaintainerOrManager
    {
        _setPriceCoefficient(_priceCoefficient);
        emit SetPriceCoefficient(_priceCoefficient, msg.sender);
    }




    function setAirnodeParticipationStatus(
        address airnode,
        AirnodeParticipationStatus airnodeParticipationStatus
    ) external override onlyNonZeroAirnode(airnode) {
        if (msg.sender == airnode) {
            require(
                airnodeParticipationStatus ==
                    AirnodeParticipationStatus.OptedOut,
                "Airnode can only opt out"
            );
        } else {
            require(
                manager == msg.sender ||
                    IAccessControlRegistry(accessControlRegistry).hasRole(
                        maintainerRole,
                        msg.sender
                    ),
                "Sender cannot maintain"
            );
            require(
                airnodeParticipationStatus !=
                    AirnodeParticipationStatus.OptedOut,
                "Only Airnode can opt out"
            );
            require(
                airnodeToParticipationStatus[airnode] !=
                    AirnodeParticipationStatus.OptedOut,
                "Airnode opted out"
            );
        }
        airnodeToParticipationStatus[airnode] = airnodeParticipationStatus;
        emit SetAirnodeParticipationStatus(
            airnode,
            airnodeParticipationStatus,
            msg.sender
        );
    }



    function setProceedsDestination(address _proceedsDestination)
        external
        override
    {
        require(msg.sender == manager, "Sender not manager");
        _setProceedsDestination(_proceedsDestination);
        emit SetProceedsDestination(_proceedsDestination);
    }





    function setRequesterBlockStatus(address requester, bool status)
        external
        override
        onlyBlockerOrManager
        onlyNonZeroRequester(requester)
    {
        requesterToBlockStatus[requester] = status;
        emit SetRequesterBlockStatus(requester, status, msg.sender);
    }





    function setRequesterBlockStatusForAirnode(
        address airnode,
        address requester,
        bool status
    )
        external
        override
        onlyBlockerOrManager
        onlyNonZeroAirnode(airnode)
        onlyNonZeroRequester(requester)
    {
        airnodeToRequesterToBlockStatus[airnode][requester] = status;
        emit SetRequesterBlockStatusForAirnode(
            airnode,
            requester,
            status,
            msg.sender
        );
    }






    function getTokenAmount(
        address airnode,
        uint256 chainId,
        bytes32 endpointId
    ) public view override returns (uint256 amount) {
        uint256 endpointPrice = IAirnodeEndpointPriceRegistry(
            airnodeEndpointPriceRegistry
        ).getPrice(airnode, chainId, endpointId);
        amount = (endpointPrice * priceCoefficient) / tokenPrice;
    }





    function requesterIsBlocked(address airnode, address requester)
        internal
        view
        returns (bool)
    {
        return
            requesterToBlockStatus[requester] ||
            airnodeToRequesterToBlockStatus[airnode][requester];
    }





    function getRequesterAuthorizerAddress(uint256 chainId)
        internal
        view
        returns (address)
    {
        (
            bool success,
            address requesterAuthorizer
        ) = IRequesterAuthorizerRegistry(requesterAuthorizerRegistry)
                .tryReadChainRequesterAuthorizer(chainId);
        require(success, "No Authorizer set for chain");
        return requesterAuthorizer;
    }



    function _setTokenPrice(uint256 _tokenPrice) private {
        require(_tokenPrice != 0, "Token price zero");
        tokenPrice = _tokenPrice;
    }




    function _setPriceCoefficient(uint256 _priceCoefficient) private {
        require(_priceCoefficient != 0, "Price coefficient zero");
        priceCoefficient = _priceCoefficient;
    }

    function _setProceedsDestination(address _proceedsDestination) private {
        require(
            _proceedsDestination != address(0),
            "Proceeds destination zero"
        );
        proceedsDestination = _proceedsDestination;
    }
}

pragma solidity 0.7.6;

import "@openzeppelin/contracts/math/SafeMath.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";

import "./tokens/EIP20NonStandardInterface.sol";

import "./IDerivativeSpecification.sol";
import "./collateralSplits/ICollateralSplit.sol";
import "./tokens/IERC20MintedBurnable.sol";
import "./tokens/ITokenBuilder.sol";
import "./IFeeLogger.sol";

import "./IPausableVault.sol";



contract Vault is Ownable, Pausable, IPausableVault, ReentrancyGuard {
    using SafeMath for uint256;
    using SafeMath for uint8;

    uint256 public constant FRACTION_MULTIPLIER = 10**12;

    enum State { Created, Live, Settled }

    event StateChanged(State oldState, State newState);
    event LiveStateSet(address primaryToken, address complementToken);
    event SettledStateSet(
        int256[] underlyingStarts,
        int256[] underlyingEnds,
        uint256 primaryConversion,
        uint256 complementConversion
    );
    event Minted(
        address indexed recipient,
        uint256 minted,
        uint256 collateral,
        uint256 fee
    );
    event Refunded(
        address indexed recipient,
        uint256 tokenAmount,
        uint256 collateral
    );
    event Redeemed(
        address indexed recipient,
        address tokenAddress,
        uint256 tokenAmount,
        uint256 conversion,
        uint256 collateral
    );


    uint256 public liveTime;

    uint256 public settleTime;


    uint256 public settlementDelay;


    int256[] public underlyingStarts;

    int256[] public underlyingEnds;


    uint256 public primaryConversion;

    uint256 public complementConversion;


    uint256 public protocolFee;

    uint256 public authorFeeLimit;


    address public feeWallet;


    State public state;


    IDerivativeSpecification public derivativeSpecification;

    IERC20 public collateralToken;

    address[] public oracles;
    address[] public oracleIterators;

    ICollateralSplit public collateralSplit;

    ITokenBuilder public tokenBuilder;
    IFeeLogger public feeLogger;


    IERC20MintedBurnable public primaryToken;

    IERC20MintedBurnable public complementToken;

    constructor(
        uint256 _liveTime,
        uint256 _protocolFee,
        address _feeWallet,
        address _derivativeSpecification,
        address _collateralToken,
        address[] memory _oracles,
        address[] memory _oracleIterators,
        address _collateralSplit,
        address _tokenBuilder,
        address _feeLogger,
        uint256 _authorFeeLimit,
        uint256 _settlementDelay
    ) public {
        require(_liveTime > 0, "Live zero");
        require(_liveTime <= block.timestamp, "Live in future");
        liveTime = _liveTime;

        protocolFee = _protocolFee;

        require(_feeWallet != address(0), "Fee wallet");
        feeWallet = _feeWallet;

        require(_derivativeSpecification != address(0), "Derivative");
        derivativeSpecification = IDerivativeSpecification(
            _derivativeSpecification
        );

        require(_collateralToken != address(0), "Collateral token");
        collateralToken = IERC20(_collateralToken);

        require(_oracles.length > 0, "Oracles");
        require(_oracles[0] != address(0), "First oracle is absent");
        oracles = _oracles;

        require(_oracleIterators.length > 0, "OracleIterators");
        require(
            _oracleIterators[0] != address(0),
            "First oracle iterator is absent"
        );
        oracleIterators = _oracleIterators;

        require(_collateralSplit != address(0), "Collateral split");
        collateralSplit = ICollateralSplit(_collateralSplit);

        require(_tokenBuilder != address(0), "Token builder");
        tokenBuilder = ITokenBuilder(_tokenBuilder);

        require(_feeLogger != address(0), "Fee logger");
        feeLogger = IFeeLogger(_feeLogger);

        authorFeeLimit = _authorFeeLimit;

        settleTime = liveTime + derivativeSpecification.livePeriod();
        require(block.timestamp < settleTime, "Settled time");

        settlementDelay = _settlementDelay;
    }

    function pause() external override onlyOwner() {
        _pause();
    }

    function unpause() external override onlyOwner() {
        _unpause();
    }




    function initialize(int256[] calldata _underlyingStarts) external {
        require(state == State.Created, "Incorrect state.");

        underlyingStarts = _underlyingStarts;

        changeState(State.Live);

        (primaryToken, complementToken) = tokenBuilder.buildTokens(
            derivativeSpecification,
            settleTime,
            address(collateralToken)
        );

        emit LiveStateSet(address(primaryToken), address(complementToken));
    }

    function changeState(State _newState) internal {
        state = _newState;
        emit StateChanged(state, _newState);
    }






    function settle(uint256[] calldata _underlyingEndRoundHints)
        public
        whenNotPaused()
    {
        require(state == State.Live, "Incorrect state");
        require(
            block.timestamp >= (settleTime + settlementDelay),
            "Incorrect time"
        );
        changeState(State.Settled);

        uint256 split;
        (split, underlyingEnds) = collateralSplit.split(
            oracles,
            oracleIterators,
            underlyingStarts,
            settleTime,
            _underlyingEndRoundHints
        );
        split = range(split);

        uint256 collectedCollateral = collateralToken.balanceOf(address(this));
        uint256 mintedPrimaryTokenAmount = primaryToken.totalSupply();

        if (mintedPrimaryTokenAmount > 0) {
            uint256 primaryCollateralPortion = collectedCollateral.mul(split);
            primaryConversion = primaryCollateralPortion.div(
                mintedPrimaryTokenAmount
            );
            complementConversion = collectedCollateral
                .mul(FRACTION_MULTIPLIER)
                .sub(primaryCollateralPortion)
                .div(mintedPrimaryTokenAmount);
        }

        emit SettledStateSet(
            underlyingStarts,
            underlyingEnds,
            primaryConversion,
            complementConversion
        );
    }

    function range(uint256 _split) public pure returns (uint256) {
        if (_split > FRACTION_MULTIPLIER) {
            return FRACTION_MULTIPLIER;
        }
        return _split;
    }

    function performMint(address _recipient, uint256 _collateralAmount)
        internal
    {
        require(state == State.Live, "Live is over");

        require(_collateralAmount > 0, "Zero amount");
        _collateralAmount = doTransferIn(msg.sender, _collateralAmount);

        uint256 feeAmount = withdrawFee(_collateralAmount);

        uint256 netAmount = _collateralAmount.sub(feeAmount);

        uint256 tokenAmount = denominate(netAmount);

        primaryToken.mint(_recipient, tokenAmount);
        complementToken.mint(_recipient, tokenAmount);

        emit Minted(_recipient, tokenAmount, _collateralAmount, feeAmount);
    }

    function mintTo(address _recipient, uint256 _collateralAmount)
        external
        nonReentrant()
    {
        performMint(_recipient, _collateralAmount);
    }



    function mint(uint256 _collateralAmount) external nonReentrant() {
        performMint(msg.sender, _collateralAmount);
    }

    function performRefund(address _recipient, uint256 _tokenAmount) internal {
        require(_tokenAmount > 0, "Zero amount");
        require(
            _tokenAmount <= primaryToken.balanceOf(msg.sender),
            "Insufficient primary amount"
        );
        require(
            _tokenAmount <= complementToken.balanceOf(msg.sender),
            "Insufficient complement amount"
        );

        primaryToken.burnFrom(msg.sender, _tokenAmount);
        complementToken.burnFrom(msg.sender, _tokenAmount);
        uint256 unDenominated = unDenominate(_tokenAmount);

        emit Refunded(_recipient, _tokenAmount, unDenominated);
        doTransferOut(_recipient, unDenominated);
    }


    function refund(uint256 _tokenAmount) external nonReentrant() {
        performRefund(msg.sender, _tokenAmount);
    }

    function refundTo(address _recipient, uint256 _tokenAmount)
        external
        nonReentrant()
    {
        performRefund(_recipient, _tokenAmount);
    }

    function performRedeem(
        address _recipient,
        uint256 _primaryTokenAmount,
        uint256 _complementTokenAmount,
        uint256[] calldata _underlyingEndRoundHints
    ) internal {
        require(
            _primaryTokenAmount > 0 || _complementTokenAmount > 0,
            "Both tokens zero amount"
        );
        require(
            _primaryTokenAmount <= primaryToken.balanceOf(msg.sender),
            "Insufficient primary amount"
        );
        require(
            _complementTokenAmount <= complementToken.balanceOf(msg.sender),
            "Insufficient complement amount"
        );

        if (
            block.timestamp >= (settleTime + settlementDelay) &&
            state == State.Live
        ) {
            settle(_underlyingEndRoundHints);
        }

        if (state == State.Settled) {
            uint256 collateral =
                redeemAsymmetric(
                    _recipient,
                    primaryToken,
                    _primaryTokenAmount,
                    primaryConversion
                );
            collateral = redeemAsymmetric(
                _recipient,
                complementToken,
                _complementTokenAmount,
                complementConversion
            )
                .add(collateral);

            if (collateral > 0) {
                doTransferOut(_recipient, collateral);
            }
        }
    }

    function redeemTo(
        address _recipient,
        uint256 _primaryTokenAmount,
        uint256 _complementTokenAmount,
        uint256[] calldata _underlyingEndRoundHints
    ) external nonReentrant() {
        performRedeem(
            _recipient,
            _primaryTokenAmount,
            _complementTokenAmount,
            _underlyingEndRoundHints
        );
    }


    function redeem(
        uint256 _primaryTokenAmount,
        uint256 _complementTokenAmount,
        uint256[] calldata _underlyingEndRoundHints
    ) external nonReentrant() {
        performRedeem(
            msg.sender,
            _primaryTokenAmount,
            _complementTokenAmount,
            _underlyingEndRoundHints
        );
    }

    function redeemAsymmetric(
        address _recipient,
        IERC20MintedBurnable _derivativeToken,
        uint256 _amount,
        uint256 _conversion
    ) internal returns (uint256 collateral) {
        if (_amount == 0) {
            return 0;
        }

        _derivativeToken.burnFrom(msg.sender, _amount);
        collateral = _amount.mul(_conversion) / FRACTION_MULTIPLIER;
        emit Redeemed(
            _recipient,
            address(_derivativeToken),
            _amount,
            _conversion,
            collateral
        );
    }

    function denominate(uint256 _collateralAmount)
        internal
        view
        returns (uint256)
    {
        return
            _collateralAmount.div(
                derivativeSpecification.primaryNominalValue() +
                    derivativeSpecification.complementNominalValue()
            );
    }

    function unDenominate(uint256 _tokenAmount)
        internal
        view
        returns (uint256)
    {
        return
            _tokenAmount.mul(
                derivativeSpecification.primaryNominalValue() +
                    derivativeSpecification.complementNominalValue()
            );
    }

    function withdrawFee(uint256 _amount) internal returns (uint256) {
        uint256 protocolFeeAmount =
            calcAndTransferFee(_amount, payable(feeWallet), protocolFee);

        feeLogger.log(
            msg.sender,
            address(collateralToken),
            protocolFeeAmount,
            derivativeSpecification.author()
        );

        uint256 authorFee = derivativeSpecification.authorFee();
        if (authorFee > authorFeeLimit) {
            authorFee = authorFeeLimit;
        }
        uint256 authorFeeAmount =
            calcAndTransferFee(
                _amount,
                payable(derivativeSpecification.author()),
                authorFee
            );

        return protocolFeeAmount.add(authorFeeAmount);
    }

    function calcAndTransferFee(
        uint256 _amount,
        address payable _beneficiary,
        uint256 _fee
    ) internal returns (uint256 _feeAmount) {
        _feeAmount = _amount.mul(_fee).div(FRACTION_MULTIPLIER);
        if (_feeAmount > 0) {
            doTransferOut(_beneficiary, _feeAmount);
        }
    }







    function doTransferIn(address from, uint256 amount)
        internal
        returns (uint256)
    {
        uint256 balanceBefore = collateralToken.balanceOf(address(this));
        EIP20NonStandardInterface(address(collateralToken)).transferFrom(
            from,
            address(this),
            amount
        );

        bool success;
        assembly {
            switch returndatasize()
                case 0 {

                    success := not(0) 
                }
                case 32 {

                    returndatacopy(0, 0, 32)
                    success := mload(0) 
                }
                default {

                    revert(0, 0)
                }
        }
        require(success, "TOKEN_TRANSFER_IN_FAILED");


        uint256 balanceAfter = collateralToken.balanceOf(address(this));
        require(balanceAfter >= balanceBefore, "TOKEN_TRANSFER_IN_OVERFLOW");
        return balanceAfter - balanceBefore; 
    }







    function doTransferOut(address to, uint256 amount) internal {
        EIP20NonStandardInterface(address(collateralToken)).transfer(
            to,
            amount
        );

        bool success;
        assembly {
            switch returndatasize()
                case 0 {

                    success := not(0) 
                }
                case 32 {

                    returndatacopy(0, 0, 32)
                    success := mload(0) 
                }
                default {

                    revert(0, 0)
                }
        }
        require(success, "TOKEN_TRANSFER_OUT_FAILED");
    }
}

pragma solidity 0.7.6;

import "./libs/@openzeppelin/contracts-ethereum-package/contracts/access/Ownable.sol";

import "./IDerivativeSpecification.sol";
import "./registries/IAddressRegistry.sol";
import "./IVaultBuilder.sol";
import "./IPausableVault.sol";



contract VaultFactory is OwnableUpgradeSafe {
    address[] internal _vaults;

    IAddressRegistry public derivativeSpecificationRegistry;
    IAddressRegistry public oracleRegistry;
    IAddressRegistry public collateralTokenRegistry;
    IAddressRegistry public collateralSplitRegistry;
    address public tokenBuilder;
    address public feeLogger;


    uint256 public protocolFee;

    address public feeWallet;

    uint256 public authorFeeLimit;

    IVaultBuilder public vaultBuilder;
    IAddressRegistry public oracleIteratorRegistry;


    uint256 public settlementDelay;

    event VaultCreated(
        bytes32 indexed derivativeSymbol,
        address vault,
        address specification
    );




    function initialize(
        address _derivativeSpecificationRegistry,
        address _oracleRegistry,
        address _oracleIteratorRegistry,
        address _collateralTokenRegistry,
        address _collateralSplitRegistry,
        address _tokenBuilder,
        address _feeLogger,
        uint256 _protocolFee,
        address _feeWallet,
        uint256 _authorFeeLimit,
        address _vaultBuilder,
        uint256 _settlementDelay
    ) external initializer {
        __Ownable_init();

        setDerivativeSpecificationRegistry(_derivativeSpecificationRegistry);
        setOracleRegistry(_oracleRegistry);
        setOracleIteratorRegistry(_oracleIteratorRegistry);
        setCollateralTokenRegistry(_collateralTokenRegistry);
        setCollateralSplitRegistry(_collateralSplitRegistry);

        setTokenBuilder(_tokenBuilder);
        setFeeLogger(_feeLogger);
        setVaultBuilder(_vaultBuilder);

        setSettlementDelay(_settlementDelay);

        protocolFee = _protocolFee;
        authorFeeLimit = _authorFeeLimit;

        require(_feeWallet != address(0), "Fee wallet");
        feeWallet = _feeWallet;
    }





    function createVault(bytes32 _derivativeSymbolHash, uint256 _liveTime)
        external
    {
        IDerivativeSpecification derivativeSpecification =
            IDerivativeSpecification(
                derivativeSpecificationRegistry.get(_derivativeSymbolHash)
            );
        require(
            address(derivativeSpecification) != address(0),
            "Specification is absent"
        );

        address collateralToken =
            collateralTokenRegistry.get(
                derivativeSpecification.collateralTokenSymbol()
            );
        address collateralSplit =
            collateralSplitRegistry.get(
                derivativeSpecification.collateralSplitSymbol()
            );

        address[] memory oracles;
        address[] memory oracleIterators;
        (oracles, oracleIterators) = getOraclesAndIterators(
            derivativeSpecification
        );

        require(_liveTime > 0, "Zero live time");

        address vault =
            vaultBuilder.buildVault(
                _liveTime,
                protocolFee,
                feeWallet,
                address(derivativeSpecification),
                collateralToken,
                oracles,
                oracleIterators,
                collateralSplit,
                tokenBuilder,
                feeLogger,
                authorFeeLimit,
                settlementDelay
            );
        emit VaultCreated(
            _derivativeSymbolHash,
            vault,
            address(derivativeSpecification)
        );
        _vaults.push(vault);
    }

    function getOraclesAndIterators(
        IDerivativeSpecification _derivativeSpecification
    )
        internal
        returns (address[] memory _oracles, address[] memory _oracleIterators)
    {
        bytes32[] memory oracleSymbols =
            _derivativeSpecification.oracleSymbols();
        bytes32[] memory oracleIteratorSymbols =
            _derivativeSpecification.oracleIteratorSymbols();
        require(
            oracleSymbols.length == oracleIteratorSymbols.length,
            "Oracles and iterators length"
        );

        _oracles = new address[](oracleSymbols.length);
        _oracleIterators = new address[](oracleIteratorSymbols.length);
        for (uint256 i = 0; i < oracleSymbols.length; i++) {
            address oracle = oracleRegistry.get(oracleSymbols[i]);
            require(address(oracle) != address(0), "Oracle is absent");
            _oracles[i] = oracle;

            address oracleIterator =
                oracleIteratorRegistry.get(oracleIteratorSymbols[i]);
            require(
                address(oracleIterator) != address(0),
                "OracleIterator is absent"
            );
            _oracleIterators[i] = oracleIterator;
        }
    }

    function setProtocolFee(uint256 _protocolFee) external onlyOwner {
        protocolFee = _protocolFee;
    }

    function setAuthorFeeLimit(uint256 _authorFeeLimit) external onlyOwner {
        authorFeeLimit = _authorFeeLimit;
    }

    function setTokenBuilder(address _tokenBuilder) public onlyOwner {
        require(_tokenBuilder != address(0), "Token builder");
        tokenBuilder = _tokenBuilder;
    }

    function setFeeLogger(address _feeLogger) public onlyOwner {
        require(_feeLogger != address(0), "Fee logger");
        feeLogger = _feeLogger;
    }

    function setVaultBuilder(address _vaultBuilder) public onlyOwner {
        require(_vaultBuilder != address(0), "Vault builder");
        vaultBuilder = IVaultBuilder(_vaultBuilder);
    }

    function setSettlementDelay(uint256 _settlementDelay) public onlyOwner {
        settlementDelay = _settlementDelay;
    }

    function setDerivativeSpecificationRegistry(
        address _derivativeSpecificationRegistry
    ) public onlyOwner {
        require(
            _derivativeSpecificationRegistry != address(0),
            "Derivative specification registry"
        );
        derivativeSpecificationRegistry = IAddressRegistry(
            _derivativeSpecificationRegistry
        );
    }

    function setOracleRegistry(address _oracleRegistry) public onlyOwner {
        require(_oracleRegistry != address(0), "Oracle registry");
        oracleRegistry = IAddressRegistry(_oracleRegistry);
    }

    function setOracleIteratorRegistry(address _oracleIteratorRegistry)
        public
        onlyOwner
    {
        require(
            _oracleIteratorRegistry != address(0),
            "Oracle iterator registry"
        );
        oracleIteratorRegistry = IAddressRegistry(_oracleIteratorRegistry);
    }

    function setCollateralTokenRegistry(address _collateralTokenRegistry)
        public
        onlyOwner
    {
        require(
            _collateralTokenRegistry != address(0),
            "Collateral token registry"
        );
        collateralTokenRegistry = IAddressRegistry(_collateralTokenRegistry);
    }

    function setCollateralSplitRegistry(address _collateralSplitRegistry)
        public
        onlyOwner
    {
        require(
            _collateralSplitRegistry != address(0),
            "Collateral split registry"
        );
        collateralSplitRegistry = IAddressRegistry(_collateralSplitRegistry);
    }

    function pauseVault(address _vault) public onlyOwner {
        IPausableVault(_vault).pause();
    }

    function unpauseVault(address _vault) public onlyOwner {
        IPausableVault(_vault).unpause();
    }

    function setDerivativeSpecification(address _value) external {
        derivativeSpecificationRegistry.set(_value);
    }

    function setOracle(address _value) external {
        oracleRegistry.set(_value);
    }

    function setOracleIterator(address _value) external {
        oracleIteratorRegistry.set(_value);
    }

    function setCollateralToken(address _value) external {
        collateralTokenRegistry.set(_value);
    }

    function setCollateralSplit(address _value) external {
        collateralSplitRegistry.set(_value);
    }




    function getVault(uint256 _index) external view returns (address) {
        return _vaults[_index];
    }



    function getLastVaultIndex() external view returns (uint256) {
        return _vaults.length - 1;
    }



    function getAllVaults() external view returns (address[] memory) {
        return _vaults;
    }

    uint256[50] private __gap;
}

pragma solidity ^0.4.18;

import "./ERC20Basic.sol";



contract ERC20 is ERC20Basic {
  function allowance(address owner, address spender) public view returns (uint256);
  function transferFrom(address from, address to, uint256 value) public returns (bool);

